globalThis.__BQ = {"atpSentaz":{"ilkokul":{"kolay":[{"q":"Bitki yapraklarında üretilen ve hücrenin enerjisini taşıyan küçük pakete ne ad verilir?","steps":[{"t":"Enerji parası","a":"ATP","d":"Hücreler enerjiyi <b>ATP</b> denilen küçük taşıyıcı moleküllerde saklar."},{"t":"Nerede üretilir","a":"Yaprakta","d":"Bitki yaprağında ışık yardımıyla bu enerji paketleri yapılır."}],"ans":"Hücrenin enerji parası <b>ATP</b> üretilir."},{"q":"ATP üretiminde çalışan, dönen bir değirmene benzeyen küçük makineye ne denir?","steps":[{"t":"Küçük makine","a":"ATP sentaz","d":"<b>ATP sentaz</b>, dönerek ATP yapan minik bir motordur."},{"t":"Ne yapar","a":"ATP yapar","d":"Bu küçük motor döndükçe enerji paketi ATP üretir."}],"ans":"Bu makineye <b>ATP sentaz</b> denir."},{"q":"ATP sentaz makinesini döndürüp çalıştıran şey nedir?","steps":[{"t":"Küçük parçacık","a":"Proton","d":"Çok küçük parçacıklar olan <b>protonlar</b> akarak makineyi döndürür."},{"t":"Su çarkı gibi","a":"Akış","d":"Tıpkı su çarkını döndüren su gibi, proton akışı makineyi çevirir."}],"ans":"<b>Protonların</b> akışı makineyi döndürür."},{"q":"ATP üretmek için bitkilerin kullandığı temel enerji kaynağı nedir?","steps":[{"t":"Enerji kaynağı","a":"Güneş ışığı","d":"Bitkiler <b>güneş ışığını</b> kullanarak enerji paketi yapar."},{"t":"Sonuç","a":"ATP","d":"Işık enerjisi sonunda ATP'ye dönüşür."}],"ans":"Bitkiler <b>güneş ışığını</b> kullanır."},{"q":"ATP üretimi bitki hücresinin hangi yeşil renkli kısmında olur?","steps":[{"t":"Yeşil kısım","a":"Kloroplast","d":"Yaprağı yeşil yapan <b>kloroplast</b> içinde enerji paketi yapılır."},{"t":"Mutfak gibi","a":"Üretim yeri","d":"Kloroplast, hücrenin enerji mutfağı gibidir."}],"ans":"ATP <b>kloroplastta</b> üretilir."}],"zor":[{"q":"Protonlar bir yerde çok birikip kalabalık olunca, daha boş bir yere doğru akar. Bu akış ATP makinesini ne yapar?","steps":[{"t":"Kalabalık taraf","a":"Çok proton","d":"Bir tarafta protonlar çok birikir, kalabalık olur."},{"t":"Akış","a":"Boş tarafa","d":"Protonlar kalabalık yerden boş yere doğru <b>akar</b>."},{"t":"Sonuç","a":"Döndürür","d":"Bu akış ATP sentaz makinesini döndürerek ATP yaptırır."}],"ans":"Proton akışı makineyi <b>döndürür</b> ve ATP üretir."},{"q":"ATP yapmak için ATP sentaz hangi iki küçük parçayı birleştirir?","steps":[{"t":"Birinci parça","a":"ADP","d":"ATP'nin yarısı gibi olan <b>ADP</b> hazır bekler."},{"t":"İkinci parça","a":"Fosfat","d":"Yanına bir <b>fosfat</b> parçası eklenir."},{"t":"Birleşme","a":"ATP","d":"ADP ile fosfat birleşince tam dolu ATP olur."}],"ans":"<b>ADP</b> ile <b>fosfat</b> birleşip ATP yapar."},{"q":"Bir su değirmeni nehrin akışıyla döner. ATP sentaz neyin akışıyla döner?","steps":[{"t":"Benzetme","a":"Su değirmeni","d":"Su değirmenini akan su çevirir."},{"t":"Hücredeki akış","a":"Proton akışı","d":"Hücrede makineyi <b>proton</b> akışı çevirir."},{"t":"Sonuç","a":"ATP","d":"Döndükçe ATP enerji paketi yapar."}],"ans":"<b>Proton</b> akışıyla döner."},{"q":"Işık olmadan, karanlıkta proton akışı durursa ATP makinesine ne olur?","steps":[{"t":"Işık gider","a":"Akış azalır","d":"Işık olmayınca protonlar birikemez, akış zayıflar."},{"t":"Makine","a":"Yavaşlar","d":"Proton akışı durunca makine <b>durur</b>."},{"t":"Sonuç","a":"ATP azalır","d":"Makine dönmeyince ATP üretimi durur."}],"ans":"Makine durur, <b>ATP üretimi durur</b>."},{"q":"Protonların biriktiği yer ile akıp gittiği yer farklıdır. Bu fark olmasaydı ne olurdu?","steps":[{"t":"Fark gerekli","a":"Kalabalık fark","d":"Bir tarafın daha kalabalık olması <b>gereklidir</b>."},{"t":"Fark yoksa","a":"Akış yok","d":"İki taraf eşit olursa protonlar akmaz."},{"t":"Sonuç","a":"ATP yok","d":"Akış olmazsa makine dönmez, ATP yapılmaz."}],"ans":"Fark olmazsa akış durur, <b>ATP üretilemez</b>."}]},"ortaokul":{"kolay":[{"q":"Kloroplastta ATP'yi üreten enzimin adı nedir?","steps":[{"t":"Enzim","a":"ATP sentaz","d":"<b>ATP sentaz</b>, ADP ve fosfattan ATP üreten enzimdir."},{"t":"Görev","a":"ATP sentezi","d":"Bu enzim hücrenin enerji molekülü ATP'yi yapar."}],"ans":"Enzimin adı <b>ATP sentaz</b>."},{"q":"ATP sentaz enzimini çalıştıran itici güç nedir?","steps":[{"t":"İtici güç","a":"Proton akışı","d":"Bir zarın iki yanındaki <b>proton (H⁺)</b> farkı enzimi çalıştırır."},{"t":"Hareket","a":"Döndürme","d":"Protonlar akarken enzimin bir kısmını döndürür."}],"ans":"<b>Proton (H⁺) akışı</b> enzimi çalıştırır."},{"q":"ATP sentaz ADP'ye ne ekleyerek ATP üretir?","steps":[{"t":"Eklenen grup","a":"Fosfat (Pi)","d":"ADP'ye bir <b>inorganik fosfat (Pi)</b> grubu eklenir."},{"t":"Tepkime","a":"ADP+Pi→ATP","d":"Bu birleşme ile ATP molekülü oluşur."}],"ans":"ADP'ye <b>fosfat (Pi)</b> eklenerek ATP olur."},{"q":"Kloroplastta protonların yoğun olarak biriktiği iç bölgenin adı nedir?","steps":[{"t":"İç bölge","a":"Tilakoid lümeni","d":"Protonlar <b>tilakoid lümeni</b> denilen iç boşlukta birikir."},{"t":"Sonuç","a":"Yoğunluk farkı","d":"Bu birikme ile lümen ile stroma arasında fark oluşur."}],"ans":"Protonlar <b>tilakoid lümeninde</b> birikir."},{"q":"Işık enerjisinin ATP'nin kimyasal enerjisine dönüştürülmesi olayına ne ad verilir?","steps":[{"t":"Olay adı","a":"Fotofosforilasyon","d":"Işıkla ATP üretilmesine <b>fotofosforilasyon</b> denir."},{"t":"Anlamı","a":"Işık+fosfat ekleme","d":"Foto ışık, fosforilasyon fosfat eklemek demektir."}],"ans":"Bu olaya <b>fotofosforilasyon</b> denir."}],"zor":[{"q":"Tilakoid lümeninde biriken protonlar neden stromaya doğru akar?","steps":[{"t":"Yoğunluk farkı","a":"Lümen yoğun","d":"<b>Tilakoid lümeninde</b> proton yoğunluğu, stromadan yüksektir."},{"t":"Hareket yönü","a":"Yoğundan seyreğe","d":"Protonlar yoğun yerden (lümen) seyrek yere (stroma) doğru akar."},{"t":"Geçiş yolu","a":"ATP sentaz","d":"Bu akış yalnızca <b>ATP sentaz</b> kanalından geçer."}],"ans":"Yoğunluk farkı nedeniyle protonlar <b>lümenden stromaya</b> akar."},{"q":"Protonların ATP sentazdan geçişi sırasında enerji nasıl ATP'ye aktarılır?","steps":[{"t":"Proton geçişi","a":"Döndürür","d":"Protonlar enzimden geçerken bir kısmını <b>döndürür</b>."},{"t":"Dönme enerjisi","a":"Mekanik enerji","d":"Bu dönme, kimyasal tepkimeyi tetikleyen enerji sağlar."},{"t":"Sonuç","a":"ADP+Pi→ATP","d":"Bu enerjiyle ADP ve fosfat birleşip ATP oluşur."}],"ans":"Dönme enerjisiyle <b>ADP+Pi→ATP</b> tepkimesi gerçekleşir."},{"q":"Tilakoid zarın iki yanındaki proton yoğunluğu farkına dayanan ATP üretim mekanizmasına ne ad verilir?","steps":[{"t":"Mekanizma adı","a":"Kemiosmoz","d":"Proton farkıyla ATP üretimine <b>kemiosmoz</b> denir."},{"t":"Temeli","a":"H⁺ gradyanı","d":"Zar boyunca <b>proton (H⁺) gradyanı</b> bu işin temelidir."},{"t":"Sonuç","a":"ATP sentezi","d":"Bu gradyanın enerjisi ATP yapımında kullanılır."}],"ans":"Bu mekanizmaya <b>kemiosmoz</b> denir."},{"q":"ATP sentaz enzimi neden bir motora benzetilir?","steps":[{"t":"Hareketli kısım","a":"Döner","d":"Protonlar geçerken enzimin orta kısmı <b>döner</b>."},{"t":"Motor benzetmesi","a":"Türbin","d":"Tıpkı bir türbin gibi akışkan geçince döner."},{"t":"İş","a":"ATP üretir","d":"Bu dönme mekanik işe, sonra kimyasal enerjiye çevrilir."}],"ans":"Proton akışıyla döndüğü için <b>motora (türbine)</b> benzetilir."},{"q":"Eğer tilakoid zar protonlara karşı geçirgen (delik) olsaydı ATP üretimine ne olurdu?","steps":[{"t":"Sızıntı","a":"Protonlar kaçar","d":"Zar delik olsaydı protonlar her yerden <b>sızardı</b>."},{"t":"Gradyan","a":"Oluşmaz","d":"Lümen ile stroma arası yoğunluk farkı oluşamazdı."},{"t":"Sonuç","a":"ATP azalır","d":"Gradyan olmadan ATP sentaz dönmez, ATP üretilemezdi."}],"ans":"Gradyan oluşmaz, <b>ATP üretimi durur</b>."}]},"lise":{"kolay":[{"q":"Kemiosmoz nedir?","steps":[{"t":"Tanım","a":"H⁺ gradyanı ile ATP","d":"<b>Kemiosmoz</b>, zar boyunca oluşan proton (H⁺) gradyanının enerjisiyle ATP üretilmesidir."},{"t":"Konum","a":"Tilakoid zar","d":"Fotosentezde bu olay <b>tilakoid zarında</b> gerçekleşir."}],"ans":"Kemiosmoz, <b>proton gradyanı</b> enerjisiyle ATP sentezlenmesidir."},{"q":"ATP sentaz enziminin temel iki bölümü nelerdir?","steps":[{"t":"Kanal kısmı","a":"CF₀","d":"Zara gömülü <b>CF₀</b> bölümü protonların geçtiği kanaldır."},{"t":"Katalitik kısım","a":"CF₁","d":"Stromaya bakan <b>CF₁</b> bölümü ADP+Pi'den ATP'yi sentezler."}],"ans":"Proton kanalı <b>CF₀</b> ve katalitik baş <b>CF₁</b>."},{"q":"Fotosentezde proton gradyanı tilakoid zarın hangi yönünde oluşur?","steps":[{"t":"Yüksek taraf","a":"Lümen","d":"Protonlar <b>tilakoid lümeninde</b> birikip yüksek derişim oluşturur."},{"t":"Düşük taraf","a":"Stroma","d":"<b>Stroma</b> tarafı düşük proton derişimlidir."}],"ans":"Gradyan, <b>lümen (yüksek) → stroma (düşük)</b> yönündedir."},{"q":"Proton hareketli kuvveti (PMF) hangi iki bileşenden oluşur?","steps":[{"t":"Kimyasal bileşen","a":"pH farkı (ΔpH)","d":"Zarın iki yanındaki H⁺ derişim farkı <b>ΔpH</b> bileşenidir."},{"t":"Elektriksel bileşen","a":"Zar potansiyeli (Δψ)","d":"Yük farkından doğan <b>Δψ</b> elektriksel bileşendir."}],"ans":"PMF, <b>ΔpH</b> (kimyasal) ve <b>Δψ</b> (elektriksel) bileşenlerinden oluşur."},{"q":"ATP sentazın katalizlediği genel tepkime nedir?","steps":[{"t":"Girenler","a":"ADP + Pi","d":"<b>ADP</b> ve inorganik fosfat <b>Pi</b> substrat olarak kullanılır."},{"t":"Ürün","a":"ATP","d":"Proton akışı enerjisiyle bunlar birleşip <b>ATP</b> oluşur."}],"ans":"ADP + Pi → <b>ATP</b> (proton hareketli kuvveti enerjisiyle)."},{"q":"Fotofosforilasyon terimi ne anlama gelir?","steps":[{"t":"Foto","a":"Işık","d":"<b>Foto</b> ışık enerjisinin kullanıldığını belirtir."},{"t":"Fosforilasyon","a":"Pi ekleme","d":"<b>Fosforilasyon</b>, ADP'ye fosfat eklenerek ATP yapımıdır."}],"ans":"Fotofosforilasyon, <b>ışık enerjisiyle ATP sentezlenmesidir</b>."},{"q":"Protonların tilakoid lümeninde birikmesine katkı sağlayan başlıca kaynak nedir?","steps":[{"t":"Su parçalanması","a":"Fotoliz","d":"<b>Fotoliz</b> ile suyun parçalanması lümene H⁺ bırakır."},{"t":"Elektron taşınması","a":"Sitokrom b₆f","d":"Elektron taşıma sırasında <b>sitokrom b₆f</b> stromadan lümene H⁺ pompalar."}],"ans":"Başlıca <b>fotoliz</b> ve <b>b₆f kompleksinin pompalaması</b>."},{"q":"ATP sentazda protonlar geçerken enzimin hangi kısmı döner?","steps":[{"t":"Dönen birim","a":"Rotor (c-halkası/γ)","d":"Protonlar CF₀'daki <b>c-halkasını</b> ve ona bağlı <b>γ alt birimini</b> döndürür."},{"t":"Sabit kısım","a":"Stator","d":"CF₁ başı sabittir, dönen γ onu içten uyarır."}],"ans":"Dönen kısım <b>c-halkası ve γ alt birimidir</b>."},{"q":"Kemiosmotik kuram kimin tarafından öne sürülmüştür?","steps":[{"t":"Bilim insanı","a":"Peter Mitchell","d":"<b>Peter Mitchell</b> 1961'de kemiosmotik kuramı ortaya koydu."},{"t":"Önemi","a":"Nobel 1978","d":"Bu kuram ile 1978 Nobel Kimya Ödülü'nü kazandı."}],"ans":"Kuramı <b>Peter Mitchell</b> öne sürmüştür."},{"q":"ATP sentaz ile üretilen ATP fotosentezde nerede kullanılır?","steps":[{"t":"Kullanım yeri","a":"Calvin döngüsü","d":"Üretilen ATP <b>stromadaki Calvin döngüsünde</b> kullanılır."},{"t":"İşlev","a":"CO₂ tutturma","d":"CO₂'nin organik moleküle dönüştürülmesi için enerji sağlar."}],"ans":"ATP, <b>Calvin döngüsünde (karbon tutturmada)</b> kullanılır."},{"q":"ATP sentazın CF₁ katalitik başı kaç farklı konformasyon (durum) arasında geçiş yapar?","steps":[{"t":"Durumlar","a":"3 durum","d":"Katalitik bölgeler <b>açık (O)</b>, <b>gevşek (L)</b>, <b>sıkı (T)</b> olmak üzere üç durumda bulunur."},{"t":"Model","a":"Bağlanma değişimi","d":"Boyer'in <b>bağlanma değişimi (binding-change)</b> modeli bunu açıklar."}],"ans":"CF₁ başı <b>3 konformasyon (O, L, T)</b> arasında geçer."},{"q":"Proton gradyanının enerjisi neden ATP üretiminde kullanılabilir bir enerji biçimidir?","steps":[{"t":"Potansiyel enerji","a":"Gradyan = enerji","d":"Derişim ve yük farkı bir tür <b>potansiyel enerji</b> deposudur."},{"t":"Salınım","a":"Akışla açığa çıkar","d":"Protonlar düşük derişime aktığında bu enerji <b>açığa çıkar</b>."}],"ans":"Gradyan bir <b>potansiyel enerji deposudur</b>; akış sırasında ATP'ye dönüşür."},{"q":"Tilakoid zarın protonlara karşı geçirimsiz olması neden zorunludur?","steps":[{"t":"Gradyan korunması","a":"Sızıntıyı önler","d":"Geçirimsiz zar, protonların rastgele kaçmasını <b>engeller</b>."},{"t":"Yönlendirme","a":"Sadece ATP sentaz","d":"Böylece protonlar yalnızca <b>ATP sentaz</b> üzerinden akar."}],"ans":"Gradyanın korunması ve akışın <b>ATP sentaza yönlendirilmesi</b> için."},{"q":"Fotosentezdeki fotofosforilasyon ile solunumdaki oksidatif fosforilasyon arasındaki ortak mekanizma nedir?","steps":[{"t":"Ortak ilke","a":"Kemiosmoz","d":"Her ikisi de <b>kemiosmoz</b> ilkesiyle ATP üretir."},{"t":"Ortak enzim","a":"ATP sentaz","d":"Her ikisinde de <b>ATP sentaz</b> proton akışını ATP'ye çevirir."}],"ans":"Ortak mekanizma <b>kemiosmoz</b> ve <b>ATP sentazdır</b>."},{"q":"ATP sentazın stromaya bakan CF₁ başının yönelimi ATP'nin nerede toplanmasını sağlar?","steps":[{"t":"Baş konumu","a":"Stromada","d":"Katalitik <b>CF₁</b> başı stromaya doğru uzanır."},{"t":"Ürün salınımı","a":"Stromaya","d":"Yeni sentezlenen ATP doğrudan <b>stromaya</b> bırakılır."}],"ans":"ATP, CF₁'in yönelimi sayesinde <b>stromada</b> birikir."}],"zor":[{"q":"Tilakoid lümeninden stromaya proton akışının ATP sentezine bağlanmasını adım adım açıklayınız.","steps":[{"t":"Gradyan","a":"Lümende yüksek H⁺","d":"Fotoliz ve b₆f pompalamasıyla <b>tilakoid lümeninde</b> yüksek H⁺ derişimi oluşur."},{"t":"Akış","a":"CF₀ kanalı","d":"Protonlar PMF etkisiyle <b>CF₀</b> kanalından stromaya akar."},{"t":"Dönme→sentez","a":"γ döner, ATP","d":"Akış c-halkası ve γ'yı döndürür; CF₁'de ADP+Pi→ATP gerçekleşir."}],"ans":"Lümen→stroma proton akışı CF₀'ı döndürür, dönme CF₁'de <b>ADP+Pi→ATP</b> tepkimesini sürer."},{"q":"Boyer'in bağlanma değişimi (binding-change) modeline göre CF₁'de ATP nasıl oluşur?","steps":[{"t":"Gevşek (L)","a":"ADP+Pi bağlanır","d":"<b>L durumunda</b> ADP ve Pi katalitik bölgeye bağlanır."},{"t":"Sıkı (T)","a":"ATP sentezi","d":"γ dönmesi bölgeyi <b>T durumuna</b> getirir; burada kendiliğinden ATP oluşur."},{"t":"Açık (O)","a":"ATP salınır","d":"Bir sonraki dönmeyle bölge <b>O durumuna</b> geçer ve ATP serbest kalır."}],"ans":"γ dönmesi her bölgeyi sırayla L→T→O durumlarından geçirerek <b>ATP'yi sentezler ve salar</b>."},{"q":"Proton hareketli kuvvetinin (PMF) ΔpH ve Δψ bileşenlerinin fotosentezdeki katkısını karşılaştırınız.","steps":[{"t":"ΔpH baskın","a":"Kloroplastta","d":"Kloroplast tilakoidinde PMF'nin büyük kısmı <b>ΔpH</b>'den gelir."},{"t":"Neden","a":"İyon dengelemesi","d":"Mg²⁺ ve Cl⁻ gibi iyonların zardan geçişi <b>Δψ'yi düşürür</b>, böylece kimyasal gradyan baskın olur."},{"t":"Mitokondri farkı","a":"Δψ baskın","d":"Mitokondride ise tam tersine <b>Δψ</b> baskındır."}],"ans":"Kloroplastta PMF'ye büyük katkı <b>ΔpH</b>'den gelir; Δψ iyon hareketiyle azaltılır."},{"q":"Bir uncoupler (ayırıcı) madde tilakoid zara eklenirse fotofosforilasyona etkisi ne olur?","steps":[{"t":"Ayırıcı işlevi","a":"H⁺ sızdırır","d":"<b>Ayırıcı</b> moleküller protonları zardan ATP sentazı atlayarak geçirir."},{"t":"Gradyan","a":"Çöker","d":"Bu durumda lümen-stroma <b>proton gradyanı dağılır</b>."},{"t":"Sonuç","a":"ATP üretimi durur","d":"Elektron taşınması sürse de PMF olmadığından <b>ATP sentezlenemez</b>."}],"ans":"Gradyan dağılır; elektron akışı sürse bile <b>ATP üretimi durur</b> (eşleşme bozulur)."},{"q":"Karanlık-ışık geçişinde, izole kloroplastlarda yapay olarak oluşturulan pH farkı ile ATP üretilebilmesi neyi kanıtlar?","steps":[{"t":"Deney","a":"Jagendorf deneyi","d":"Kloroplastlar asitli ortamda bekletilip aniden bazik ortama alınınca <b>karanlıkta bile ATP</b> üretilir."},{"t":"Yorum","a":"pH farkı yeterli","d":"Demek ki ATP üretimi için <b>tek başına proton gradyanı</b> yeterlidir."},{"t":"Kanıt","a":"Kemiosmoz doğru","d":"Bu, ışık olmadan da gradyanın iş gördüğünü, <b>kemiosmotik kuramı</b> doğrular."}],"ans":"Yapay pH farkıyla karanlıkta ATP üretilmesi, ATP sentezi için <b>proton gradyanının yeterli olduğunu</b> kanıtlar."},{"q":"Siklik fotofosforilasyon ile devirsiz fotofosforilasyon ATP üretimi açısından nasıl farklılaşır?","steps":[{"t":"Devirsiz","a":"ATP+NADPH","d":"<b>Devirsiz</b> yolda hem ATP hem NADPH üretilir, su parçalanır."},{"t":"Siklik","a":"Sadece ATP","d":"<b>Siklik</b> yolda elektron PSI'ye geri döner; yalnızca ek <b>ATP</b> üretilir."},{"t":"Ortak nokta","a":"Kemiosmoz","d":"Her ikisinde de ATP, proton gradyanı ve <b>ATP sentaz</b> ile yapılır."}],"ans":"Siklik yol yalnızca <b>ATP</b> üretirken devirsiz yol <b>ATP ve NADPH</b> üretir; mekanizma kemiosmoz."},{"q":"ATP sentazın bir tam dönüşünde yaklaşık kaç ATP üretildiğini ve bunun proton sayısıyla ilişkisini açıklayınız.","steps":[{"t":"Katalitik bölge","a":"3 ATP/tur","d":"CF₁'de <b>üç katalitik bölge</b> olduğundan tam bir γ dönüşünde yaklaşık <b>3 ATP</b> oluşur."},{"t":"Proton/tur","a":"c-halkası sayısı","d":"Bir tam tur için c-halkasındaki alt birim sayısı kadar (≈12-14) <b>proton</b> geçer."},{"t":"H⁺/ATP","a":"≈4","d":"Bu durumda yaklaşık <b>4 H⁺ / 1 ATP</b> oranı çıkar."}],"ans":"Bir tam dönüşte ≈<b>3 ATP</b> üretilir; ATP başına yaklaşık <b>4 proton</b> gerekir (c-halkası boyutuna bağlı)."},{"q":"Tilakoid lümeninin küçük hacimli, kapalı bir bölme olması kemiosmoz açısından neden avantajlıdır?","steps":[{"t":"Küçük hacim","a":"Hızlı asitlenme","d":"Az sayıda H⁺ bile küçük hacimde <b>derişimi hızla artırır</b>."},{"t":"Kapalı bölme","a":"Kaçışı önler","d":"Kapalı yapı protonların <b>dağılmasını engeller</b>."},{"t":"Sonuç","a":"Güçlü gradyan","d":"Böylece dik bir <b>pH gradyanı</b> hızla kurulur ve sürdürülür."}],"ans":"Küçük kapalı hacim, az protonla <b>hızlı ve güçlü bir pH gradyanı</b> oluşmasını sağlar."},{"q":"Elektron taşıma zinciri ile ATP sentaz arasındaki 'eşleşme' (coupling) kavramını açıklayınız.","steps":[{"t":"Zincir görevi","a":"H⁺ pompalar","d":"Elektron taşıma zinciri (ör. b₆f) enerjiyi kullanarak <b>protonları lümene pompalar</b>."},{"t":"Bağlantı","a":"Gradyan","d":"Oluşan proton gradyanı, iki sistemi <b>dolaylı olarak bağlayan ara enerjidir</b>."},{"t":"ATP sentaz","a":"Gradyanı harcar","d":"ATP sentaz bu gradyanı kullanarak ATP yapar; iki olay gradyan üzerinden <b>eşleşir</b>."}],"ans":"Elektron akışı ile ATP sentezi doğrudan değil, <b>proton gradyanı</b> aracılığıyla eşleşir (kemiosmotik eşleşme)."},{"q":"Bir mutasyon ATP sentazın CF₀ kanalını tıkarsa kloroplastta hangi sonuçlar zincirleme ortaya çıkar?","steps":[{"t":"Kanal tıkalı","a":"Akış yok","d":"Protonlar CF₀'dan geçemez, <b>akış durur</b>."},{"t":"Gradyan birikir","a":"Aşırı ΔpH","d":"H⁺ harcanmadığı için lümende aşırı yüksek gradyan <b>birikir</b>."},{"t":"Geri besleme","a":"Zincir durur","d":"Yüksek gradyan elektron taşımayı baskılar; ATP ve NADPH üretimi <b>durur</b>."}],"ans":"Akış durur, gradyan aşırı birikir ve geri baskıyla <b>elektron taşıma ile ATP/NADPH üretimi durur</b>."},{"q":"İzole tilakoidlerde ışıkta ATP üretildiğinde ortamın stroma tarafındaki pH'ı nasıl değişir, neden?","steps":[{"t":"Proton akışı","a":"Lümen→stroma","d":"ATP sentazdan protonlar stromaya <b>akar</b>."},{"t":"pH etkisi","a":"Stroma bazikleşir? Tersi","d":"Lümene pompalama nedeniyle <b>stromadan H⁺ çekilir</b>, stroma daha bazik (pH artar) olur."},{"t":"Net sonuç","a":"Lümen asidik","d":"Net olarak <b>lümen asitleşir, stroma bazikleşir</b>."}],"ans":"Işıkta stroma <b>bazikleşir (pH artar)</b>, çünkü H⁺ lümene pompalanır; lümen asitleşir."},{"q":"ATP sentaz neden 'döner moleküler motor' olarak sınıflandırılır ve bu rotasyon deneysel olarak nasıl gösterilmiştir?","steps":[{"t":"Dönme","a":"γ rotasyonu","d":"Proton akışı γ alt birimini <b>fiziksel olarak döndürür</b>."},{"t":"Deney","a":"Floresan aktin","d":"γ'ya bağlanan işaretli bir <b>aktin filamentinin döndüğü</b> mikroskopta gözlenmiştir."},{"t":"Tersinirlik","a":"ATP→dönme","d":"ATP hidrolizi tersine motoru döndürebilir; bu da onun <b>gerçek bir motor</b> olduğunu kanıtlar."}],"ans":"γ alt biriminin döndüğü işaretli filamentle doğrudan görüntülenmiştir; bu nedenle <b>döner moleküler motordur</b>."},{"q":"Fotosentezde NADPH ihtiyacının ATP ihtiyacından farklı olması durumunda hücre ATP dengesini nasıl ayarlar?","steps":[{"t":"Sorun","a":"Oran uyumsuz","d":"Calvin döngüsü ATP'yi NADPH'den daha fazla tüketir; devirsiz yol bunu tam karşılayamaz."},{"t":"Çözüm","a":"Siklik akış","d":"Hücre <b>siklik fotofosforilasyonu</b> devreye sokarak NADPH üretmeden ek ATP yapar."},{"t":"Sonuç","a":"Denge","d":"Böylece kemiosmoz yoluyla <b>ATP/NADPH oranı</b> ihtiyaca göre ayarlanır."}],"ans":"Hücre <b>siklik fotofosforilasyonu</b> artırarak NADPH üretmeden ek ATP sağlar ve oranı dengeler."},{"q":"Termodinamik açıdan ADP+Pi→ATP tepkimesi içe çekimli (endergonik) iken kemiosmoz bunu nasıl olanaklı kılar?","steps":[{"t":"Tepkime","a":"Endergonik","d":"ADP+Pi→ATP tepkimesi <b>enerji gerektirir</b> (ΔG>0)."},{"t":"Enerji kaynağı","a":"PMF (ekzergonik)","d":"Protonların gradyandan akışı <b>ekzergoniktir</b> (ΔG<0) ve enerji açığa çıkarır."},{"t":"Eşleşme","a":"Net ΔG<0","d":"ATP sentaz iki olayı birleştirir; toplam ΔG negatif olunca sentez <b>kendiliğinden</b> ilerler."}],"ans":"Ekzergonik proton akışı endergonik ATP sentezine eşlenir; <b>toplam ΔG negatif</b> olduğu için tepkime ilerler."},{"q":"DCMU gibi PSII'yi engelleyen bir madde kullanıldığında ATP sentaz aktivitesi neden azalır?","steps":[{"t":"PSII bloğu","a":"Su parçalanmaz","d":"<b>DCMU</b> PSII'de elektron akışını keser; fotoliz durur."},{"t":"Gradyan","a":"Pompalama azalır","d":"Elektron akmadığı için b₆f proton pompalayamaz, lümene H⁺ birikmez."},{"t":"Sonuç","a":"PMF düşer","d":"Proton gradyanı zayıflar, ATP sentaz dönmesi <b>azalır/durur</b>."}],"ans":"DCMU elektron akışını keserek proton pompalamasını durdurur; PMF düştüğü için <b>ATP sentezi azalır</b>."}]}},"c3":{"ilkokul":{"kolay":[{"q":"Buğday, pirinç ve arpa gibi bitkiler güneş ışığını kullanarak kendi besinini nasıl yapar?","steps":[{"t":"Işığı yakalama","a":"Yapraklar","d":"Bu bitkilerin yeşil yaprakları güneş ışığını yakalar ve bu ışığı bir çeşit yemek pişirme enerjisi gibi kullanır."},{"t":"Besin yapma","a":"Şeker (besin)","d":"Bitki, hava ve sudan aldığı maddeleri ışık enerjisiyle birleştirip kendine şeker yani besin yapar."}],"ans":"Bu bitkiler yapraklarıyla güneş ışığını yakalar ve kendi besinini kendisi yapar."},{"q":"Dünyadaki bitkilerin <b>çoğu</b> besinini hangi yolla üretir?","steps":[{"t":"En yaygın yol","a":"Çoğu bitki","d":"Bitkilerin büyük bölümü aynı temel yolu kullanarak besin üretir; buğday, pirinç ve arpa da bunlardandır."},{"t":"Sonuç","a":"Güneş ışığıyla","d":"Bu bitkiler güneş ışığı, su ve havayı kullanarak besin yapar."}],"ans":"Bitkilerin çoğu güneş ışığını kullanarak aynı temel yolla besin üretir."},{"q":"Bir bitkinin besin yapabilmesi için en çok neye ihtiyacı vardır?","steps":[{"t":"Gerekli olanlar","a":"Işık, su, hava","d":"Bitki besin yapmak için güneş ışığına, suya ve havadaki bir gaza ihtiyaç duyar."},{"t":"Sonuç","a":"Üçü birlikte","d":"Bunlardan biri eksik olursa bitki yeterince besin yapamaz."}],"ans":"Bitki besin yapmak için güneş ışığına, suya ve havaya ihtiyaç duyar."},{"q":"Çok sıcak ve kurak günlerde buğday gibi bitkiler neden zorlanır?","steps":[{"t":"Su azalır","a":"Susuzluk","d":"Hava çok sıcak ve kurak olunca toprakta su azalır, bitki susuz kalır."},{"t":"Besin azalır","a":"Daha az büyür","d":"Su az olunca bitki besinini iyi yapamaz ve daha yavaş büyür."}],"ans":"Çok sıcak ve kurak günlerde su azaldığı için bu bitkiler zorlanır ve daha az besin yapar."},{"q":"Ekmek yaptığımız buğday, kendi besinini kim sayesinde yapar?","steps":[{"t":"Enerji kaynağı","a":"Güneş","d":"Buğdayın yaprakları güneşten gelen ışığı kullanır."},{"t":"Besin oluşur","a":"Kendi yapar","d":"Güneş ışığı sayesinde buğday kendi besinini kendisi yapar, biz de bu besinden yararlanırız."}],"ans":"Buğday, güneş ışığı sayesinde kendi besinini kendisi yapar."}],"zor":[{"q":"Buğday tarlasında bitkiler hem ışık alıyor hem de bol su buluyor. Bu bitkiler neden iyi büyür?","steps":[{"t":"Bol ışık","a":"Çok enerji","d":"Bol güneş ışığı bitkiye besin yapması için çok enerji verir."},{"t":"Bol su","a":"Rahat çalışır","d":"Yeterli su olunca bitki susuz kalmaz ve besin yapma işini rahatça sürdürür."},{"t":"Sonuç","a":"İyi büyür","d":"Hem ışık hem su yeterli olduğunda bitki çok besin yapar ve sağlıklı büyür."}],"ans":"Bol ışık ve bol su olunca bitki çok besin yaptığı için iyi büyür."},{"q":"Pirinç neden çoğunlukla suyun bol olduğu sulak tarlalarda yetiştirilir?","steps":[{"t":"Suya ihtiyaç","a":"Çok su ister","d":"Pirinç besin yapmak ve büyümek için bol suya ihtiyaç duyar."},{"t":"Sulak tarla","a":"Su her zaman var","d":"Sulak tarlalarda su hiç eksilmediği için pirinç susuz kalmaz."},{"t":"Sonuç","a":"Daha iyi ürün","d":"Suyu bol bulan pirinç daha iyi büyür ve daha çok ürün verir."}],"ans":"Pirinç bol su istediği için, suyun hiç eksilmediği sulak tarlalarda yetiştirilir."},{"q":"İki saksıdan birini güneşe, diğerini karanlık dolaba koyarsak hangi bitki daha iyi büyür ve neden?","steps":[{"t":"Işık şart","a":"Güneşteki","d":"Bitki besin yapmak için ışığa ihtiyaç duyar; ışık yoksa besin yapamaz."},{"t":"Karanlıktaki","a":"Zayıflar","d":"Karanlıkta kalan bitki besin yapamadığı için solar ve zayıflar."},{"t":"Sonuç","a":"Güneşteki kazanır","d":"Güneş gören bitki besin yapabildiği için daha iyi büyür."}],"ans":"Güneşe konan bitki ışıkla besin yapabildiği için daha iyi büyür; karanlıktaki zayıflar."},{"q":"Bir çiftçi çok sıcak bir yazda tarlasını hiç sulamazsa buğdaya ne olur?","steps":[{"t":"Su biter","a":"Kuruma","d":"Sıcak havada toprak hızla kurur ve buğday susuz kalır."},{"t":"Besin azalır","a":"Az besin","d":"Susuz kalan buğday besin yapma işini iyi yapamaz."},{"t":"Sonuç","a":"Verim düşer","d":"Az besin yapan buğday cılız kalır ve çiftçi az ürün alır."}],"ans":"Sulanmayan buğday sıcakta susuz kalır, az besin yapar ve verimi düşer."},{"q":"Niçin bir bitkinin yaprakları yeşildir ve bu renk besin yapmasına nasıl yardım eder?","steps":[{"t":"Yeşil madde","a":"Yaprakta","d":"Yaprakların içinde ışığı yakalayan yeşil bir madde vardır, bu yüzden yapraklar yeşil görünür."},{"t":"Işığı toplar","a":"Enerji alır","d":"Bu yeşil madde güneş ışığını toplayarak bitkiye besin yapma enerjisi sağlar."},{"t":"Sonuç","a":"Besin yapar","d":"Yeşil madde sayesinde toplanan ışık enerjisiyle bitki besinini yapar."}],"ans":"Yaprakların içindeki yeşil madde güneş ışığını toplar ve bu enerjiyle bitki besinini yapar."}]},"ortaokul":{"kolay":[{"q":"C3 bitkileri terimi neyi ifade eder?","steps":[{"t":"Tanım","a":"Bitki grubu","d":"C3 bitkileri, fotosentez sırasında havadaki karbondioksiti doğrudan kullanan en yaygın bitki grubudur."},{"t":"Örnekler","a":"Buğday, pirinç, arpa","d":"Buğday, pirinç ve arpa gibi tanıdığımız birçok bitki C3 grubundadır."}],"ans":"C3 bitkileri, fotosentezde havadaki karbondioksiti doğrudan kullanan ve dünyada en yaygın olan bitki grubudur."},{"q":"Dünyadaki bitkilerin büyük çoğunluğu hangi fotosentez yolunu kullanır?","steps":[{"t":"En yaygın yol","a":"C3 yolu","d":"Bitki türlerinin büyük bölümü fotosentezi C3 yoluyla yapar."},{"t":"Anlamı","a":"Karbonu doğrudan bağlar","d":"Bu yolda bitki havadaki karbondioksiti hiçbir ön hazırlık yapmadan doğrudan kullanır."}],"ans":"Bitkilerin çoğu, karbondioksiti doğrudan bağlayan C3 fotosentez yolunu kullanır."},{"q":"Buğday, pirinç ve arpa hangi ortak özelliğe sahiptir?","steps":[{"t":"Ortak grup","a":"C3 bitkisi","d":"Bu üç bitki de C3 grubuna girer ve aynı temel fotosentez yolunu kullanır."},{"t":"Önemi","a":"Temel besin","d":"Bu bitkiler dünyada en çok yetiştirilen ve beslenmemizde önemli olan tahıllardır."}],"ans":"Buğday, pirinç ve arpanın hepsi C3 bitkisidir ve aynı fotosentez yolunu kullanır."},{"q":"C3 bitkilerinin fotosentezi serin ve nemli ortamlarda neden daha rahat ilerler?","steps":[{"t":"Su yeterli","a":"Az terleme","d":"Serin ve nemli havada bitki az su kaybeder, gözenekleri rahatça açık kalabilir."},{"t":"Karbon girişi","a":"CO₂ rahat girer","d":"Gözenekler açık kaldığı için havadaki karbondioksit yaprağa kolayca girer."}],"ans":"Serin ve nemli ortamda gözenekler açık kalabildiği için CO₂ rahat girer ve C3 fotosentezi iyi ilerler."},{"q":"C3 bitkileri sıcak ve kurak ortamda neden zorlanır?","steps":[{"t":"Su kaybı","a":"Gözenek kapanır","d":"Sıcak ve kurak havada bitki su kaybetmemek için yaprak gözeneklerini kapatır."},{"t":"CO₂ azalır","a":"Az besin","d":"Gözenekler kapanınca yaprağa giren karbondioksit azalır ve fotosentez yavaşlar."}],"ans":"Sıcak-kurak ortamda gözenekler kapandığı için yaprağa az CO₂ girer ve C3 bitkilerinin fotosentezi yavaşlar."}],"zor":[{"q":"C3 bitkilerinde fotosentezin karbon bağlama tepkimesinde havadaki CO₂ ne ile birleşir ve neden bu gruba C3 denir?","steps":[{"t":"CO₂ bağlanır","a":"5 karbonlu molekül","d":"Havadan alınan karbondioksit, yaprakta bulunan 5 karbonlu bir moleküle eklenir."},{"t":"Ürün oluşur","a":"3 karbonlu ürün","d":"Bu birleşme sonucu ilk kararlı ürün 3 karbon içeren bir bileşik olarak ortaya çıkar."},{"t":"İsim nereden","a":"C3","d":"İlk ürün 3 karbonlu olduğu için bu bitkilere C3 bitkileri denir."}],"ans":"CO₂, 5 karbonlu bir moleküle bağlanır ve ilk kararlı ürün 3 karbonlu olduğu için bu bitkilere C3 denir."},{"q":"Bir C3 bitkisi sıcakta gözeneklerini kapatınca yaprak içindeki oksijen artar; bu durum fotosentezi neden olumsuz etkiler?","steps":[{"t":"Gözenek kapanır","a":"Gaz değişimi durur","d":"Su kaybını önlemek için gözenekler kapanınca yaprağa CO₂ giremez, içeride oksijen birikir."},{"t":"Yanlış tepkime","a":"O₂ kullanılır","d":"CO₂ azalıp oksijen artınca bitki karbon bağlama yerine boşa giden bir tepkimeye yönelir."},{"t":"Sonuç","a":"Verim düşer","d":"Bu durumda bitki beklenen besini üretemez, fotosentez verimi azalır."}],"ans":"Gözenek kapanınca CO₂ azalır, oksijen artar ve bitki boşa giden tepkimeye yöneldiği için C3 fotosentez verimi düşer."},{"q":"Neden buğday gibi C3 bitkileri çok sıcak iklimlerde mısır kadar yüksek verim veremez?","steps":[{"t":"Sorun","a":"Sıcakta su kaybı","d":"Çok sıcak iklimde C3 bitkisi su kaybını önlemek için gözenekleri kapatmak zorunda kalır."},{"t":"CO₂ kıtlığı","a":"Az karbon","d":"Gözenekler kapanınca CO₂ azalır ve karbon bağlama tepkimesi verimli çalışamaz."},{"t":"Sonuç","a":"Düşük verim","d":"Sıcak ortama daha iyi uyum sağlamış bitkiler varken C3 bitkileri bu koşulda geride kalır."}],"ans":"C3 bitkileri sıcakta gözenek kapatıp CO₂ kaybettiği için karbon bağlamada zorlanır ve sıcak iklimde verimi düşük kalır."},{"q":"Bir araştırmacı buğdayı serin-nemli bölgede, başka bir buğdayı sıcak-kurak bölgede yetiştiriyor. Hangisi daha çok ürün verir ve neden?","steps":[{"t":"Serin-nemli","a":"Gözenek açık","d":"Serin ve nemli bölgede su bol olduğu için gözenekler açık kalır, CO₂ rahat girer."},{"t":"Sıcak-kurak","a":"Gözenek kapalı","d":"Sıcak-kurak bölgede bitki su kaybetmemek için gözeneklerini kapatır, CO₂ azalır."},{"t":"Sonuç","a":"Serin bölge","d":"CO₂ bol giren serin-nemli bölgedeki buğday daha çok besin yapar ve daha fazla ürün verir."}],"ans":"Serin-nemli bölgedeki buğday gözenekleri açık tutup bol CO₂ aldığı için daha çok ürün verir."},{"q":"C3 bitkilerinin karbon bağlamasını yapan enzim, bazen yanlışlıkla CO₂ yerine başka bir gazı kullanır. Bu gaz hangisidir ve sonucu nedir?","steps":[{"t":"Yanlış gaz","a":"Oksijen (O₂)","d":"Karbon bağlayan enzim, ortamda CO₂ azalıp O₂ arttığında oksijeni de kullanabilir."},{"t":"İstenmeyen yol","a":"Boşa harcama","d":"Oksijen kullanıldığında besin üretilmez, bunun yerine enerji ve madde boşa harcanır."},{"t":"Sonuç","a":"Verim düşer","d":"Bu nedenle C3 bitkilerinde fotosentez verimi, özellikle sıcakta, beklenenin altına iner."}],"ans":"Enzim CO₂ yerine oksijeni kullanabilir; bu durumda besin üretilmez, madde boşa gider ve C3 bitkisinin verimi düşer."}]},"lise":{"kolay":[{"q":"C3 bitkilerinde CO₂'nin tutulmasıyla oluşan ilk kararlı organik ürün nedir?","steps":[{"t":"Karbon tutulumu","a":"RuBP'ye bağlanma","d":"Havadan alınan CO₂, 5 karbonlu RuBP molekülüne RuBisCO enzimi aracılığıyla bağlanır."},{"t":"İlk ürün","a":"3-PGA","d":"Oluşan 6 karbonlu kararsız ara ürün hemen iki adet 3 karbonlu 3-fosfogliserata (3-PGA) ayrılır."}],"ans":"C3 bitkilerinde ilk kararlı ürün, 3 karbonlu 3-fosfogliserattır (3-PGA)."},{"q":"C3 bitkileri neden bu adla anılır?","steps":[{"t":"İlk ürünün karbon sayısı","a":"3 karbon","d":"CO₂ tutulduğunda oluşan ilk kararlı ürün 3 karbonlu bir bileşiktir (3-PGA)."},{"t":"Adlandırma","a":"C3","d":"İlk ürün 3 karbonlu olduğu için bu bitkilere C3 bitkileri denir."}],"ans":"İlk kararlı fotosentez ürünleri 3 karbonlu (3-PGA) olduğu için bu bitkilere C3 bitkileri denir."},{"q":"C3 bitkilerinde CO₂ tutulumunu hangi enzim katalizler?","steps":[{"t":"Tepkime","a":"CO₂ + RuBP","d":"Karbon tutma tepkimesinde CO₂, 5 karbonlu RuBP ile birleşir."},{"t":"Enzim","a":"RuBisCO","d":"Bu tepkimeyi RuBisCO (ribuloz-1,5-bisfosfat karboksilaz/oksijenaz) enzimi katalizler."}],"ans":"C3 bitkilerinde CO₂ tutulumunu RuBisCO enzimi katalizler."},{"q":"C3 bitkileri CO₂'yi Calvin döngüsünde nasıl kullanır?","steps":[{"t":"Doğrudan giriş","a":"Ön işlem yok","d":"C3 bitkilerinde atmosferik CO₂, herhangi bir ön depolama olmadan doğrudan Calvin döngüsüne katılır."},{"t":"Tutulma yeri","a":"Mezofil hücresi","d":"CO₂ doğrudan mezofil hücrelerindeki RuBisCO ile RuBP'ye bağlanır."}],"ans":"C3 bitkileri CO₂'yi ön bir işlemden geçirmeden doğrudan Calvin döngüsünde kullanır."},{"q":"C3 grubuna giren tipik kültür bitkilerine örnek veriniz.","steps":[{"t":"Yaygın tahıllar","a":"Buğday, pirinç, arpa","d":"Buğday, pirinç ve arpa en bilinen C3 bitkileridir."},{"t":"Genel dağılım","a":"Çoğu bitki","d":"Dünya bitki türlerinin büyük çoğunluğu C3 grubuna girer."}],"ans":"Buğday, pirinç ve arpa tipik C3 bitkileridir; türlerin çoğu bu gruptadır."},{"q":"C3 fotosentezinde CO₂'nin bağlandığı 5 karbonlu molekülün adı nedir?","steps":[{"t":"Kabul edici molekül","a":"RuBP","d":"CO₂'yi kabul eden molekül 5 karbonlu ribuloz-1,5-bisfosfattır (RuBP)."},{"t":"Sonuç","a":"3-PGA'ya dönüşür","d":"CO₂ bağlanınca oluşan ara ürün parçalanarak 3-PGA verir."}],"ans":"C3 fotosentezinde CO₂, 5 karbonlu RuBP (ribuloz-1,5-bisfosfat) molekülüne bağlanır."},{"q":"Fotorespirasyon nedir ve hangi enzimle ilişkilidir?","steps":[{"t":"Tanım","a":"O₂ tüketen yol","d":"Fotorespirasyon, RuBisCO'nun CO₂ yerine O₂ kullanmasıyla başlayan, besin üretmeyen bir süreçtir."},{"t":"İlgili enzim","a":"RuBisCO","d":"Aynı RuBisCO enzimi hem karboksilaz hem oksijenaz olarak davranabildiği için fotorespirasyonu başlatır."}],"ans":"Fotorespirasyon, RuBisCO'nun O₂'yi kullanmasıyla başlayan ve besin üretmeyen bir süreçtir."},{"q":"C3 bitkilerinde sıcak ve kurak koşullarda stomalar neden kapanır?","steps":[{"t":"Su kaybı riski","a":"Terleme artar","d":"Sıcak-kurak havada terleme hızlanır ve bitki aşırı su kaybetme riskiyle karşılaşır."},{"t":"Önlem","a":"Stoma kapanır","d":"Su kaybını sınırlamak için bitki yaprak gözeneklerini (stoma) kapatır."}],"ans":"Sıcak-kurak koşullarda C3 bitkileri su kaybını azaltmak için stomalarını kapatır."},{"q":"Stomalar kapandığında C3 bitkisinin yaprağında CO₂ ve O₂ derişimi nasıl değişir?","steps":[{"t":"CO₂ tüketimi","a":"CO₂ azalır","d":"Stoma kapalıyken dışarıdan CO₂ giremez, fotosentezde tüketildikçe yaprak içi CO₂ azalır."},{"t":"O₂ birikimi","a":"O₂ artar","d":"Işık tepkimelerinde üretilen O₂ dışarı çıkamaz ve yaprak içinde birikir."}],"ans":"Stomalar kapanınca yaprak içi CO₂ azalır, O₂ ise artar."},{"q":"C3 bitkileri hangi iklim koşullarında en verimli fotosentez yapar?","steps":[{"t":"Uygun koşul","a":"Ilıman, nemli","d":"C3 bitkileri ılıman sıcaklık ve yeterli nemin olduğu koşullarda en iyi performansı gösterir."},{"t":"Nedeni","a":"Stoma açık kalır","d":"Bu koşullarda stomalar açık kalabilir, CO₂ bol girer ve fotorespirasyon düşük kalır."}],"ans":"C3 bitkileri ılıman ve nemli koşullarda, stomaları açık tutabildiklerinde en verimli fotosentez yapar."},{"q":"3-PGA molekülü Calvin döngüsünde sonraki adımda neye dönüştürülür?","steps":[{"t":"İndirgenme aşaması","a":"ATP ve NADPH","d":"3-PGA, ışık tepkimelerinden gelen ATP ve NADPH kullanılarak indirgenir."},{"t":"Ürün","a":"G3P (PGAL)","d":"İndirgenme sonucu 3 karbonlu gliseraldehit-3-fosfat (G3P) oluşur."}],"ans":"3-PGA, ATP ve NADPH kullanılarak indirgenip 3 karbonlu G3P'ye (PGAL) dönüştürülür."},{"q":"C3 bitkilerinin tutuğu karbonu doğrudan kullanması, sıcak ortamda neden bir dezavantaj olur?","steps":[{"t":"CO₂ deposu yok","a":"Ön birikim yok","d":"C3 bitkileri CO₂'yi önceden depolamaz, bu yüzden stoma kapanınca yedek karbon kaynağı kalmaz."},{"t":"Sonuç","a":"Fotorespirasyon","d":"CO₂ azalıp O₂ artınca RuBisCO oksijenaz gibi çalışır ve verim düşer."}],"ans":"C3 bitkileri CO₂ deposu tutmadığı için sıcakta stoma kapanınca karbon bulamaz ve fotorespirasyon nedeniyle dezavantajlı olur."},{"q":"C3 fotosentezi karanlık (ışıktan bağımsız) tepkimelerinin gerçekleştiği yer neresidir?","steps":[{"t":"Organel","a":"Kloroplast","d":"Tepkimeler kloroplast içinde gerçekleşir."},{"t":"Bölge","a":"Stroma","d":"Calvin döngüsü kloroplastın sıvı kısmı olan stromada yürür."}],"ans":"C3 karanlık tepkimeleri (Calvin döngüsü) kloroplastın stroma kısmında gerçekleşir."},{"q":"C3 bitkilerinin dünya bitki örtüsündeki yaygınlığı nasıldır?","steps":[{"t":"Tür sayısı","a":"En kalabalık grup","d":"Bilinen bitki türlerinin büyük çoğunluğu C3 metabolizmasına sahiptir."},{"t":"Örnek alanlar","a":"Ormanlar, tahıllar","d":"Ağaçların çoğu ve buğday-pirinç gibi temel tahıllar C3 grubundadır."}],"ans":"C3 bitkileri dünya bitki türlerinin büyük çoğunluğunu oluşturan en yaygın gruptur."},{"q":"RuBisCO enziminin iki farklı işlevi nedir?","steps":[{"t":"Karboksilaz işlevi","a":"CO₂ bağlar","d":"RuBisCO normalde RuBP'ye CO₂ bağlayarak fotosentezi (karbon tutmayı) sağlar."},{"t":"Oksijenaz işlevi","a":"O₂ bağlar","d":"Aynı enzim O₂ derişimi yüksekken RuBP'ye O₂ bağlayarak fotorespirasyonu başlatır."}],"ans":"RuBisCO hem CO₂ bağlayan karboksilaz hem de O₂ bağlayan oksijenaz olarak işlev görür."}],"zor":[{"q":"C3 bitkilerinde Calvin döngüsünün karbon tutma aşamasını ürün düzeyinde açıklayınız.","steps":[{"t":"Substrat ve enzim","a":"RuBP + CO₂, RuBisCO","d":"5 karbonlu RuBP, RuBisCO enzimi ile bir molekül CO₂'yi bağlar."},{"t":"Kararsız ara ürün","a":"6 karbonlu","d":"Oluşan 6 karbonlu bileşik son derece kararsızdır ve hemen parçalanır."},{"t":"Kararlı ürün","a":"2 × 3-PGA","d":"Parçalanma sonucu iki molekül 3 karbonlu 3-PGA, yani ilk kararlı ürün oluşur."}],"ans":"RuBP, RuBisCO ile CO₂'yi bağlar; oluşan 6 karbonlu kararsız ara ürün hemen iki molekül 3 karbonlu 3-PGA'ya ayrılır."},{"q":"RuBisCO'nun oksijenaz aktivitesinin yüksek sıcaklıkta artmasının fotorespirasyona etkisini açıklayınız.","steps":[{"t":"Sıcaklığın etkisi","a":"O₂ ilgisi artar","d":"Yüksek sıcaklıkta RuBisCO'nun O₂'ye olan göreli ilgisi CO₂'ye göre artar."},{"t":"Stoma kapanması","a":"CO₂/O₂ düşer","d":"Sıcakta stomalar kapandığı için yaprak içi CO₂ azalır, O₂ artar ve oran oksijenaz lehine kayar."},{"t":"Sonuç","a":"Fotorespirasyon artar","d":"Bu koşulda RuBisCO daha çok O₂ bağlar, fotorespirasyon hızlanır ve net fotosentez azalır."}],"ans":"Yüksek sıcaklıkta RuBisCO'nun O₂ ilgisi artar ve düşük CO₂/O₂ oranıyla birleşince fotorespirasyon hızlanıp net fotosentez azalır."},{"q":"Fotorespirasyon C3 bitkisinin enerji ve karbon bütçesini neden olumsuz etkiler?","steps":[{"t":"Karbon kaybı","a":"CO₂ açığa çıkar","d":"Fotorespirasyonda daha önce bağlanmış karbonun bir kısmı tekrar CO₂ olarak kaybedilir."},{"t":"Enerji tüketimi","a":"ATP/indirgenme harcanır","d":"Süreç besin üretmediği halde ATP ve indirgenme gücü tüketir."},{"t":"Sonuç","a":"Net verim düşer","d":"Hem karbon kaybı hem enerji harcaması nedeniyle bitkinin net üretimi azalır."}],"ans":"Fotorespirasyon bağlanmış karbonu CO₂ olarak geri verir ve enerji harcar; bu nedenle C3 bitkisinin net verimini düşürür."},{"q":"Sıcak-kurak bir ortamda C3 bitkisinin verim düşüşünü adım adım açıklayınız.","steps":[{"t":"Su koruması","a":"Stoma kapanır","d":"Aşırı su kaybını önlemek için bitki stomalarını kapatır."},{"t":"Gaz dengesi bozulur","a":"CO₂↓ O₂↑","d":"Stoma kapalıyken CO₂ giremez ve tüketilir, O₂ ise birikir."},{"t":"Metabolik sonuç","a":"Fotorespirasyon","d":"Düşük CO₂/yüksek O₂ ortamında RuBisCO oksijenaz olarak çalışır, fotorespirasyon artar ve verim düşer."}],"ans":"Sıcak-kurak ortamda stomalar kapanır, CO₂ azalıp O₂ artar, fotorespirasyon hızlanır ve C3 bitkisinin verimi düşer."},{"q":"C3 ve C4 bitkilerini karbon tutma açısından karşılaştırınız.","steps":[{"t":"C3'te tutma","a":"Doğrudan RuBisCO","d":"C3 bitkilerinde CO₂ doğrudan RuBisCO ile bağlanır, ilk ürün 3 karbonludur."},{"t":"C4'te tutma","a":"Önce 4 karbonlu","d":"C4 bitkilerinde CO₂ önce 4 karbonlu bir bileşiğe bağlanır ve sonra RuBisCO'ya yoğunlaştırılarak taşınır."},{"t":"Sonuç","a":"C4 fotorespirasyonu azaltır","d":"C4 düzeneği RuBisCO çevresinde CO₂'yi yoğunlaştırarak fotorespirasyonu baskılar; C3'te böyle bir ön mekanizma yoktur."}],"ans":"C3 bitkileri CO₂'yi doğrudan RuBisCO ile bağlar (ilk ürün 3-PGA), C4 bitkileri ise CO₂'yi önce 4 karbonlu bileşikte yoğunlaştırarak fotorespirasyonu azaltır."},{"q":"Yüksek O₂ derişiminin C3 fotosentez verimine etkisini açıklayınız.","steps":[{"t":"Rekabet","a":"O₂ ↔ CO₂","d":"O₂ ve CO₂, RuBisCO'nun aynı aktif bölgesi için yarışır."},{"t":"O₂ artışı","a":"Oksijenaz baskın","d":"O₂ derişimi arttıkça RuBisCO daha sık oksijenaz olarak davranır."},{"t":"Sonuç","a":"Verim azalır","d":"Karbon tutma azalır, fotorespirasyon artar ve net fotosentez düşer."}],"ans":"Yüksek O₂ derişimi RuBisCO'yu oksijenaz yönüne kaydırır, fotorespirasyonu artırır ve C3 fotosentez verimini düşürür."},{"q":"3-PGA'nın G3P'ye indirgenmesi sırasında ışık tepkimelerinin katkısını açıklayınız.","steps":[{"t":"Gerekli girdiler","a":"ATP, NADPH","d":"3-PGA'nın indirgenmesi için ışık tepkimelerinde üretilen ATP ve NADPH gereklidir."},{"t":"İndirgenme","a":"3-PGA → G3P","d":"ATP enerji, NADPH ise indirgenme gücü sağlayarak 3-PGA'yı G3P'ye dönüştürür."},{"t":"Bağlantı","a":"İki evre bağlı","d":"Böylece ışık tepkimeleri ile Calvin döngüsü birbirine bağımlı çalışır."}],"ans":"Işık tepkimelerinden gelen ATP ve NADPH kullanılarak 3-PGA, G3P'ye indirgenir; bu, iki evrenin birbirine bağımlı olduğunu gösterir."},{"q":"Calvin döngüsünün RuBP'nin yenilenmesi (rejenerasyon) aşamasının önemini açıklayınız.","steps":[{"t":"Yenilenme","a":"RuBP üretilir","d":"Oluşan G3P moleküllerinin bir kısmı bir dizi tepkimeyle tekrar 5 karbonlu RuBP'ye dönüştürülür."},{"t":"ATP kullanımı","a":"Enerji harcanır","d":"Bu yenilenme adımı ATP harcayarak yürütülür."},{"t":"Süreklilik","a":"Döngü devam eder","d":"RuBP sürekli yenilendiği için yeni CO₂ molekülleri tutulmaya devam edebilir."}],"ans":"G3P'nin bir kısmından ATP harcanarak RuBP yeniden üretilir; bu yenilenme döngünün sürekli CO₂ tutabilmesini sağlar."},{"q":"Bir C3 bitkisinde CO₂ derişiminin artırılması fotosentez hızını neden belli bir noktaya kadar artırır?","steps":[{"t":"Substrat etkisi","a":"Daha çok CO₂","d":"CO₂ artınca RuBisCO daha sık karboksilaz olarak çalışır ve karbon tutma hızlanır."},{"t":"Fotorespirasyon baskılanır","a":"O₂ rekabeti azalır","d":"Yüksek CO₂, O₂ ile rekabette üstün gelir ve fotorespirasyonu azaltır."},{"t":"Doyma noktası","a":"Plato","d":"Belli bir derişimden sonra enzimler doyduğu için hız artmaz, eğri platoya ulaşır."}],"ans":"Artan CO₂, karboksilaz aktivitesini artırıp fotorespirasyonu azaltarak hızı yükseltir; enzimler doyunca hız bir platoda sabitlenir."},{"q":"Buğday tarlasında öğle saatlerinde fotosentez hızının geçici olarak düşmesi (öğle depresyonu) nasıl açıklanır?","steps":[{"t":"Yüksek sıcaklık","a":"Su stresi","d":"Öğle saatlerinde sıcaklık ve ışık zirvedeyken terleme artar, su stresi oluşur."},{"t":"Stoma kapanması","a":"CO₂ düşer","d":"Su kaybını önlemek için stomalar kısmen kapanır, yaprak içi CO₂ azalır."},{"t":"Fotorespirasyon","a":"Verim düşer","d":"Düşük CO₂ ve yüksek sıcaklık fotorespirasyonu artırır, net fotosentez geçici olarak düşer."}],"ans":"Öğle saatlerinde su stresiyle stomalar kapanır, CO₂ azalır ve fotorespirasyon artar; bu yüzden C3 bitkisinde fotosentez geçici olarak düşer (öğle depresyonu)."},{"q":"C3 bitkilerinin neden serin iklim tahılları olarak öne çıktığını açıklayınız.","steps":[{"t":"Düşük fotorespirasyon","a":"Serinde avantaj","d":"Serin iklimde sıcaklık düşük olduğundan RuBisCO'nun oksijenaz aktivitesi ve fotorespirasyon azdır."},{"t":"Stoma açık","a":"CO₂ bol","d":"Nemli-serin koşulda stomalar açık kalabilir, CO₂ girişi sürekli olur."},{"t":"Sonuç","a":"Yüksek verim","d":"Bu koşullarda buğday, arpa gibi C3 tahılları yüksek verim verir."}],"ans":"Serin-nemli iklimde fotorespirasyon düşük, CO₂ girişi sürekli olduğundan buğday ve arpa gibi C3 tahılları yüksek verim verir."},{"q":"Atmosferik CO₂ derişiminin gelecekte artmasının C3 bitkileri üzerindeki olası etkisini değerlendiriniz.","steps":[{"t":"CO₂ artışı","a":"Karboksilaz lehine","d":"Yüksek CO₂, RuBisCO'yu karboksilaz yönüne kaydırır ve karbon tutmayı artırabilir."},{"t":"Fotorespirasyon azalır","a":"Verim potansiyeli","d":"O₂ ile rekabet azaldığından fotorespirasyon düşer, C3 bitkilerinde verim artma eğilimi gösterebilir."},{"t":"Sınırlamalar","a":"Su ve sıcaklık","d":"Ancak eş zamanlı sıcaklık artışı ve su kıtlığı bu kazancı sınırlayabilir."}],"ans":"Artan atmosferik CO₂, C3 bitkilerinde fotorespirasyonu azaltıp verimi artırma eğilimi gösterir; fakat sıcaklık artışı ve su kıtlığı bu kazancı sınırlayabilir."},{"q":"C3 bitkilerinde net fotosentez hızı nasıl tanımlanır ve fotorespirasyon bu değeri nasıl etkiler?","steps":[{"t":"Tanım","a":"Brüt − kayıplar","d":"Net fotosentez, brüt karbon tutmadan solunum ve fotorespirasyon kayıpları çıkarılarak bulunur."},{"t":"Fotorespirasyon kaybı","a":"Brütü azaltır","d":"Fotorespirasyon bağlanmış karbonun bir kısmını geri verdiğinden brüt kazancı eksiltir."},{"t":"Sonuç","a":"Net düşer","d":"Fotorespirasyon arttıkça net fotosentez hızı belirgin biçimde azalır."}],"ans":"Net fotosentez, brüt karbon tutmadan kayıpların çıkarılmasıdır; fotorespirasyon bağlanmış karbonu geri verdiği için net fotosentezi düşürür."},{"q":"RuBisCO'nun hem karboksilaz hem oksijenaz olarak çalışabilmesi C3 bitkileri için neden bir kısıt oluşturur?","steps":[{"t":"Çift işlev","a":"CO₂ ve O₂","d":"RuBisCO aynı aktif bölgede hem CO₂ hem O₂ ile tepkimeye girebilir."},{"t":"Rekabet","a":"Seçicilik sınırlı","d":"Enzim CO₂'ye tam seçici olmadığından O₂ yüksekken oksijenaz aktivitesi kaçınılmaz olur."},{"t":"Sonuç","a":"Verim sınırı","d":"Bu çift işlev, özellikle sıcak-kurak koşulda fotorespirasyona yol açarak C3 verimini sınırlar."}],"ans":"RuBisCO CO₂'ye tam seçici olmadığından O₂ yüksekken oksijenaz olarak da çalışır; bu çift işlev fotorespirasyona yol açarak C3 verimini sınırlar."},{"q":"İlk kararlı ürünün 3 karbonlu olması ile C3 bitkilerinin metabolik basitliği arasındaki ilişkiyi açıklayınız.","steps":[{"t":"Tek aşamalı tutma","a":"Doğrudan Calvin","d":"C3'te CO₂ ön bir yoğunlaştırma olmadan doğrudan Calvin döngüsünde tutulur."},{"t":"İlk ürün","a":"3-PGA","d":"Bu doğrudan tutma sonucu ilk kararlı ürün 3 karbonlu 3-PGA olur."},{"t":"Sonuç","a":"Basit ama riskli","d":"Ek bir CO₂ yoğunlaştırma mekanizması bulunmadığından sistem basittir, ama fotorespirasyona açıktır."}],"ans":"C3 bitkilerinde CO₂ doğrudan tutulduğu için ilk ürün 3 karbonlu 3-PGA'dır; bu basit düzenek ek yoğunlaştırma içermediğinden fotorespirasyona açıktır."}]}},"c4cam":{"ilkokul":{"kolay":[{"q":"Çok sıcak ve kurak yerlerde yaşayan bazı bitkiler suyu nasıl korur?","steps":[{"t":"Sorun ne?","a":"Su azlığı","d":"Çöl gibi sıcak yerlerde su çok azdır, bitki suyunu boşa harcamamalıdır."},{"t":"Bitki ne yapar?","a":"Suyu tutar","d":"Bu bitkiler yapraklarındaki küçük deliklerden çok az su buharlaştırarak suyu korur."}],"ans":"Sıcak yerlerdeki bazı bitkiler suyu boşa harcamayacak şekilde besin üretir."},{"q":"Kaktüs nerede yaşar ve neden suya çok ihtiyaç duymaz?","steps":[{"t":"Kaktüs nerede?","a":"Çölde","d":"Kaktüs çok sıcak ve kurak çöllerde yaşar."},{"t":"Nasıl dayanır?","a":"Suyu biriktirir","d":"Kaktüs gövdesinde su biriktirir ve suyu çok tutumlu kullanır."}],"ans":"Kaktüs çölde yaşar ve gövdesinde su biriktirdiği için az suyla yaşayabilir."},{"q":"Mısır bitkisi besinini nerede üretir?","steps":[{"t":"Neresi?","a":"Yapraklar","d":"Mısırın yeşil yaprakları güneş ışığını yakalar."},{"t":"Ne üretir?","a":"Besin","d":"Yapraklar güneş ışığı, su ve havayı kullanarak besin üretir."}],"ans":"Mısır besinini yeşil yapraklarında güneş ışığı ile üretir."},{"q":"Bitkiler besin yapmak için güneşten başka neye ihtiyaç duyar?","steps":[{"t":"İlk gereken","a":"Su","d":"Bitkiler kökleriyle topraktan su alır."},{"t":"İkinci gereken","a":"Hava","d":"Bitkiler havadan da gaz alarak besin üretir."}],"ans":"Bitkiler besin yapmak için güneş ışığının yanında su ve havaya ihtiyaç duyar."},{"q":"Sıcak yerlerdeki bazı bitkiler yapraklarındaki küçük delikleri ne zaman açar?","steps":[{"t":"Sıcakta ne olur?","a":"Su uçar","d":"Gündüz çok sıcaktır, delikler açılırsa su buharlaşıp gider."},{"t":"Ne zaman açar?","a":"Geceleri","d":"Bazı bitkiler bu delikleri serin geceleri açarak suyu korur."}],"ans":"Bazı bitkiler suyu korumak için yapraklarındaki delikleri serin geceleri açar."}],"zor":[{"q":"Ananas bitkisi sıcak ortamda yaşar; suyunu korumak için havadaki gazı ne zaman alır?","steps":[{"t":"Gündüz sorunu","a":"Çok sıcak","d":"Gündüz hava çok sıcaktır, delikler açık olursa bitki çok su kaybeder."},{"t":"Çözüm","a":"Gece almak","d":"Ananas havadaki gazı serin geceleri alır, böylece su kaybını azaltır."},{"t":"Sonuç","a":"Suyu korur","d":"Bu sayede ananas kurak ortamda az suyla besin üretir."}],"ans":"Ananas, suyu korumak için ihtiyaç duyduğu gazı serin geceleri alır."},{"q":"Şeker kamışı çok güneşli ve sıcak yerlerde iyi büyür; bunun bir nedeni nedir?","steps":[{"t":"Nerede büyür?","a":"Sıcak yerler","d":"Şeker kamışı bol güneşli, sıcak bölgeleri sever."},{"t":"Neden uygun?","a":"Hızlı besin","d":"Bu bitki güçlü güneşte çok iyi besin üretip hızlı büyür."}],"ans":"Şeker kamışı bol güneşli sıcak yerlerde çok iyi besin üretip hızlı büyür."},{"q":"Çölde yaşayan bir bitki, gündüz yapraklarındaki delikleri kapalı tutarsa ne kazanır?","steps":[{"t":"Açık olsa ne olur?","a":"Su kaybı","d":"Sıcak gündüz delikler açıksa bitkinin suyu hızla uçar."},{"t":"Kapalıyken","a":"Su kalır","d":"Delikler kapalıyken bitki suyunu içinde tutar."},{"t":"Kazanç","a":"Susuz dayanır","d":"Böylece bitki uzun süre az suyla yaşayabilir."}],"ans":"Çöl bitkisi gündüz deliklerini kapatarak suyunu korur ve kurakta yaşayabilir."},{"q":"Bazı sıcak bölge bitkileri neden hem güneşi hem suyu çok iyi kullanır?","steps":[{"t":"Ortam nasıl?","a":"Sıcak-kurak","d":"Yaşadıkları yer hem çok güneşli hem susuzdur."},{"t":"Ne yapmaları gerekir?","a":"İkisini de korumak","d":"Hem bol güneşten yararlanmalı hem azıcık suyu boşa harcamamalı."}],"ans":"Sıcak bölge bitkileri bol güneşi kullanırken az suyu da dikkatle harcar."},{"q":"Kaktüsün yaprakları küçük dikenler şeklindedir; bu ona ne fayda sağlar?","steps":[{"t":"Geniş yaprak olsa","a":"Çok su gider","d":"Geniş yapraklardan çok su buharlaşır."},{"t":"Dikenler ne yapar?","a":"Su korur","d":"İnce dikenlerden çok az su uçar, böylece su korunur."},{"t":"Sonuç","a":"Çöle uyum","d":"Bu sayede kaktüs susuz çölde yaşayabilir."}],"ans":"Kaktüsün dikenleri su kaybını azaltır, böylece bitki kurak çölde yaşayabilir."}]},"ortaokul":{"kolay":[{"q":"C4 bitkilerine örnek olarak hangi bitkiler verilebilir?","steps":[{"t":"C4 nedir?","a":"Özel bitki grubu","d":"C4 bitkileri sıcak ortamda besin üretimini daha verimli yapan bitkilerdir."},{"t":"Örnekler","a":"Mısır, şeker kamışı","d":"Mısır ve şeker kamışı bilinen C4 bitkileridir."}],"ans":"Mısır ve şeker kamışı C4 bitkilerine örnektir."},{"q":"CAM bitkileri stomalarını (yaprak deliklerini) genellikle ne zaman açar?","steps":[{"t":"Gündüz durumu","a":"Sıcak","d":"Gündüz hava çok sıcak olduğundan su kaybı yüksek olur."},{"t":"Açma zamanı","a":"Gece","d":"CAM bitkileri stomalarını serin geceleri açar."}],"ans":"CAM bitkileri stomalarını su kaybını azaltmak için geceleri açar."},{"q":"Kaktüs ve ananas hangi bitki grubuna örnektir?","steps":[{"t":"Ortak özellik","a":"Kurağa dayanır","d":"İkisi de çok kurak ortamlarda yaşayabilir."},{"t":"Grup","a":"CAM bitkileri","d":"Kaktüs ve ananas CAM bitkilerine örnektir."}],"ans":"Kaktüs ve ananas CAM bitkilerine örnektir."},{"q":"Stoma (yaprak deliği) nedir ve ne işe yarar?","steps":[{"t":"Stoma ne?","a":"Küçük delik","d":"Stoma yaprakların yüzeyindeki küçük gözeneklerdir."},{"t":"Görevi","a":"Gaz alışverişi","d":"Bitki bu deliklerden gaz alır ve su buharı verir."}],"ans":"Stoma, yapraktaki küçük deliklerdir; gaz alışverişi ve su buharı çıkışını sağlar."},{"q":"C4 ve CAM bitkilerinin ortak amacı nedir?","steps":[{"t":"Ortam","a":"Sıcak-kurak","d":"İkisi de sıcak veya kurak ortamlara uyum sağlamıştır."},{"t":"Amaç","a":"Verimli besin + su koruma","d":"Su kaybını azaltarak besin üretimini sürdürmeye çalışırlar."}],"ans":"C4 ve CAM bitkileri sıcak-kurak ortamda su kaybını azaltıp verimli besin üretmeyi amaçlar."}],"zor":[{"q":"C4 ve CAM bitkilerini su koruma yöntemleri bakımından nasıl ayırırız?","steps":[{"t":"C4 yolu","a":"Mekan ayrımı","d":"C4 bitkileri besin üretiminin ilk adımını farklı hücrelerde yapar, gündüz çalışır."},{"t":"CAM yolu","a":"Zaman ayrımı","d":"CAM bitkileri gazı gece alır, besin üretimini gündüz yapar."},{"t":"Fark","a":"Yer / zaman","d":"C4 işi yere göre, CAM ise zamana göre ayırır."}],"ans":"C4 bitkileri işi farklı hücrelere (yere) ayırır; CAM bitkileri gece-gündüz (zamana) ayırır."},{"q":"CAM bitkileri stomalarını gündüz kapatmasına rağmen besini nasıl üretebilir?","steps":[{"t":"Gece ne yapar?","a":"Gaz depolar","d":"CAM bitkileri geceleri havadan aldıkları karbondioksiti hücrelerinde depolar."},{"t":"Gündüz ne yapar?","a":"Depoyu kullanır","d":"Gündüz stomalar kapalıyken depoladığı karbondioksiti besin üretiminde kullanır."},{"t":"Sonuç","a":"Su korunur","d":"Böylece gündüz stoma açmadan besin üretip su kaybını önler."}],"ans":"CAM bitkileri geceleri karbondioksiti depolar, gündüz bu depoyu kullanarak stoma açmadan besin üretir."},{"q":"Mısır gibi C4 bitkileri çok sıcak ve güneşli iklimlerde neden daha avantajlıdır?","steps":[{"t":"Sıcakta sorun","a":"Su kaybı","d":"Çok sıcakta normal bitkiler su kaybeder ve verim düşer."},{"t":"C4 avantajı","a":"Verimli kullanım","d":"C4 bitkileri karbondioksiti daha verimli yakaladığı için stomayı az açıp az su kaybeder."},{"t":"Sonuç","a":"Yüksek verim","d":"Bu yüzden sıcak iklimlerde hızlı büyüyüp bol ürün verir."}],"ans":"C4 bitkileri sıcakta karbondioksiti verimli yakalayıp az su kaybettiği için sıcak iklimlerde avantajlıdır."},{"q":"CAM bitkilerinin geceleri stoma açması onlara çölde nasıl bir üstünlük sağlar?","steps":[{"t":"Gece koşulu","a":"Serin","d":"Geceleri hava serin ve nemlidir, su buharlaşması azdır."},{"t":"Stoma gece açık","a":"Az su kaybı","d":"Serin gecede stoma açıldığında çok az su kaybedilir."},{"t":"Üstünlük","a":"Kurakta yaşar","d":"Böylece CAM bitkileri çok az suyla çölde yaşamını sürdürür."}],"ans":"CAM bitkileri serin gecelerde stoma açtığı için çok az su kaybeder ve çölde yaşayabilir."},{"q":"Bir bitkinin yaprağında özel bir hücre düzeni (damar etrafında halka biçiminde hücreler) görülürse bu bitki büyük olasılıkla hangi gruptandır?","steps":[{"t":"Özellik ne?","a":"Halka hücre düzeni","d":"C4 bitkilerinde yaprak damarlarının çevresinde özel bir hücre halkası bulunur."},{"t":"Bu düzen ne işe yarar?","a":"Verimli üretim","d":"Bu düzen besin üretiminin iki adımını farklı hücrelere ayırarak verimi artırır."},{"t":"Grup","a":"C4","d":"Bu özel anatomi C4 bitkilerine özgüdür."}],"ans":"Damar çevresinde halka biçiminde özel hücre düzeni görülen bitki büyük olasılıkla C4 bitkisidir."}]},"lise":{"kolay":[{"q":"C4 bitkilerinde karbondioksiti ilk tutan enzim hangisidir ve ilk kararlı ürün kaç karbonludur?","steps":[{"t":"İlk enzim","a":"PEP karboksilaz","d":"C4 bitkilerinde CO₂ önce mezofil hücrelerinde PEP karboksilaz enzimi ile tutulur."},{"t":"İlk ürün","a":"Oksaloasetat (4C)","d":"PEP karboksilaz, CO₂ ile fosfoenolpiruvatı (PEP) birleştirerek 4 karbonlu oksaloasetat oluşturur."}],"ans":"C4 bitkilerinde CO₂ PEP karboksilaz ile tutulur, ilk kararlı ürün 4 karbonlu oksaloasetattır."},{"q":"C4 ve CAM bitkilerinin CO₂ tespitinde kullandığı temel ayrım stratejileri nelerdir?","steps":[{"t":"C4 stratejisi","a":"Mekansal ayrım","d":"C4 bitkileri ilk CO₂ tespitini mezofilde, Calvin döngüsünü demet kını hücrelerinde yapar."},{"t":"CAM stratejisi","a":"Zamansal ayrım","d":"CAM bitkileri CO₂ tespitini gece, Calvin döngüsünü gündüz yapar."}],"ans":"C4 bitkilerinde mekansal (hücreler arası), CAM bitkilerinde zamansal (gece-gündüz) ayrım vardır."},{"q":"Kranz anatomisi nedir ve hangi bitki grubuna özgüdür?","steps":[{"t":"Tanım","a":"Demet kını halkası","d":"Kranz anatomisi, yaprak iletim demetlerini çevreleyen kloroplast bakımından zengin demet kını hücrelerinin halka biçiminde dizilmesidir."},{"t":"Grup","a":"C4 bitkileri","d":"Bu özel anatomi C4 bitkilerine özgüdür ve CO₂ derişiminin artırılmasını sağlar."}],"ans":"Kranz anatomisi, demet kını hücrelerinin damar çevresinde halka oluşturmasıdır ve C4 bitkilerine özgüdür."},{"q":"C4 bitkilerinde Calvin döngüsü hangi hücrelerde gerçekleşir?","steps":[{"t":"İlk tutulma yeri","a":"Mezofil","d":"CO₂ önce mezofil hücrelerinde 4 karbonlu bileşiğe bağlanır."},{"t":"Calvin yeri","a":"Demet kını","d":"4 karbonlu bileşik demet kını hücrelerine taşınır, orada CO₂ bırakılır ve Calvin döngüsü işler."}],"ans":"C4 bitkilerinde Calvin döngüsü demet kını hücrelerinde gerçekleşir."},{"q":"CAM bitkileri stomalarını neden gündüz değil gece açar?","steps":[{"t":"Gündüz koşulu","a":"Yüksek su kaybı","d":"Gündüz sıcaklık ve buharlaşma yüksektir, stoma açıksa çok su kaybedilir."},{"t":"Gece avantajı","a":"Düşük transpirasyon","d":"Geceleri serin ve nemli olduğundan stoma açıkken su kaybı çok azdır."}],"ans":"CAM bitkileri su kaybını en aza indirmek için stomalarını serin gecelerde açar."},{"q":"C4 bitkilerinde mezofil hücrelerinden demet kını hücrelerine taşınan 4 karbonlu bileşik genellikle hangisidir?","steps":[{"t":"İlk ürün","a":"Oksaloasetat","d":"PEP karboksilaz CO₂ ile 4 karbonlu oksaloasetatı oluşturur."},{"t":"Taşınan form","a":"Malat","d":"Oksaloasetat çoğunlukla malata dönüştürülür ve malat demet kını hücrelerine taşınır."}],"ans":"C4 bitkilerinde demet kını hücrelerine genellikle 4 karbonlu malat taşınır."},{"q":"CAM bitkilerinde geceleri tutulan CO₂ hangi bileşik biçiminde depolanır?","steps":[{"t":"Gece tepkimesi","a":"PEP karboksilaz","d":"Geceleri stoma açıkken CO₂ PEP karboksilaz ile tutulur."},{"t":"Depo bileşiği","a":"Malat","d":"Oluşan oksaloasetat malata dönüşür ve kofulda malik asit olarak depolanır."}],"ans":"CAM bitkilerinde gece tutulan CO₂ malat (malik asit) biçiminde kofulda depolanır."},{"q":"C4 bitkilerine üç örnek veriniz.","steps":[{"t":"Özellik","a":"Sıcak iklim bitkileri","d":"C4 bitkileri çoğunlukla sıcak ve güneşli iklimlerde yetişen ürünlerdir."},{"t":"Örnekler","a":"Mısır, şeker kamışı, darı","d":"Mısır, şeker kamışı ve darı (sorgum) tipik C4 bitkileridir."}],"ans":"Mısır, şeker kamışı ve darı (sorgum) C4 bitkilerine örnektir."},{"q":"CAM bitkilerine örnek veriniz ve ortak yaşam ortamlarını belirtiniz.","steps":[{"t":"Örnekler","a":"Kaktüs, ananas, agav","d":"Kaktüs, ananas ve agav bilinen CAM bitkileridir."},{"t":"Ortam","a":"Kurak / sıcak","d":"Bu bitkiler genellikle çöl ve kurak bölgelerde yaşar."}],"ans":"Kaktüs, ananas ve agav CAM bitkileridir; genellikle kurak-sıcak ortamlarda yaşar."},{"q":"PEP karboksilaz enziminin CO₂'ye olan ilgisi RuBisCO'ya göre nasıldır?","steps":[{"t":"PEP karboksilaz özelliği","a":"Yüksek ilgi","d":"PEP karboksilazın CO₂'ye ilgisi çok yüksektir ve O₂ ile tepkimeye girmez."},{"t":"Avantaj","a":"Düşük CO₂'de çalışır","d":"Bu sayede stoma az açık olsa bile düşük CO₂ derişiminde etkili çalışır."}],"ans":"PEP karboksilazın CO₂'ye ilgisi RuBisCO'dan çok yüksektir ve O₂'yi substrat olarak kullanmaz."},{"q":"C4 bitkilerinde demet kını hücrelerinde CO₂ derişiminin yüksek tutulması neyi engeller?","steps":[{"t":"Yüksek CO₂ etkisi","a":"RuBisCO'yu yönlendirir","d":"Demet kınında yüksek CO₂ derişimi RuBisCO'nun karboksilaz tepkimesini destekler."},{"t":"Engellenen olay","a":"Fotorespirasyon","d":"Yüksek CO₂ / düşük O₂ ortamında fotorespirasyon (fotosolunum) büyük ölçüde engellenir."}],"ans":"C4 bitkilerinde demet kınındaki yüksek CO₂ derişimi fotorespirasyonu (fotosolunumu) engeller."},{"q":"CAM bitkilerinde gündüz stoma kapalıyken Calvin döngüsü için gerekli CO₂ nereden gelir?","steps":[{"t":"Gece deposu","a":"Malik asit","d":"Geceleri tutulan CO₂ kofulda malik asit olarak biriktirilmiştir."},{"t":"Gündüz salınım","a":"Malattan CO₂","d":"Gündüz malik asit parçalanır, açığa çıkan CO₂ Calvin döngüsünde kullanılır."}],"ans":"CAM bitkilerinde gündüz CO₂, gece depolanan malik asidin parçalanmasıyla sağlanır."},{"q":"C4 yolağında ilk CO₂ tutma tepkimesinin gerçekleştiği hücre hangisidir?","steps":[{"t":"İlk basamak yeri","a":"Mezofil hücresi","d":"CO₂ ilk olarak mezofil hücrelerinde PEP karboksilaz ile tutulur."},{"t":"Sonraki yer","a":"Demet kını","d":"Oluşan 4 karbonlu bileşik daha sonra demet kını hücrelerine geçer."}],"ans":"C4 bitkilerinde ilk CO₂ tutulması mezofil hücrelerinde gerçekleşir."},{"q":"C3, C4 ve CAM bitkilerini CO₂ tutan ilk enzime göre kıyaslayınız.","steps":[{"t":"C3","a":"RuBisCO","d":"C3 bitkilerinde CO₂ doğrudan RuBisCO ile Calvin döngüsünde tutulur."},{"t":"C4 ve CAM","a":"PEP karboksilaz","d":"C4 ve CAM bitkilerinde CO₂ önce PEP karboksilaz ile tutulup geçici 4 karbonlu bileşiğe bağlanır."}],"ans":"C3 bitkilerinde CO₂'yi ilk tutan RuBisCO, C4 ve CAM bitkilerinde ise PEP karboksilazdır."},{"q":"CAM yolağındaki 'gece-gündüz' iş bölümünün temel amacı nedir?","steps":[{"t":"Gece işi","a":"CO₂ alımı","d":"Geceleri stoma açılır, CO₂ alınıp malik asit olarak depolanır."},{"t":"Gündüz işi","a":"Calvin döngüsü","d":"Gündüz stoma kapalıyken ışık enerjisiyle Calvin döngüsü işletilir."},{"t":"Amaç","a":"Su tasarrufu","d":"Bu iş bölümü kurak ortamda su kaybını en aza indirir."}],"ans":"CAM bitkilerindeki gece-gündüz iş bölümünün temel amacı kurak ortamda su kaybını en aza indirmektir."}],"zor":[{"q":"C4 bitkilerinde CO₂'nin mezofilden demet kını hücrelerine taşınma sürecini adımlarıyla açıklayınız.","steps":[{"t":"1. Tutulma","a":"Mezofil / PEP karboksilaz","d":"Mezofil hücrelerinde PEP karboksilaz CO₂'yi PEP'e bağlayarak 4 karbonlu oksaloasetat oluşturur."},{"t":"2. Dönüşüm ve taşıma","a":"Malat → demet kını","d":"Oksaloasetat malata dönüşür ve plazmodezmalar yoluyla demet kını hücrelerine taşınır."},{"t":"3. CO₂ salınımı","a":"Calvin döngüsü","d":"Demet kınında malat parçalanıp CO₂ bırakır; bu CO₂ RuBisCO ile Calvin döngüsüne girer, kalan piruvat mezofile döner."}],"ans":"CO₂ mezofilde PEP karboksilazla 4C oksaloasetata bağlanır, malat olarak demet kınına taşınır, orada CO₂ salınıp Calvin döngüsüne girer."},{"q":"C4 bitkilerinin fotorespirasyonu (fotosolunumu) baskılama mekanizmasını açıklayınız.","steps":[{"t":"1. RuBisCO sorunu","a":"O₂ ile tepkime","d":"RuBisCO yüksek O₂ / düşük CO₂'de O₂ bağlayarak fotorespirasyona yol açar ve verim düşer."},{"t":"2. CO₂ pompası","a":"Demet kınında derişim","d":"C4 yolağı CO₂'yi 4 karbonlu bileşik olarak demet kınına pompalar, burada CO₂ derişimini çok yükseltir."},{"t":"3. Sonuç","a":"Karboksilaz baskın","d":"Yüksek CO₂ derişimi RuBisCO'yu karboksilasyona yönlendirir, oksijenasyon (fotorespirasyon) büyük ölçüde engellenir."}],"ans":"C4 bitkileri CO₂'yi demet kınına pompalayıp derişimini yükselterek RuBisCO'nun O₂ tepkimesini, yani fotorespirasyonu baskılar."},{"q":"CAM bitkilerinde malik asit derişiminin gün boyunca nasıl değiştiğini ve nedenini açıklayınız.","steps":[{"t":"1. Gece artışı","a":"Malik asit birikir","d":"Geceleri stoma açıkken CO₂ tutulur, malik asit kofulda birikir ve derişimi yükselir."},{"t":"2. Gündüz azalış","a":"Malik asit tükenir","d":"Gündüz malik asit dekarboksile olup CO₂ bırakır, derişimi düşer."},{"t":"3. Ritim","a":"Günlük döngü","d":"Bu durum gece yüksek-gündüz düşük şeklinde günlük (sirkadiyen) bir asit ritmi oluşturur."}],"ans":"CAM bitkilerinde malik asit geceleri birikip gündüz tükenir; bu, CO₂'nin gece depolanıp gündüz Calvin döngüsünde kullanılmasından kaynaklanan günlük bir ritimdir."},{"q":"C4 ve CAM yolaklarının ortak biyokimyasal adımı ile temel farkını karşılaştırınız.","steps":[{"t":"1. Ortak adım","a":"PEP karboksilaz","d":"Her ikisi de CO₂'yi önce PEP karboksilaz ile 4 karbonlu bileşiğe bağlar."},{"t":"2. Ayrım türü","a":"Mekan / zaman","d":"C4'te ilk tutulma ve Calvin döngüsü farklı hücrelerde (mekansal); CAM'de farklı zamanlarda (zamansal) ayrılır."},{"t":"3. Sonuç","a":"Aynı amaç","d":"İki strateji de fotorespirasyonu azaltıp su tasarrufu sağlama amacına hizmet eder."}],"ans":"C4 ve CAM yolakları ortak olarak CO₂'yi PEP karboksilazla tutar; farkları C4'ün mekansal, CAM'in zamansal ayrım yapmasıdır."},{"q":"Çok kurak bir çölde CAM, hafif sıcak verimli bir tarlada ise C4 bitkisinin avantajlı olmasının nedenini açıklayınız.","steps":[{"t":"1. CAM avantajı","a":"Aşırı su tasarrufu","d":"CAM gündüz stomayı tamamen kapatır, bu yüzden suyun çok kısıtlı olduğu çölde hayatta kalır ama büyümesi yavaştır."},{"t":"2. C4 avantajı","a":"Yüksek verim","d":"C4 gündüz fotosentez yapar, bol ışık ve yeterli suda hızlı büyür ve yüksek verim sağlar."},{"t":"3. Sonuç","a":"Ortama uyum","d":"Su çok azsa CAM, su orta düzeyde ama sıcaksa C4 ekolojik olarak avantajlıdır."}],"ans":"Aşırı kurakta gündüz stomayı kapatan CAM hayatta kalmada üstündür; bol ışıklı ve yeterli sulu sıcak ortamda hızlı büyüyen C4 verim bakımından üstündür."},{"q":"C4 bitkilerinde PEP karboksilazın RuBisCO'ya göre iki temel avantajını açıklayınız.","steps":[{"t":"1. CO₂ ilgisi","a":"Çok yüksek","d":"PEP karboksilazın CO₂'ye ilgisi RuBisCO'dan çok yüksektir, düşük derişimde bile etkili çalışır."},{"t":"2. O₂ etkisi","a":"Oksijenazlık yok","d":"PEP karboksilaz O₂'yi substrat olarak kullanmaz, dolayısıyla fotorespirasyon yapmaz."},{"t":"3. Sonuç","a":"Az stomayla verim","d":"Bu sayede stoma az açıkken bile CO₂ verimli tutulur, su korunur."}],"ans":"PEP karboksilazın CO₂'ye ilgisi RuBisCO'dan çok yüksektir ve O₂ kullanmaz; böylece düşük CO₂'de verimli çalışıp su tasarrufu sağlar."},{"q":"C4 bitkilerinde mezofil ve demet kını hücreleri arasındaki iş bölümünü açıklayınız.","steps":[{"t":"1. Mezofil görevi","a":"İlk CO₂ tutma","d":"Mezofil hücreleri PEP karboksilaz ile CO₂'yi tutup 4 karbonlu bileşik yapar; burada RuBisCO bulunmaz veya işlevsel değildir."},{"t":"2. Demet kını görevi","a":"Calvin döngüsü","d":"Demet kını hücreleri RuBisCO içerir; salınan CO₂ ile Calvin döngüsünü işletir."},{"t":"3. Sonuç","a":"İki aşamalı verim","d":"Bu iş bölümü demet kınında yüksek CO₂ derişimi yaratıp verimi artırır."}],"ans":"C4 bitkilerinde mezofil hücreleri CO₂'yi tutup 4C bileşik yapar, demet kını hücreleri ise CO₂'yi alıp Calvin döngüsünü gerçekleştirir."},{"q":"CAM bitkilerinde gece ve gündüz gerçekleşen tepkimeleri ayrı ayrı açıklayınız.","steps":[{"t":"1. Gece","a":"CO₂ tutma","d":"Stoma açıkken CO₂ PEP karboksilazla tutulur, oluşan oksaloasetat malata dönüşüp malik asit olarak kofulda depolanır."},{"t":"2. Gündüz","a":"CO₂ salınım ve Calvin","d":"Stoma kapalıyken malik asit dekarboksile olur, açığa çıkan CO₂ ışık reaksiyonlarının ürünleriyle Calvin döngüsünde kullanılır."},{"t":"3. Sonuç","a":"Zamansal ayrım","d":"CO₂ tutma gece, şeker üretimi gündüz olduğundan zamansal ayrım sağlanır."}],"ans":"CAM bitkilerinde geceleri CO₂ tutulup malik asit olarak depolanır, gündüz bu asit parçalanıp CO₂ Calvin döngüsünde kullanılır."},{"q":"Bir araştırmacı bir bitkinin yaprağında Kranz anatomisi ve iki farklı kloroplast tipi gözlemliyor. Bu bitki hakkında ne söylenebilir?","steps":[{"t":"1. Anatomi yorumu","a":"C4 bitkisi","d":"Demet kınını çevreleyen halka biçimli hücre düzeni (Kranz anatomisi) C4 bitkilerine özgüdür."},{"t":"2. Kloroplast farkı","a":"İşbölümü","d":"Mezofil ve demet kını kloroplastları farklı işler yapar; demet kını kloroplastlarında Calvin döngüsü yoğundur."},{"t":"3. Sonuç","a":"Mekansal ayrım","d":"Bu yapı CO₂ tutma ile Calvin döngüsünün mekansal ayrımını gösterir."}],"ans":"Bu bitki C4 bitkisidir; Kranz anatomisi ve iki kloroplast tipi, CO₂ tutma ile Calvin döngüsünün mekansal ayrıldığını gösterir."},{"q":"C4 ve CAM bitkilerinde PEP karboksilazın çalışma zamanı ve yeri bakımından farkını açıklayınız.","steps":[{"t":"1. C4'te","a":"Gündüz, mezofil","d":"C4 bitkilerinde PEP karboksilaz gündüz mezofil hücrelerinde çalışır."},{"t":"2. CAM'de","a":"Gece, aynı hücre","d":"CAM bitkilerinde PEP karboksilaz geceleri çalışır ve Calvin döngüsüyle aynı hücrede ama farklı zamanda işler."},{"t":"3. Sonuç","a":"Mekan vs zaman","d":"C4'te enzim Calvin'den mekansal, CAM'de zamansal olarak ayrılır."}],"ans":"C4'te PEP karboksilaz gündüz mezofilde çalışıp Calvin'den mekansal ayrılır; CAM'de gece aynı hücrede çalışıp zamansal ayrılır."},{"q":"CAM bitkilerinin büyüme hızının C4 bitkilerine göre genellikle daha yavaş olmasının nedenini açıklayınız.","steps":[{"t":"1. Depo sınırı","a":"Koful kapasitesi","d":"CAM bitkilerinde gece tutulabilen CO₂ miktarı koful malik asit kapasitesiyle sınırlıdır."},{"t":"2. Stoma süresi","a":"Sınırlı gaz alımı","d":"Stoma yalnızca geceleri açık olduğundan toplam CO₂ alımı C4'e göre azdır."},{"t":"3. Sonuç","a":"Düşük üretim","d":"Sınırlı CO₂ alımı daha az şeker ve daha yavaş büyüme demektir; buna karşılık aşırı su tasarrufu sağlar."}],"ans":"CAM bitkilerinde CO₂ alımı gece ve koful kapasitesiyle sınırlı olduğundan üretim azdır; bu yüzden büyüme yavaştır ama su tasarrufu yüksektir."},{"q":"C4 yolağında piruvatın mezofile geri dönüşü ve yeniden PEP'e çevrilmesi neden enerji gerektirir?","steps":[{"t":"1. Geri dönüş","a":"Piruvat → mezofil","d":"Demet kınında CO₂ bırakıldıktan sonra geriye kalan piruvat mezofile döner."},{"t":"2. Yeniden üretim","a":"PEP sentezi","d":"Piruvat, PEP karboksilazın substratı olan PEP'e yeniden çevrilmelidir; bu tepkime ATP harcar."},{"t":"3. Sonuç","a":"Ek enerji maliyeti","d":"Bu yüzden C4 yolağı C3'e göre fazladan ATP harcar, ancak fotorespirasyon kaybını önler."}],"ans":"Piruvatın yeniden PEP'e çevrilmesi ATP harcadığından C4 yolağı ek enerji gerektirir; bu maliyet fotorespirasyonu önleyerek karşılanır."},{"q":"Yüksek sıcaklık ve düşük su koşullarında bir C3 bitkisinin neden C4 bitkisinden daha düşük verim göstereceğini açıklayınız.","steps":[{"t":"1. Stoma kapanması","a":"CO₂ azalır","d":"Su kaybını önlemek için C3 bitkisi stomalarını kısar, yaprak içi CO₂ derişimi düşer."},{"t":"2. Fotorespirasyon artışı","a":"RuBisCO O₂ bağlar","d":"Düşük CO₂ / yüksek sıcaklıkta RuBisCO O₂ bağlayıp fotorespirasyonu artırır, verim düşer."},{"t":"3. C4 farkı","a":"CO₂ pompası","d":"C4 bitkisi CO₂'yi demet kınına pompalayarak bu sorunu yaşamaz ve verimini korur."}],"ans":"Sıcak-kurak ortamda C3 bitkisinde stoma kapanıp CO₂ düşer ve fotorespirasyon artar; CO₂ pompalayan C4 bu sorunu yaşamadığı için daha verimlidir."},{"q":"Bazı CAM bitkilerinin koşullara göre C3 gibi davranabilmesi (fakültatif CAM) ne anlama gelir?","steps":[{"t":"1. Tanım","a":"Esnek metabolizma","d":"Fakültatif CAM bitkileri su bol olduğunda gündüz stoma açıp C3 gibi fotosentez yapabilir."},{"t":"2. Kurakta değişim","a":"CAM moduna geçiş","d":"Su kısıtlanınca aynı bitki CAM moduna geçip stomayı gece açar ve su tasarrufu yapar."},{"t":"3. Sonuç","a":"Uyum avantajı","d":"Bu esneklik bitkinin değişken su koşullarına uyum sağlamasına olanak verir."}],"ans":"Fakültatif CAM, bir bitkinin su bolken C3, kuraklıkta CAM modunda fotosentez yaparak değişken koşullara uyum sağlamasıdır."},{"q":"C4 bitkilerinin ilk kararlı ürününün 4 karbonlu olması, adlandırmayı C3 bitkilerinden nasıl ayırır?","steps":[{"t":"1. C3 ürünü","a":"3 karbonlu (PGA)","d":"C3 bitkilerinde CO₂ RuBisCO ile tutulunca ilk kararlı ürün 3 karbonlu fosfogliserattır (PGA)."},{"t":"2. C4 ürünü","a":"4 karbonlu (OAA)","d":"C4 bitkilerinde CO₂ PEP karboksilazla tutulunca ilk kararlı ürün 4 karbonlu oksaloasetattır."},{"t":"3. Adlandırma","a":"Karbon sayısı","d":"Bitkiler ilk kararlı ürünlerinin karbon sayısına göre C3 ve C4 olarak adlandırılır."}],"ans":"C3 bitkilerinde ilk ürün 3 karbonlu PGA, C4 bitkilerinde 4 karbonlu oksaloasetattır; adlandırma bu karbon sayısına dayanır."}]}},"calvin":{"ilkokul":{"kolay":[{"q":"Bitkiler havadan aldıkları karbondioksit gazını ne yapmak için kullanır?","steps":[{"t":"Havadan gaz alınır","a":"karbondioksit","d":"Yaprak, havadaki karbondioksit gazını içine alır."},{"t":"Şeker yapılır","a":"besin yapımı","d":"Bitki bu gazı kullanarak kendine <b>şeker</b> (besin) yapar."}],"ans":"Bitkiler karbondioksitten kendine şeker (besin) yapmak için kullanır."},{"q":"Bitkinin şeker yaptığı bu işlemler yaprağın hangi bölümünde olur?","steps":[{"t":"Yaprağın içi","a":"yeşil kısım","d":"Yaprağın yeşil kısmında küçük üretim odaları vardır."},{"t":"Şeker burada yapılır","a":"yaprakta","d":"Karbondioksitten <b>şeker</b> yapma işi yaprağın içinde olur."}],"ans":"Bitkinin şeker yapması yaprağın içindeki yeşil bölümde olur."},{"q":"Bitki şeker yaparken havadan aldığı karbondioksiti neyle birleştirir?","steps":[{"t":"İki şey gerekir","a":"karbondioksit ve enerji","d":"Bitki, karbondioksit gazını güneşten gelen enerjiyle birleştirir."},{"t":"Sonuç şeker","a":"şeker","d":"Bu birleşmeden bitkinin besini olan <b>şeker</b> oluşur."}],"ans":"Bitki karbondioksiti güneşten aldığı enerjiyle birleştirip şeker yapar."},{"q":"Bitkinin yaptığı şeker bitkiye ne sağlar?","steps":[{"t":"Şeker besindir","a":"besin","d":"Şeker, bitkinin yiyeceği yani besinidir."},{"t":"Bitki büyür","a":"enerji ve büyüme","d":"Bitki bu <b>besin</b> sayesinde enerji bulur ve büyür."}],"ans":"Bitkinin yaptığı şeker ona besin olur, böylece büyür ve yaşar."},{"q":"Bitkiler şeker yapmak için karbondioksiti nereden alır?","steps":[{"t":"Kaynak hava","a":"hava","d":"Karbondioksit gazı havanın içinde bulunur."},{"t":"Yaprak alır","a":"yapraktan","d":"Bitki bu gazı <b>yaprakları</b> ile havadan alır."}],"ans":"Bitkiler karbondioksiti havadan, yaprakları yardımıyla alır."}],"zor":[{"q":"Bir bitki gece güneş olmadığı halde içinde biriken karbondioksitten neden hemen şeker yapamaz?","steps":[{"t":"Şeker yapımı için enerji şart","a":"enerji gerekir","d":"Karbondioksitten şeker yapmak için bitkiye enerji lazımdır."},{"t":"Enerji güneşten gelir","a":"güneş yok","d":"Bu enerji güneş ışığından sağlanır; gece <b>güneş olmadığı</b> için enerji azdır."}],"ans":"Çünkü şeker yapmak için enerji gerekir, gece güneş olmadığından bu enerji bulunamaz."},{"q":"Bir bahçedeki bitki bol karbondioksit alıyor ama hiç şeker yapamıyorsa eksik olan ilk şey ne olabilir?","steps":[{"t":"Gaz var","a":"karbondioksit yeterli","d":"Bitkide bol karbondioksit gazı bulunuyor."},{"t":"Enerji eksik","a":"ışık yok","d":"Şeker yapmak için gereken <b>ışık enerjisi</b> eksik olabilir."}],"ans":"Bitkiye gereken ışık (enerji) eksik olabilir, bu yüzden şeker yapamaz."},{"q":"Bitki yaptığı şekerin fazlasını ileride kullanmak için ne yapar?","steps":[{"t":"Fazla şeker olur","a":"artan şeker","d":"Bitki ihtiyacından fazla şeker yapabilir."},{"t":"Saklar","a":"depolar","d":"Fazla şekeri kök, meyve gibi yerlerde <b>depolar</b>, sonra kullanır."}],"ans":"Bitki fazla şekeri kök ve meyve gibi yerlerde saklayıp (depolayıp) sonra kullanır."},{"q":"İki saksı bitkiden birine bol ışık verilir, diğeri karanlıkta tutulur. İkisinde de hava aynıdır. Hangisi daha çok şeker yapar, neden?","steps":[{"t":"Hava aynı","a":"karbondioksit eşit","d":"İki bitkide de karbondioksit gazı aynıdır."},{"t":"Işık farkı","a":"ışıklı kazanır","d":"<b>Işıklı</b> bitkinin enerjisi çoktur, bu yüzden daha çok şeker yapar."}],"ans":"Bol ışık alan bitki daha çok şeker yapar, çünkü şeker yapmak için ışık enerjisi gerekir."},{"q":"Bitkinin yaptığı şeker neden sadece bitki için değil, bizim için de önemlidir?","steps":[{"t":"Şeker besin","a":"besin oluşur","d":"Bitki karbondioksitten besin olan şeker yapar."},{"t":"Biz de yeriz","a":"bizim besinimiz","d":"İnsanlar ve hayvanlar bu bitkileri yiyerek <b>besin</b> alır."}],"ans":"Bitkinin yaptığı şeker hem bitkiye hem de onu yiyen insan ve hayvanlara besin olur."}]},"ortaokul":{"kolay":[{"q":"Fotosentezde karbondioksitin şekere dönüştürüldüğü tepkimelere ne ad verilir?","steps":[{"t":"İki evre vardır","a":"ışık ve karanlık","d":"Fotosentezin ışığa bağlı ve ışıktan bağımsız evreleri vardır."},{"t":"Şeker yapan evre","a":"ışıktan bağımsız reaksiyonlar","d":"Karbondioksitin şekere dönüştüğü evreye <b>ışıktan bağımsız reaksiyonlar</b> (Calvin döngüsü) denir."}],"ans":"Karbondioksitin şekere dönüştüğü evreye ışıktan bağımsız reaksiyonlar (Calvin döngüsü) denir."},{"q":"Calvin döngüsü kloroplastın hangi bölümünde gerçekleşir?","steps":[{"t":"Kloroplastın kısımları","a":"stroma ve tilakoit","d":"Kloroplastta sıvı dolu stroma ve zarlı tilakoitler bulunur."},{"t":"Döngünün yeri","a":"stroma","d":"Calvin döngüsü kloroplastın sıvı kısmı olan <b>stromada</b> gerçekleşir."}],"ans":"Calvin döngüsü kloroplastın sıvı kısmı olan stromada gerçekleşir."},{"q":"Calvin döngüsünde karbondioksiti şekere dönüştürmek için hangi iki madde harcanır?","steps":[{"t":"Işık evresinin ürünleri","a":"ATP ve NADPH","d":"Işığa bağlı evrede enerji taşıyan ATP ve NADPH üretilir."},{"t":"Döngüde kullanılır","a":"ATP ve NADPH","d":"Calvin döngüsü bu <b>ATP ve NADPH</b>'yi kullanarak şeker yapar."}],"ans":"Calvin döngüsünde ATP ve NADPH harcanarak karbondioksit şekere dönüştürülür."},{"q":"Calvin döngüsü neden 'ışıktan bağımsız reaksiyonlar' diye adlandırılır?","steps":[{"t":"Işığı doğrudan kullanmaz","a":"ışık gerekmez","d":"Bu tepkimeler için doğrudan ışığa gerek yoktur."},{"t":"Hazır enerjiyle çalışır","a":"ATP-NADPH ile","d":"Işık evresinde üretilen <b>ATP ve NADPH</b> ile çalışır, ışığa doğrudan ihtiyaç duymaz."}],"ans":"Doğrudan ışık kullanmadan, ışık evresinde üretilen ATP ve NADPH ile çalıştığı için bu adı alır."},{"q":"Calvin döngüsünün temel ürünü olan ve bitkinin besin yapımında kullandığı madde nedir?","steps":[{"t":"Karbondioksit girer","a":"karbondioksit","d":"Döngüye havadan karbondioksit alınır."},{"t":"Şeker çıkar","a":"glikoz (şeker)","d":"Döngü sonunda karbondioksitten <b>glikoz</b> gibi şeker yapılır."}],"ans":"Calvin döngüsünün ürünü, glikoz gibi bitkiye besin olan şekerdir."}],"zor":[{"q":"Işığa bağlı evre durduğunda Calvin döngüsü de bir süre sonra neden durur?","steps":[{"t":"Döngünün ihtiyacı","a":"ATP ve NADPH","d":"Calvin döngüsü çalışmak için ATP ve NADPH'ye ihtiyaç duyar."},{"t":"Kaynak kesilir","a":"üretim durur","d":"Işık evresi durunca <b>ATP ve NADPH</b> üretilemez, döngü bu maddeler bitince durur."}],"ans":"Işık evresi durunca ATP ve NADPH üretilemez; bu maddeler tükenince Calvin döngüsü de durur."},{"q":"Calvin döngüsünde karbondioksiti yakalayan tepkimeyi hızlandıran enzim hangisidir?","steps":[{"t":"Karbon tutulması","a":"karbon bağlama","d":"Döngünün ilk adımında karbondioksit bir moleküle bağlanır."},{"t":"Görevli enzim","a":"RuBisCO","d":"Bu bağlama tepkimesini <b>RuBisCO</b> enzimi hızlandırır."}],"ans":"Calvin döngüsünde karbondioksiti yakalayan tepkimeyi RuBisCO enzimi hızlandırır."},{"q":"Bir bitkiye verilen karbondioksit kesilirse Calvin döngüsünün ürünü olan şeker neden azalır?","steps":[{"t":"Şekerin kaynağı","a":"karbondioksit","d":"Döngüde şekerin karbonu havadan alınan karbondioksitten gelir."},{"t":"Hammadde biter","a":"şeker yapılamaz","d":"Karbondioksit kesilince döngü <b>hammaddesiz</b> kalır ve şeker yapımı azalır."}],"ans":"Şekerin karbonu karbondioksitten geldiği için, karbondioksit kesilince döngü hammaddesiz kalır ve şeker azalır."},{"q":"Calvin döngüsüne neden 'döngü' denir?","steps":[{"t":"Başlangıç maddesi","a":"karbon yakalayıcı molekül","d":"Döngü, karbondioksiti yakalayan bir molekülle başlar."},{"t":"Tekrar üretilir","a":"yeniden oluşur","d":"Bu yakalayıcı molekül sonunda <b>yeniden üretilir</b>, böylece tepkimeler tekrar başlar."}],"ans":"Karbonu yakalayan molekül sonunda yeniden üretilip tepkimeler tekrarlandığı için 'döngü' denir."},{"q":"Gündüz bol şeker yapan bir bitki, üretimin büyük kısmını neden ışık evresine değil Calvin döngüsüne borçludur?","steps":[{"t":"Işık evresinin işi","a":"enerji üretimi","d":"Işık evresi şeker değil, ATP ve NADPH gibi enerji taşıyıcıları üretir."},{"t":"Şekeri kim yapar","a":"Calvin döngüsü","d":"Asıl <b>şeker</b> (besin), karbondioksiti bağlayan Calvin döngüsünde yapılır."}],"ans":"Çünkü ışık evresi sadece enerji üretir; asıl şeker, karbondioksiti bağlayan Calvin döngüsünde yapılır."}]},"lise":{"kolay":[{"q":"Calvin döngüsü kloroplastın hangi kısmında ve hangi evrede gerçekleşir?","steps":[{"t":"Bölge","a":"stroma","d":"Calvin döngüsü kloroplastın sıvı dolu kısmı olan stromada yürür."},{"t":"Evre","a":"ışıktan bağımsız evre","d":"Bu tepkimeler fotosentezin <b>ışıktan bağımsız</b> (karanlık) evresini oluşturur."}],"ans":"Calvin döngüsü kloroplastın stromasında, ışıktan bağımsız evrede gerçekleşir."},{"q":"Calvin döngüsünde karbondioksiti bağlayan 5 karbonlu molekül hangisidir?","steps":[{"t":"Karbon tutucu","a":"RuBP","d":"Döngüde karbondioksiti yakalayan molekül 5 karbonlu ribuloz-1,5-bifosfattır (RuBP)."},{"t":"Birleşme","a":"karbon tutulması","d":"Karbondioksit, <b>RuBP</b>'ye bağlanarak karbon tutulmasını başlatır."}],"ans":"Calvin döngüsünde karbondioksiti bağlayan 5 karbonlu molekül RuBP'dir (ribuloz-1,5-bifosfat)."},{"q":"Karbondioksit ile RuBP'nin birleşmesini katalizleyen enzim hangisidir?","steps":[{"t":"Tepkime","a":"karbon tutulması","d":"Karbondioksit ile RuBP'nin birleşmesi karbon tutulması (fiksasyon) tepkimesidir."},{"t":"Enzim","a":"RuBisCO","d":"Bu tepkimeyi <b>RuBisCO</b> (ribuloz bifosfat karboksilaz) enzimi katalizler."}],"ans":"Karbondioksit ile RuBP'nin birleşmesini RuBisCO enzimi katalizler."},{"q":"Karbondioksitin RuBP'ye bağlanmasıyla oluşan kararsız 6 karbonlu molekül hemen neye dönüşür?","steps":[{"t":"İlk ürün kararsız","a":"6 karbonlu ara ürün","d":"CO₂ + RuBP birleşince oluşan 6 karbonlu molekül çok kararsızdır."},{"t":"Parçalanma","a":"iki molekül 3-PGA","d":"Bu molekül hemen ikiye bölünerek iki molekül <b>3-PGA</b> (3 karbonlu) oluşturur."}],"ans":"Kararsız 6 karbonlu molekül hemen ikiye bölünerek iki molekül 3-PGA oluşturur."},{"q":"Calvin döngüsünün ürettiği 3 karbonlu şeker molekülü hangisidir?","steps":[{"t":"İndirgenme ürünü","a":"G3P","d":"3-PGA, ATP ve NADPH ile indirgenerek gliseraldehit-3-fosfata (G3P) dönüşür."},{"t":"Çıkış molekülü","a":"G3P","d":"<b>G3P</b>, döngüden çıkıp glikoz ve diğer organik maddelerin yapımında kullanılır."}],"ans":"Calvin döngüsünün ürettiği 3 karbonlu şeker G3P'dir (gliseraldehit-3-fosfat)."},{"q":"Calvin döngüsü ışık evresinin hangi iki ürününü tüketir?","steps":[{"t":"Enerji kaynağı","a":"ATP","d":"Döngü, hem fosfat aktarımı için ATP'yi kullanır."},{"t":"İndirgeyici","a":"NADPH","d":"Hem de 3-PGA'yı G3P'ye indirgemek için <b>NADPH</b>'yi kullanır."}],"ans":"Calvin döngüsü ışık evresinde üretilen ATP ve NADPH'yi tüketir."},{"q":"Calvin döngüsünde 3-PGA'nın G3P'ye dönüşmesine ne ad verilir?","steps":[{"t":"Elektron eklenir","a":"indirgenme","d":"3-PGA'ya NADPH'den elektron (hidrojen) eklenmesi indirgenmedir."},{"t":"Evre adı","a":"indirgenme evresi","d":"Bu adım Calvin döngüsünün <b>indirgenme</b> evresini oluşturur."}],"ans":"3-PGA'nın G3P'ye dönüşmesine indirgenme (redüksiyon) evresi denir."},{"q":"Calvin döngüsünün üç temel evresi hangileridir?","steps":[{"t":"Önce yakalama","a":"karbon tutulması","d":"İlk evrede CO₂, RuBP'ye bağlanır (karbon tutulması/fiksasyon)."},{"t":"Sonra dönüşüm ve yenileme","a":"indirgenme ve yenilenme","d":"İkinci evre <b>indirgenme</b> (G3P oluşumu), üçüncü evre RuBP'nin <b>yenilenmesidir</b>."}],"ans":"Üç evre: karbon tutulması (fiksasyon), indirgenme ve RuBP'nin yenilenmesidir."},{"q":"Calvin döngüsünde RuBP'nin yenilenmesi neden gereklidir?","steps":[{"t":"RuBP tüketilir","a":"karbon tutmada harcanır","d":"Karbon tutulmasında RuBP, CO₂'yi bağlayıp tükenir."},{"t":"Döngü sürmeli","a":"yeniden üretilir","d":"Döngünün devam etmesi için <b>RuBP</b> G3P'lerden yeniden üretilmelidir."}],"ans":"RuBP karbon tutmada tükendiği için, döngünün sürmesi adına sürekli yeniden üretilmesi gerekir."},{"q":"Calvin döngüsünde bir molekül glikoz oluşturmak için kaç tur dönmek gerekir?","steps":[{"t":"Tur başına karbon","a":"1 CO₂","d":"Her turda 1 molekül CO₂ bağlanır, glikoz için 6 karbon gerekir."},{"t":"Tur sayısı","a":"6 tur","d":"6 karbonlu glikoz için döngünün <b>6 tur</b> dönüp 6 CO₂ bağlaması gerekir."}],"ans":"Bir molekül glikoz için Calvin döngüsünün 6 tur dönüp 6 CO₂ bağlaması gerekir."},{"q":"Calvin döngüsünün enerjisini sağlayan ışığa bağlı reaksiyonlar nerede gerçekleşir?","steps":[{"t":"Işık evresinin yeri","a":"tilakoit zar","d":"Işığa bağlı reaksiyonlar tilakoit zarlarda gerçekleşir."},{"t":"Ürünler stromaya geçer","a":"ATP ve NADPH","d":"Burada üretilen <b>ATP ve NADPH</b> stromadaki Calvin döngüsüne aktarılır."}],"ans":"Işığa bağlı reaksiyonlar tilakoit zarlarda olur; ürünleri stromadaki Calvin döngüsüne gider."},{"q":"Calvin döngüsünden çıkan G3P'nin döngü dışındaki başlıca kullanımı nedir?","steps":[{"t":"Yapı taşı","a":"3 karbonlu şeker","d":"G3P, 3 karbonlu basit bir şeker molekülüdür."},{"t":"Büyük moleküller","a":"glikoz, nişasta","d":"İki G3P birleşip <b>glikoz</b> verir; glikozlar nişasta ve selüloza dönüşebilir."}],"ans":"G3P, glikoz yapımında kullanılır; glikozlar da nişasta, selüloz gibi maddelere dönüşür."},{"q":"Calvin döngüsü neden 'karbon fiksasyonu' (karbon tutulması) yolu olarak da bilinir?","steps":[{"t":"İnorganik karbon","a":"CO₂","d":"Havadaki karbondioksit inorganik bir karbon kaynağıdır."},{"t":"Organik yapıya katılır","a":"karbon tutulması","d":"Döngü, bu CO₂'yi organik moleküllere bağlar; bu işleme <b>karbon tutulması</b> denir."}],"ans":"Havadaki inorganik CO₂'yi organik moleküllere bağladığı için karbon fiksasyonu yolu olarak bilinir."},{"q":"Calvin döngüsünde NADPH ve ATP'nin görevleri arasındaki temel fark nedir?","steps":[{"t":"ATP'nin görevi","a":"enerji/fosfat","d":"ATP, tepkimelere fosfat ve enerji sağlar (örneğin RuBP yenilenmesinde)."},{"t":"NADPH'nin görevi","a":"indirgeyici","d":"<b>NADPH</b> ise elektron-hidrojen vererek 3-PGA'yı G3P'ye indirger."}],"ans":"ATP enerji/fosfat sağlar, NADPH ise indirgeyici olarak elektron-hidrojen verir."},{"q":"Calvin döngüsü 'karanlık reaksiyonlar' diye anılsa da neden gerçekte ışığa bağımlıdır?","steps":[{"t":"Doğrudan ışık kullanmaz","a":"ışıksız işler","d":"Döngünün tepkimeleri için doğrudan ışık gerekmez."},{"t":"Dolaylı bağımlılık","a":"ATP-NADPH üzerinden","d":"Ama kullandığı <b>ATP ve NADPH</b> ışık evresinde üretildiğinden dolaylı olarak ışığa bağımlıdır."}],"ans":"Doğrudan ışık kullanmasa da, gereken ATP ve NADPH ışık evresinde üretildiği için dolaylı olarak ışığa bağımlıdır."}],"zor":[{"q":"Calvin döngüsünün bir tam turunda 3 CO₂ bağlandığında üretilen 6 G3P'nin kaçı RuBP yenilenmesine, kaçı net ürüne ayrılır?","steps":[{"t":"Üretilen G3P","a":"6 G3P","d":"3 CO₂ + 3 RuBP'den 6 molekül G3P (toplam 18 karbon) oluşur."},{"t":"Dağılım","a":"5 yenilenmeye, 1 net ürün","d":"6 G3P'nin 5'i RuBP'yi yenilemek için kullanılır, <b>1</b> tanesi net kazanç olarak döngüden çıkar."}],"ans":"6 G3P'nin 5'i RuBP yenilenmesine, 1'i ise net ürün olarak döngüden ayrılır."},{"q":"3 CO₂ bağlayan bir tam Calvin turunda kaç ATP ve kaç NADPH harcanır?","steps":[{"t":"İndirgenme aşaması","a":"6 ATP, 6 NADPH","d":"6 molekül 3-PGA'nın G3P'ye indirgenmesinde 6 ATP ve 6 NADPH kullanılır."},{"t":"Yenilenme aşaması","a":"+3 ATP","d":"RuBP'nin yenilenmesinde ek <b>3 ATP</b> harcanır; toplam 9 ATP ve 6 NADPH olur."}],"ans":"3 CO₂'lik bir turda toplam 9 ATP ve 6 NADPH harcanır."},{"q":"Bir molekül glikoz sentezi için Calvin döngüsünün toplam ATP ve NADPH gereksinimi nedir?","steps":[{"t":"6 tur gerekir","a":"6 CO₂","d":"Glikoz için 6 CO₂ bağlanır, yani döngü 6 kez döner."},{"t":"Toplam maliyet","a":"18 ATP, 12 NADPH","d":"Tur başına 3 ATP + 2 NADPH; 6 tur için <b>18 ATP</b> ve <b>12 NADPH</b> gerekir."}],"ans":"Bir glikoz molekülü için toplam 18 ATP ve 12 NADPH harcanır."},{"q":"RuBisCO'nun oksijene de bağlanması (fotorespirasyon) Calvin döngüsünün verimini nasıl etkiler?","steps":[{"t":"Rekabet","a":"O₂ ile CO₂ yarışır","d":"RuBisCO hem CO₂ hem O₂ bağlayabilir; O₂ bağlanınca fotorespirasyon başlar."},{"t":"Verim düşer","a":"karbon kaybı","d":"O₂ bağlanması faydalı şeker yerine <b>karbon kaybına</b> yol açar, döngünün net verimi düşer."}],"ans":"RuBisCO O₂ bağladığında fotorespirasyon olur; bu, karbon kazancını azaltarak döngünün verimini düşürür."},{"q":"Aniden karanlığa alınan bir bitkide RuBP miktarının önce artıp 3-PGA'nın birikmesinin nedeni nedir?","steps":[{"t":"Karbon tutulması sürer","a":"3-PGA oluşur","d":"Karanlıkta da RuBisCO bir süre CO₂'yi bağlamaya devam eder, 3-PGA oluşur."},{"t":"İndirgenme durur","a":"ATP-NADPH biter","d":"Ama ışık olmadığı için <b>ATP ve NADPH</b> tükenir; 3-PGA, G3P'ye dönüşemez ve <b>birikir</b>."}],"ans":"Karanlıkta ATP-NADPH üretimi durur; 3-PGA indirgenemediği için birikir, RuBP'ye dönüşüm de yavaşlar."},{"q":"Aniden CO₂'si kesilen bir bitkide RuBP'nin birikip 3-PGA'nın azalmasının nedeni nedir?","steps":[{"t":"Tutulma durur","a":"3-PGA azalır","d":"CO₂ olmayınca RuBP bağlanacak karbon bulamaz; 3-PGA üretimi durur ve azalır."},{"t":"Yenilenme sürer","a":"RuBP birikir","d":"ATP-NADPH bir süre var olduğundan <b>RuBP</b> üretilmeye devam eder ama tüketilmediği için birikir."}],"ans":"CO₂ kesilince 3-PGA üretilemeyip azalır; tüketilmeyen RuBP ise birikir."},{"q":"C4 bitkilerinin sıcak ortamda Calvin döngüsünü neden daha verimli çalıştırabildiğini açıklayın.","steps":[{"t":"Sorun fotorespirasyon","a":"sıcakta O₂ artar","d":"Sıcak-kurak ortamda gözenekler kapanır, hücrede O₂ artıp CO₂ azalır; RuBisCO O₂ bağlar."},{"t":"C4 çözümü","a":"CO₂ derişimini artırır","d":"C4 bitkileri CO₂'yi önce 4 karbonlu moleküle bağlayıp demet kını hücrelerine taşır; orada <b>yüksek CO₂</b> sağlayarak RuBisCO'nun verimli çalışmasını sağlar."}],"ans":"C4 bitkileri CO₂'yi yoğunlaştırıp RuBisCO çevresinde derişimi artırır; böylece fotorespirasyonu azaltıp Calvin döngüsünü sıcakta da verimli çalıştırır."},{"q":"Calvin döngüsünde tüketilen karbonun tamamı CO₂'den geldiği halde RuBP yenilenmesi için neden ayrıca enerji (ATP) gerekir?","steps":[{"t":"Karbon iskeleti yeterli değil","a":"5 G3P → 3 RuBP","d":"5 molekül G3P'den (15 karbon) 3 molekül RuBP'nin (15 karbon) karbon iskeleti elde edilir."},{"t":"Fosforilasyon gerekir","a":"ATP ile aktifleşir","d":"Ancak RuBP'nin reaktif olması için fosfat eklenmesi şarttır; bu <b>ATP</b> ile sağlanır."}],"ans":"Karbon iskeleti G3P'den gelse de, RuBP'yi reaktif kılan fosfat grubunun eklenmesi için ATP enerjisi gerekir."},{"q":"Calvin döngüsünün ışık olmadan kısa süre sürüp uzun süre süremeyişini, ürün ve substrat dengesiyle açıklayın.","steps":[{"t":"Kısa süre devam","a":"depo ATP-NADPH","d":"Işık kesildiğinde stromada kalan ATP ve NADPH ile döngü kısa süre devam eder."},{"t":"Sonra durur","a":"taşıyıcılar tükenir","d":"Bu taşıyıcılar yenilenmediği için tükenince indirgenme durur, döngü <b>uzun süre süremez</b>."}],"ans":"Stromadaki ATP-NADPH stoğuyla döngü kısa süre devam eder; bu taşıyıcılar yenilenmediği için tükenince durur."},{"q":"RuBisCO'nun Dünya'daki en bol protein sayılmasının, Calvin döngüsündeki rolüyle bağlantısını açıklayın.","steps":[{"t":"Yavaş enzim","a":"düşük hız","d":"RuBisCO, katalitik hızı düşük (saniyede az tepkime) bir enzimdir."},{"t":"Bol miktar gerekir","a":"yüksek derişim","d":"Yeterli karbon tutulması için çok sayıda enzim gerekir; bu yüzden <b>çok bol</b> bulunur. Ayrıca tüm karbon tutulması ona dayanır."}],"ans":"RuBisCO yavaş çalıştığı ve gezegendeki karbon tutulmasının tamamını üstlendiği için çok yüksek miktarda bulunur; bu onu en bol protein yapar."},{"q":"Calvin döngüsünde net 1 G3P üretmek için döngünün kaç kez dönmesi ve kaç CO₂ bağlaması gerektiğini açıklayın.","steps":[{"t":"Net ürün oranı","a":"tur başına 1/3 G3P net","d":"Her turda 1 CO₂ bağlanır; 3 turda 1 net G3P çıkışı olur (6 G3P'den 1'i net)."},{"t":"Sonuç","a":"3 tur, 3 CO₂","d":"Net 1 G3P için döngü <b>3 kez</b> dönmeli ve <b>3 CO₂</b> bağlamalıdır."}],"ans":"Net 1 G3P için döngü 3 kez dönmeli ve 3 CO₂ bağlamalıdır."},{"q":"Işık evresi ürünleri ATP/NADPH ile Calvin döngüsü arasında neden 'geri besleme' türü bir bağımlılık vardır?","steps":[{"t":"Calvin tüketir","a":"ADP, NADP⁺ açığa çıkar","d":"Calvin döngüsü ATP ve NADPH'yi kullanıp ADP, Pi ve NADP⁺'a çevirir."},{"t":"Işık evresi yeniden yükler","a":"ADP, NADP⁺ gerekir","d":"Işık evresi çalışmak için <b>ADP ve NADP⁺</b>'ya ihtiyaç duyar; Calvin durursa bunlar bitip ışık evresi de yavaşlar."}],"ans":"Calvin döngüsü ATP-NADPH'yi ADP ve NADP⁺'a çevirip ışık evresine geri verir; biri durursa diğeri de yavaşladığı için karşılıklı (geri besleme) bağımlılık vardır."},{"q":"Calvin döngüsünde 3-PGA'nın G3P'ye indirgenmesinin neden hem ATP hem NADPH gerektirdiğini açıklayın.","steps":[{"t":"Önce fosforilasyon","a":"ATP harcanır","d":"3-PGA önce ATP ile fosforillenerek 1,3-bifosfogliserata dönüşür (enerji yüklenir)."},{"t":"Sonra indirgeme","a":"NADPH harcanır","d":"Ardından <b>NADPH</b>, bu molekülü indirgeyerek G3P'ye çevirir (elektron eklenir)."}],"ans":"3-PGA önce ATP ile fosforillenir, sonra NADPH ile indirgenir; bu yüzden indirgenme adımı hem ATP hem NADPH gerektirir."},{"q":"İzotopla işaretli ¹⁴CO₂ verilen bir bitkide işaretli karbonun ilk olarak hangi molekülde görülmesi beklenir, neden?","steps":[{"t":"İlk bağlanma","a":"karbon tutulması","d":"¹⁴CO₂ önce RuBP'ye bağlanır (RuBisCO katalizi)."},{"t":"İlk kararlı ürün","a":"3-PGA","d":"Oluşan 6 karbonlu ara ürün hemen parçalanır; işaretli karbon ilk olarak kararlı <b>3-PGA</b>'da görülür."}],"ans":"İşaretli karbon ilk kararlı ürün olan 3-PGA'da görülür; çünkü CO₂ önce RuBP'ye bağlanıp hemen 3-PGA'ya dönüşür."},{"q":"Calvin döngüsünün tek başına bitkiyi besleyemeyeceğini, ışık evresiyle zorunlu işbirliğini gerekçelendirerek açıklayın.","steps":[{"t":"Calvin enerji üretmez","a":"sadece tüketir","d":"Calvin döngüsü kendi enerjisini üretmez; ATP ve NADPH'yi dışarıdan (ışık evresinden) alıp tüketir."},{"t":"Işık evresi şeker yapmaz","a":"işbirliği şart","d":"Işık evresi de şeker yapmaz, yalnızca taşıyıcı üretir; bu yüzden besin yapımı iki evrenin <b>zorunlu işbirliğiyle</b> olur."}],"ans":"Calvin döngüsü enerji üretmeyip ışık evresinin ATP-NADPH'sine bağımlıdır; ışık evresi de şeker yapmaz, bu yüzden besin yapımı iki evrenin zorunlu işbirliğiyle gerçekleşir."}]}},"etc":{"ilkokul":{"kolay":[{"q":"Bitkinin yapraklarında, güneş ışığının enerjisini taşıyan küçük yollar vardır. Bu olay nerede gerçekleşir?","steps":[{"t":"Yaprağı düşün","a":"Yeşil yapraklar","d":"Bitkinin yeşil yaprakları güneş ışığını yakalar."},{"t":"İçindeki küçük fabrika","a":"Yaprağın içi","d":"Yaprağın içinde ışık enerjisini taşıyan minik yollar bulunur."}],"ans":"Bu olay yaprağın içinde gerçekleşir."},{"q":"Güneş ışığı yaprağa düştüğünde enerjiye ne olur?","steps":[{"t":"Işık gelir","a":"Güneş ışığı","d":"Güneşten gelen ışık yaprağa ulaşır."},{"t":"Enerji taşınır","a":"Enerji aktarılır","d":"Işığın enerjisi yaprağın içinde bir yerden başka bir yere taşınır."}],"ans":"Işığın enerjisi yaprak içinde taşınır."},{"q":"Yaprakta ışık enerjisi sonunda ne için kullanılır?","steps":[{"t":"Enerji toplanır","a":"Enerji","d":"Işıktan gelen enerji yaprakta toplanır."},{"t":"Besin yapılır","a":"Besin","d":"Bu enerjiyle bitki kendi besinini yapmaya hazırlanır."}],"ans":"Işık enerjisi bitkinin besin yapması için kullanılır."},{"q":"Bir su borusunda su nasıl bir yerden başka yere akarsa, yaprakta da enerji öyle akar. Buna ne diyebiliriz?","steps":[{"t":"Akış fikri","a":"Akmak","d":"Su nasıl borudan akarsa, enerji de sırayla taşınır."},{"t":"Yaprakta akış","a":"Enerji akışı","d":"Yaprakta enerji bir noktadan diğerine akar."}],"ans":"Yaprakta enerji bir akış gibi taşınır."},{"q":"Bitki bu enerjiyi yapraklarında saklayabilir mi?","steps":[{"t":"Enerji gelir","a":"Işık enerjisi","d":"Güneşten enerji gelir."},{"t":"Depolama","a":"Saklanır","d":"Bitki bu enerjiyi sonra kullanmak için biriktirir."}],"ans":"Evet, bitki enerjiyi saklayıp sonra kullanır."}],"zor":[{"q":"Yaprakta enerji taşınırken küçük 'taşıyıcılar' vardır. Bunlar enerjiyi ne yapar?","steps":[{"t":"Taşıyıcı nedir","a":"Yardımcı parça","d":"Enerjiyi elden ele aktaran küçük parçalardır."},{"t":"Ne yaparlar","a":"Enerjiyi taşır","d":"Enerjiyi bir taşıyıcıdan diğerine ulaştırırlar."}],"ans":"Taşıyıcılar enerjiyi elden ele aktarır."},{"q":"Bir merdiven düşün; enerji basamak basamak iner. Yaprakta da enerji nasıl ilerler?","steps":[{"t":"Merdiven benzetmesi","a":"Basamaklar","d":"Enerji bir anda değil, basamak basamak hareket eder."},{"t":"Yaprakta","a":"Sırayla","d":"Yaprakta da enerji sırayla, adım adım taşınır."}],"ans":"Enerji yaprakta basamak basamak, sırayla taşınır."},{"q":"Bu enerji taşıma sırasında bitki neyi biriktirir?","steps":[{"t":"Taşıma olur","a":"Enerji akar","d":"Enerji taşınırken bir şeyler de toplanır."},{"t":"Biriken şey","a":"Güç deposu","d":"Bitki bu sırada kullanacağı bir güç deposu hazırlar."}],"ans":"Bitki kullanacağı enerji deposunu biriktirir."},{"q":"Yağmur damlaları bir oluktan akarken aşağıya iner. Yaprakta enerji taşınırken neye benzer bir şey olur?","steps":[{"t":"Akış","a":"Akmak","d":"Su gibi enerji de bir yönde akar."},{"t":"Sonuç","a":"Toplanma","d":"Akışın sonunda enerji belli bir yerde toplanır."}],"ans":"Enerji su gibi akar ve bir yerde toplanır."},{"q":"Eğer güneş hiç doğmasaydı, yaprakta bu enerji taşıması olur muydu?","steps":[{"t":"Enerji kaynağı","a":"Güneş","d":"Enerjinin kaynağı güneş ışığıdır."},{"t":"Işık yoksa","a":"Taşıma durur","d":"Işık olmazsa taşınacak enerji de olmaz."}],"ans":"Hayır, ışık olmazsa enerji taşıması olmaz."}]},"ortaokul":{"kolay":[{"q":"Fotosentezde ışık enerjisini kullanan tepkimeler bitki hücresinin hangi yapısında olur?","steps":[{"t":"Yapıyı bul","a":"Kloroplast","d":"Fotosentez bitki hücresindeki kloroplastlarda gerçekleşir."},{"t":"İç zarlar","a":"Tilakoit","d":"Işık tepkimeleri kloroplast içindeki tilakoit zarlarında olur."}],"ans":"Işık enerjisi tepkimeleri tilakoit zarında gerçekleşir."},{"q":"Tilakoit zarında elektronlar bir yapıdan diğerine taşınır. Bu olaya ne ad verilir?","steps":[{"t":"Elektron hareketi","a":"Taşınma","d":"Elektronlar zardaki yapılar arasında hareket eder."},{"t":"Adı","a":"Elektron taşıma zinciri","d":"Bu sıralı taşımaya elektron taşıma zinciri denir."}],"ans":"Bu olaya elektron taşıma zinciri denir."},{"q":"Elektron taşıma zincirinde elektronlara enerji veren temel kaynak nedir?","steps":[{"t":"Kaynak","a":"Işık","d":"Güneş ışığı elektronları yüksek enerjili hale getirir."},{"t":"Sonuç","a":"Taşınma başlar","d":"Enerji alan elektronlar zincir boyunca taşınmaya başlar."}],"ans":"Elektronlara enerjiyi güneş ışığı verir."},{"q":"Elektron taşıma zinciri sonunda bitki ne tür yararlı maddeler üretir?","steps":[{"t":"Taşıma sonucu","a":"Enerji","d":"Elektron taşıması enerji açığa çıkarır."},{"t":"Ürünler","a":"ATP","d":"Bu enerjiyle bitki için enerji parası olan ATP üretilir."}],"ans":"Elektron taşıma zinciri ATP üretimine yardım eder."},{"q":"Elektronlar zincir boyunca taşınırken enerjileri genel olarak nasıl değişir?","steps":[{"t":"Başlangıç","a":"Yüksek enerji","d":"Elektronlar zincire yüksek enerjiyle girer."},{"t":"İlerleyiş","a":"Azalır","d":"Her basamakta biraz enerji kullanılır, elektron enerjisi azalır."}],"ans":"Elektronların enerjisi zincir boyunca giderek azalır."}],"zor":[{"q":"Tilakoit zarında elektron taşırken görev yapan hareketli bir taşıyıcı molekül hangisidir?","steps":[{"t":"Taşıyıcı kavramı","a":"Mekik molekül","d":"Bazı moleküller elektronu bir yapıdan alıp diğerine taşır."},{"t":"Örnek","a":"Plastokinon (PQ)","d":"Plastokinon elektronları bir kompleksten diğerine taşıyan mekiktir."}],"ans":"Plastokinon (PQ) elektron taşıyan hareketli bir moleküldür."},{"q":"Elektron taşıma zincirinde elektronlar hangi yönde, hangi sistemden hangisine akar?","steps":[{"t":"Başlangıç","a":"Fotosistem II","d":"Elektronlar ilk olarak fotosistem II'den ayrılır."},{"t":"Varış","a":"Fotosistem I","d":"Elektronlar zincir üzerinden fotosistem I'e doğru akar."}],"ans":"Elektronlar fotosistem II'den fotosistem I'e doğru akar."},{"q":"Elektronlar taşınırken tilakoit boşluğuna (lümen) hangi parçacıklar pompalanır?","steps":[{"t":"Taşıma enerjisi","a":"Enerji açığa çıkar","d":"Elektron taşınırken açığa çıkan enerji bir işi yapar."},{"t":"Pompalanan","a":"H⁺ (proton)","d":"Bu enerjiyle hidrojen iyonları (H⁺) lümene pompalanır."}],"ans":"Tilakoit boşluğuna H⁺ (proton) pompalanır."},{"q":"Tilakoit boşluğunda H⁺ birikmesi neden önemlidir?","steps":[{"t":"Birikme","a":"H⁺ yoğunlaşır","d":"Lümende H⁺ derişimi artar, bir yoğunluk farkı oluşur."},{"t":"Yarar","a":"ATP üretimi","d":"Bu yoğunluk farkı ATP üretiminde kullanılır."}],"ans":"Lümende biriken H⁺, ATP üretimi için enerji farkı sağlar."},{"q":"Elektron taşıma zincirinde fotosistem II ile fotosistem I arasında köprü görevi gören kompleks hangisidir?","steps":[{"t":"Aradaki yapı","a":"Bir kompleks","d":"İki fotosistem arasında elektronu aktaran bir yapı vardır."},{"t":"Adı","a":"Sitokrom b6f","d":"Sitokrom b6f kompleksi elektronu PSII tarafından alıp PSI yönüne aktarır."}],"ans":"İki fotosistem arasındaki köprü sitokrom b6f kompleksidir."}]},"lise":{"kolay":[{"q":"Fotosentezde elektron taşıma zinciri (ETZ) kloroplastın tam olarak hangi yapısında yer alır?","steps":[{"t":"Bölge","a":"Kloroplast","d":"Fotosentezin ışık tepkimeleri kloroplastta gerçekleşir."},{"t":"Zar","a":"Tilakoit zarı","d":"ETZ bileşenleri tilakoit zarına gömülü olarak bulunur."}],"ans":"Elektron taşıma zinciri tilakoit zarında bulunur."},{"q":"Tilakoit zarındaki elektron taşıma zincirinde elektronlar hangi fotosistemden başlayarak akar?","steps":[{"t":"Başlangıç noktası","a":"PSII","d":"Doğrusal akışta elektronlar fotosistem II'den (PSII) köken alır."},{"t":"Yön","a":"PSI'e doğru","d":"Elektronlar PSII'den PSI'e doğru taşınır."}],"ans":"Elektronlar PSII'den başlayıp PSI'e akar."},{"q":"Plastokinon (PQ) elektron taşıma zincirinde hangi görevi üstlenir?","steps":[{"t":"Tür","a":"Hareketli taşıyıcı","d":"PQ lipit fazda hareket edebilen küçük bir mekik moleküldür."},{"t":"Görev","a":"PSII → b6f","d":"Elektronu PSII'den sitokrom b6f kompleksine taşır."}],"ans":"PQ, elektronu PSII'den sitokrom b6f'e taşıyan hareketli taşıyıcıdır."},{"q":"Plastosiyanin (PC) elektron taşıma zincirinde hangi iki yapı arasında elektron taşır?","steps":[{"t":"Konum","a":"Lümen yüzeyi","d":"PC tilakoit lümeninde bulunan bakır içeren bir proteindir."},{"t":"Görev","a":"b6f → PSI","d":"Elektronu sitokrom b6f kompleksinden PSI'e taşır."}],"ans":"PC, elektronu sitokrom b6f kompleksinden PSI'e taşır."},{"q":"Sitokrom b6f kompleksi elektron taşıma zincirinde nasıl bir konumda bulunur?","steps":[{"t":"Konum","a":"PSII ile PSI arası","d":"b6f, iki fotosistem arasında yer alan bir zar kompleksidir."},{"t":"Görev","a":"Elektron aktarımı + H⁺ pompası","d":"Elektronu PQ'dan alıp PC'ye verir ve H⁺ pompalar."}],"ans":"Sitokrom b6f, PSII ile PSI arasında yer alıp elektronu aktarır ve H⁺ pompalar."},{"q":"Elektron taşıma zincirinde elektronlar zincir boyunca ilerlerken enerjileri nasıl değişir?","steps":[{"t":"Giriş","a":"Yüksek enerji","d":"Işıkla uyarılan elektronlar zincire yüksek enerjili girer."},{"t":"Akış","a":"Kademeli düşüş","d":"Her redoks basamağında enerji düşer; açığa çıkan enerji H⁺ pompalar."}],"ans":"Elektronların enerjisi zincir boyunca kademeli olarak azalır."},{"q":"Elektron taşıma zincirinde açığa çıkan enerji öncelikle hangi işte kullanılır?","steps":[{"t":"Enerji kaynağı","a":"Redoks basamakları","d":"Elektron aktarımındaki enerji düşüşü iş yapacak enerjiyi sağlar."},{"t":"Kullanım","a":"H⁺ pompalama","d":"Bu enerji ile H⁺ stromadan lümene pompalanır."}],"ans":"Açığa çıkan enerji H⁺'nin lümene pompalanmasında kullanılır."},{"q":"Elektron taşıma sırasında protonlar (H⁺) hangi bölmeye doğru pompalanır?","steps":[{"t":"Bölmeler","a":"Stroma / lümen","d":"Tilakoit zarı stroma ile lümeni ayırır."},{"t":"Yön","a":"Lümene","d":"H⁺ stromadan tilakoit lümenine pompalanır."}],"ans":"Protonlar tilakoit lümenine doğru pompalanır."},{"q":"Tilakoit lümeninde H⁺ birikmesi sonucu ne oluşur?","steps":[{"t":"Birikim","a":"H⁺ derişimi artar","d":"Lümende H⁺ yoğunluğu stromaya göre yükselir."},{"t":"Sonuç","a":"Proton gradyanı","d":"Zarın iki yanı arasında bir proton (H⁺) gradyanı doğar."}],"ans":"Lümende H⁺ birikmesi bir proton gradyanı oluşturur."},{"q":"Proton gradyanının enerjisi sonunda hangi molekülün üretiminde kullanılır?","steps":[{"t":"Gradyan","a":"H⁺ enerjisi","d":"Lümen-stroma arası H⁺ farkı potansiyel enerji depolar."},{"t":"Kullanım","a":"ATP","d":"ATP sentaz bu enerjiyi kullanarak ATP üretir."}],"ans":"Proton gradyanının enerjisi ATP üretiminde kullanılır."},{"q":"PSII'den ayrılan elektronların yerine gelen elektronlar nereden sağlanır?","steps":[{"t":"Eksik elektron","a":"PSII açığı","d":"Işıkla elektron kaybeden PSII'nin elektron açığı kapanmalıdır."},{"t":"Kaynak","a":"Suyun ayrışması","d":"Su molekülünün parçalanmasıyla açığa çıkan elektronlar PSII'ye gelir."}],"ans":"PSII'nin elektron açığı suyun ayrışmasıyla giderilir."},{"q":"Elektron taşıma zincirinin sonunda PSI'den ayrılan elektronlar hangi moleküle aktarılır?","steps":[{"t":"Son alıcı","a":"NADP⁺","d":"Doğrusal akışta son elektron alıcısı NADP⁺'dir."},{"t":"Ürün","a":"NADPH","d":"NADP⁺ elektron ve H⁺ alarak NADPH'ye indirgenir."}],"ans":"PSI'den çıkan elektronlar NADP⁺'ye aktarılıp NADPH oluşturur."},{"q":"Plastokinon (PQ) elektron taşırken zarda nasıl hareket eder?","steps":[{"t":"Yapı","a":"Lipitte çözünür","d":"PQ yağ fazında çözünebilen küçük bir moleküldür."},{"t":"Hareket","a":"Zar içinde difüzyon","d":"Tilakoit zarı içinde yana doğru difüzyonla hareket eder."}],"ans":"PQ tilakoit zarı içinde difüzyonla hareket ederek elektron taşır."},{"q":"Elektron taşıma zinciri 'zincir' olarak adlandırılırken hangi temel özelliği vurgulanır?","steps":[{"t":"Zincir benzetmesi","a":"Sıralı bileşenler","d":"Bileşenler belirli bir sırayla dizilmiştir."},{"t":"Aktarım","a":"Ardışık redoks","d":"Elektron her bileşene sırayla aktarılır."}],"ans":"Elektronun ardışık olarak bileşenden bileşene aktarılması vurgulanır."},{"q":"Plastosiyanin (PC) yapısında elektron taşımasını sağlayan element hangisidir?","steps":[{"t":"Protein türü","a":"Metalloprotein","d":"PC, içinde metal iyonu bulunan küçük bir proteindir."},{"t":"Element","a":"Bakır (Cu)","d":"PC, bakır iyonunun yükseltgenip indirgenmesiyle elektron taşır."}],"ans":"Plastosiyanin elektron taşımasını bakır (Cu) iyonu ile sağlar."}],"zor":[{"q":"Doğrusal elektron akışında elektronların izlediği bileşen sırası nasıldır?","steps":[{"t":"Başlangıç","a":"H₂O → PSII","d":"Su ayrışır, elektron PSII'ye, oradan ışıkla uyarılıp feofitine geçer."},{"t":"Orta zincir","a":"PQ → b6f → PC","d":"Elektron plastokinon, sitokrom b6f ve plastosiyanin üzerinden ilerler."},{"t":"Son","a":"PSI → NADP⁺","d":"PSI'de tekrar uyarılan elektron ferredoksin yoluyla NADP⁺'ye aktarılır."}],"ans":"Sıra: H₂O → PSII → PQ → b6f → PC → PSI → NADP⁺ (NADPH)."},{"q":"Sitokrom b6f kompleksi neden proton gradyanına PSII'den daha fazla katkı sağlayabilir?","steps":[{"t":"Q-çevrimi","a":"PQ döngüsü","d":"b6f'te plastokinol oksidasyonu Q-çevrimi ile gerçekleşir."},{"t":"Ek pompalama","a":"Fazla H⁺","d":"Q-çevrimi her elektron için lümene ek H⁺ taşınmasını sağlar."}],"ans":"Q-çevrimi sayesinde b6f, lümene fazladan H⁺ pompalayarak gradyana güçlü katkı verir."},{"q":"Plastokinonun (PQ) hem elektron hem proton taşıması gradyan oluşumuna nasıl katkı sağlar?","steps":[{"t":"İndirgenme","a":"Stroma yüzeyi","d":"PQ, PSII'den 2 elektron ve stromadan 2 H⁺ alarak PQH₂ olur."},{"t":"Yükseltgenme","a":"Lümen yüzeyi","d":"PQH₂, b6f'te yükseltgenir; aldığı H⁺'leri lümene bırakır."}],"ans":"PQ, H⁺'leri stromadan alıp lümene bırakarak proton gradyanını besler."},{"q":"Elektron taşıma zincirindeki bileşenler neden belirli bir sırayla dizilmiştir?","steps":[{"t":"İlke","a":"Redoks potansiyeli","d":"Her bileşenin elektron çekme eğilimi (redoks potansiyeli) farklıdır."},{"t":"Dizilim","a":"Artan potansiyel","d":"Elektron, düşük potansiyelden yüksek potansiyelli bileşene kendiliğinden akar."}],"ans":"Bileşenler artan redoks potansiyeline göre dizildiği için elektron akışı kendiliğinden olur."},{"q":"Tilakoit lümeni ile stroma arasındaki proton gradyanı hangi iki bileşenden oluşur?","steps":[{"t":"Birinci bileşen","a":"Kimyasal gradyan (ΔpH)","d":"Lümende H⁺ derişimi yüksek olduğundan pH farkı oluşur."},{"t":"İkinci bileşen","a":"Elektriksel gradyan","d":"Yük ayrımı zar boyunca bir elektriksel potansiyel yaratır."}],"ans":"Proton gradyanı kimyasal (ΔpH) ve elektriksel potansiyel farkının toplamından oluşur."},{"q":"PSII'de oluşan elektron açığının suyla kapatılması sırasında lümene ne katkıda bulunulur?","steps":[{"t":"Suyun ayrışması","a":"2H₂O → O₂ + 4H⁺ + 4e⁻","d":"Su ayrışması lümen tarafında gerçekleşir."},{"t":"Gradyana katkı","a":"Lümene H⁺","d":"Açığa çıkan H⁺ doğrudan lümende kalarak gradyanı artırır."}],"ans":"Suyun ayrışmasıyla açığa çıkan H⁺ lümende birikerek proton gradyanına katkı sağlar."},{"q":"Elektronlar PSI'e ulaşmadan önce neden ışık enerjisiyle yeniden uyarılmaları gerekir?","steps":[{"t":"Enerji kaybı","a":"Zincirde düşüş","d":"Elektronlar PSII'den PSI'e gelirken redoks basamaklarında enerji kaybeder."},{"t":"Tekrar uyarılma","a":"PSI'de ışık","d":"NADP⁺'yi indirgeyecek kadar enerji için PSI'de tekrar uyarılırlar."}],"ans":"Zincirde enerji kaybeden elektronlar, NADP⁺'yi indirgeyebilmek için PSI'de yeniden uyarılır."},{"q":"Plastosiyanin (PC) elektron taşıma zincirinde nerede ve nasıl hareket eder?","steps":[{"t":"Konum","a":"Lümen içinde","d":"PC, tilakoit lümeninde çözünmüş halde bulunan küçük bir proteindir."},{"t":"Hareket","a":"Yüzey difüzyonu","d":"Lümende b6f ile PSI arasında difüzyonla mekik dokur."}],"ans":"PC, tilakoit lümeninde b6f ile PSI arasında difüzyonla hareket ederek elektron taşır."},{"q":"Sitokrom b6f kompleksi içinde elektron hangi bileşenler arasında aktarılır?","steps":[{"t":"Giriş","a":"PQH₂'den","d":"Elektronlar indirgenmiş plastokinon (PQH₂) tarafından getirilir."},{"t":"İç aktarım","a":"Demir-kükürt ve sitokromlar","d":"Rieske demir-kükürt merkezi ve sitokrom f üzerinden elektron PC'ye verilir."}],"ans":"b6f içinde elektron, Rieske Fe-S merkezi ve sitokrom f üzerinden PQH₂'den PC'ye aktarılır."},{"q":"Doğrusal (asiklik) elektron akışı ile döngüsel (siklik) akış arasındaki temel fark nedir?","steps":[{"t":"Doğrusal akış","a":"PSII + PSI","d":"Elektron sudan gelir, NADPH ile O₂ üretilir; hem ATP hem NADPH oluşur."},{"t":"Döngüsel akış","a":"Yalnız PSI","d":"Elektron PSI'den b6f'e geri döner; yalnız ATP üretilir, NADPH ve O₂ oluşmaz."}],"ans":"Doğrusalda PSII+PSI ile ATP ve NADPH üretilir; döngüselde yalnız PSI ile sadece ATP üretilir."},{"q":"Elektron taşıma zinciri durduğunda proton gradyanına ve ATP üretimine ne olur?","steps":[{"t":"Akış durur","a":"H⁺ pompalanmaz","d":"Elektron akışı kesilince lümene yeni H⁺ pompalanamaz."},{"t":"Gradyan söner","a":"ATP azalır","d":"Var olan gradyan tüketilir ve ATP sentaz enerjisiz kalarak ATP üretimi durur."}],"ans":"Elektron akışı durunca proton gradyanı sönerek ATP üretimi durur."},{"q":"Tilakoit lümeni pH'ının stromaya göre düşük (asidik) olmasının nedeni nedir?","steps":[{"t":"H⁺ kaynağı","a":"Pompalama + su ayrışması","d":"b6f H⁺ pompalar, su ayrışması da lümene H⁺ bırakır."},{"t":"Sonuç","a":"Asidik lümen","d":"Lümende H⁺ birikmesi pH'ı düşürerek ortamı asidik yapar."}],"ans":"Lümene H⁺ pompalanıp su ayrışmasıyla H⁺ eklendiği için lümen stromaya göre asidiktir."},{"q":"Plastokinonun zincirdeki konumu, b6f kompleksinin H⁺ pompalama yeteneğiyle nasıl ilişkilidir?","steps":[{"t":"PQ taşıması","a":"H⁺ + e⁻","d":"PQ hem elektron hem proton taşıyabilen bir moleküldür."},{"t":"b6f kullanımı","a":"Q-çevrimi","d":"b6f, PQ'nun bu çift taşıma özelliğini Q-çevriminde kullanarak ek H⁺ pompalar."}],"ans":"PQ'nun H⁺+e⁻ taşıma özelliği, b6f'in Q-çevrimi ile fazladan H⁺ pompalamasını mümkün kılar."},{"q":"Elektron taşıma zincirinin oksijen üretimiyle ilişkisi nasıl açıklanır?","steps":[{"t":"Elektron talebi","a":"PSII açığı","d":"PSII ışıkla elektron kaybedince bir elektron açığı oluşur."},{"t":"Su ayrışması","a":"O₂ açığa çıkar","d":"Bu açığı kapatmak için su ayrışır ve yan ürün olarak O₂ oluşur."}],"ans":"ETZ, PSII'nin elektron talebiyle su ayrışmasını tetikler; bunun yan ürünü oksijendir."},{"q":"Kemiozmotik kuram, elektron taşıma zinciri ile ATP üretimini nasıl ilişkilendirir?","steps":[{"t":"Enerji dönüşümü","a":"Elektron → gradyan","d":"Elektron akışının enerjisi proton gradyanı olarak depolanır."},{"t":"Gradyan → ATP","a":"ATP sentaz","d":"H⁺'ler gradyan boyunca ATP sentazdan stromaya akarken ATP üretilir."}],"ans":"Kemiozmotik kurama göre ETZ'nin oluşturduğu proton gradyanı, ATP sentaz aracılığıyla ATP üretimini sağlar."}]}},"faktorler":{"ilkokul":{"kolay":[{"q":"Bir bitkiyi karanlık bir dolaba koyarsak fotosentez yapabilir mi?","steps":[{"t":"Işık gerekli mi?","a":"Evet, gerekli","d":"Bitkiler fotosentez yapmak için <b>ışığa</b> ihtiyaç duyar; ışık olmadan besin üretemezler."},{"t":"Dolapta ne olur?","a":"Işık yok","d":"Karanlık dolapta ışık bulunmadığı için bitki fotosentez yapamaz."}],"ans":"Hayır; karanlıkta ışık olmadığı için bitki fotosentez yapamaz."},{"q":"Bir saksı çiçeğini hiç sulamazsak fotosentezi nasıl etkilenir?","steps":[{"t":"Su ne işe yarar?","a":"Fotosentez malzemesi","d":"Bitki fotosentez yaparken topraktan aldığı <b>suyu</b> kullanır."},{"t":"Su olmazsa?","a":"Yavaşlar veya durur","d":"Su olmayınca bitki besin üretmekte zorlanır ve solar."}],"ans":"Su olmayınca fotosentez yavaşlar; bitki solar."},{"q":"Güneşli bir günde mi yoksa bulutlu bir günde mi bitki daha çok fotosentez yapar?","steps":[{"t":"Hangi günde ışık çok?","a":"Güneşli gün","d":"Güneşli günde <b>daha fazla ışık</b> vardır."},{"t":"Sonuç","a":"Güneşli günde fazla","d":"Işık arttıkça fotosentez de artar."}],"ans":"Güneşli günde; çünkü daha çok ışık vardır."},{"q":"Bitkiler ışığı hangi renkli kısımlarıyla yakalar?","steps":[{"t":"Yeşil kısım hangisi?","a":"Yapraklar","d":"Bitkinin <b>yeşil yaprakları</b> ışığı yakalar."},{"t":"Neden yeşil?","a":"İçinde yeşil madde var","d":"Yapraktaki yeşil madde ışığı toplayıp fotosentezi başlatır."}],"ans":"Bitkiler ışığı yeşil yapraklarıyla yakalar."},{"q":"Çok soğuk bir kış gününde dışarıdaki bir bitkinin fotosentezi nasıl olur?","steps":[{"t":"Sıcaklık nasıl?","a":"Çok düşük","d":"Kışın hava <b>çok soğuktur</b>."},{"t":"Etkisi","a":"Yavaşlar","d":"Çok soğukta bitkinin çalışması yavaşladığı için fotosentez azalır."}],"ans":"Çok soğukta fotosentez yavaşlar."}],"zor":[{"q":"Bir bitkiye bol ışık veriyoruz ama hiç su vermiyoruz. Bol ışık fotosentezi kurtarır mı?","steps":[{"t":"Kaç malzeme gerekli?","a":"Hem ışık hem su","d":"Fotosentez için bitkiye <b>hem ışık hem su</b> gerekir."},{"t":"Su yoksa?","a":"Yine yetersiz","d":"Su olmadan ışık tek başına yeterli olmaz; eksik malzeme işi durdurur."}],"ans":"Hayır; su olmadan bol ışık tek başına yeterli olmaz."},{"q":"İki aynı bitkiden birini pencere önüne, diğerini dolaba koyuyoruz. Bir hafta sonra hangisi daha sağlıklı olur ve neden?","steps":[{"t":"Hangisi ışık alır?","a":"Pencere önündeki","d":"Pencere önündeki bitki <b>ışık</b> alır."},{"t":"Sonuç","a":"Penceredeki sağlıklı","d":"Işık alan bitki fotosentez yapıp besin ürettiği için daha sağlıklı olur."}],"ans":"Pencere önündeki; çünkü ışık alıp fotosentez yaparak besin üretir."},{"q":"Sıcacık ve aydınlık bir odadaki bitki ile buzdolabındaki bir bitkiden hangisi daha hızlı fotosentez yapar?","steps":[{"t":"İki koşul nasıl?","a":"Işık ve ılık sıcaklık","d":"Odadaki bitki hem <b>ışık</b> hem de uygun <b>sıcaklık</b> bulur."},{"t":"Buzdolabında?","a":"Soğuk ve karanlık","d":"Buzdolabı hem soğuk hem karanlık olduğu için fotosentez neredeyse durur."}],"ans":"Sıcak ve aydınlık odadaki bitki daha hızlı fotosentez yapar."},{"q":"Yaprakları tozla kaplanmış bir bitkinin fotosentezi neden azalır?","steps":[{"t":"Toz ne yapar?","a":"Işığı engeller","d":"Yaprağı kaplayan toz, <b>ışığın</b> yaprağa ulaşmasını engeller."},{"t":"Sonuç","a":"Az ışık az fotosentez","d":"Yaprak yeterince ışık alamadığı için fotosentez azalır."}],"ans":"Toz ışığı engellediği için yaprak az ışık alır, fotosentez azalır."},{"q":"Yazın bitkiler genellikle daha hızlı büyür. Bunun fotosentezle ilgisi nedir?","steps":[{"t":"Yazın koşullar","a":"Bol ışık ve ılık hava","d":"Yazın <b>ışık çok</b> ve hava <b>ılıktır</b>."},{"t":"Etkisi","a":"Fazla fotosentez","d":"Bol ışık ve uygun sıcaklıkta bitki çok fotosentez yapıp çok besin ürettiği için hızlı büyür."}],"ans":"Yazın bol ışık ve uygun sıcaklıkta fotosentez artar, bitki hızlı büyür."}]},"ortaokul":{"kolay":[{"q":"Işık şiddeti arttıkça fotosentez hızı nasıl değişir?","steps":[{"t":"Işık fotosentezde ne yapar?","a":"Enerji sağlar","d":"Işık, fotosentez için gereken <b>enerjiyi</b> sağlar."},{"t":"Şiddet artarsa?","a":"Hız artar","d":"Belli bir noktaya kadar ışık şiddeti arttıkça fotosentez hızı artar."}],"ans":"Belli bir noktaya kadar ışık şiddeti arttıkça fotosentez hızı artar."},{"q":"Karbondioksit derişiminin artması fotosentezi nasıl etkiler?","steps":[{"t":"CO₂ ne için kullanılır?","a":"Ham madde","d":"Karbondioksit, fotosentezde besin yapımının <b>ham maddesidir</b>."},{"t":"Derişim artarsa?","a":"Hız artar","d":"Yeterli ışık varken CO₂ derişimi arttıkça fotosentez hızı artar."}],"ans":"Yeterli ışıkta CO₂ derişimi arttıkça fotosentez hızı artar."},{"q":"Suyun fotosentezdeki rolü nedir ve eksikliği hızı nasıl etkiler?","steps":[{"t":"Su nerede kullanılır?","a":"Ham madde","d":"Su, fotosentezin <b>ham maddelerinden</b> biridir."},{"t":"Su azalırsa?","a":"Hız azalır","d":"Su yetersizse stomalar kapanır ve fotosentez hızı düşer."}],"ans":"Su ham maddedir; eksikliğinde fotosentez hızı azalır."},{"q":"Çok düşük sıcaklıkta fotosentez hızının azalmasının nedeni nedir?","steps":[{"t":"Fotosentezi kim yürütür?","a":"Enzimler","d":"Fotosentez tepkimelerini <b>enzimler</b> yürütür."},{"t":"Soğukta enzim?","a":"Yavaş çalışır","d":"Düşük sıcaklıkta enzimler yavaş çalıştığı için fotosentez hızı azalır."}],"ans":"Düşük sıcaklıkta enzimler yavaşladığı için fotosentez hızı azalır."},{"q":"Bir bitkiye sadece ışık verip karbondioksit vermezsek fotosentez yapabilir mi?","steps":[{"t":"CO₂ şart mı?","a":"Evet","d":"Karbondioksit fotosentezin <b>ham maddesidir</b>."},{"t":"CO₂ yoksa?","a":"Yapamaz","d":"Işık olsa bile CO₂ olmadan besin üretilemez."}],"ans":"Hayır; CO₂ olmadan ışık tek başına yeterli değildir."}],"zor":[{"q":"Bol ışık ve uygun sıcaklık olmasına rağmen ortamda çok az CO₂ varsa fotosentez hızını ne belirler?","steps":[{"t":"Hangi faktör eksik?","a":"CO₂","d":"Diğer koşullar uygunken <b>CO₂ azdır</b>."},{"t":"Sınırlayan ne?","a":"En az olan","d":"Fotosentez hızını, en yetersiz olan faktör (sınırlayıcı faktör) belirler."}],"ans":"Hızı, en yetersiz faktör olan CO₂ (sınırlayıcı faktör) belirler."},{"q":"Işık şiddetini sürekli artırdığımızda fotosentez hızı neden bir süre sonra sabitlenir?","steps":[{"t":"Başta ne olur?","a":"Hız artar","d":"Düşük ışıkta şiddet arttıkça hız <b>artar</b>."},{"t":"Sonra neden durur?","a":"Başka faktör sınırlar","d":"Bir noktadan sonra CO₂ veya sıcaklık gibi başka bir faktör sınırlayıcı olur ve hız sabitlenir."}],"ans":"Bir noktadan sonra başka bir faktör sınırlayıcı olduğu için hız sabitlenir."},{"q":"Sıcaklık çok yükseldiğinde fotosentez hızının düşmesinin nedeni nedir?","steps":[{"t":"Hangi yapı etkilenir?","a":"Enzimler","d":"Fotosentezi yürüten <b>enzimler</b> proteindir."},{"t":"Aşırı sıcakta?","a":"Bozulur","d":"Çok yüksek sıcaklık enzimlerin yapısını bozar (denatüre eder), bu yüzden hız düşer."}],"ans":"Aşırı sıcaklıkta enzimler bozulduğu için fotosentez hızı düşer."},{"q":"Bir akvaryum bitkisi ışık altında daha çok hava kabarcığı çıkarıyor. Bu kabarcıklar neyi gösterir ve ışıkla ilişkisi nedir?","steps":[{"t":"Kabarcık hangi gaz?","a":"Oksijen","d":"Kabarcıklar fotosentezde üretilen <b>oksijendir</b>."},{"t":"Işıkla ilişki","a":"Işık çok, kabarcık çok","d":"Işık şiddeti arttıkça fotosentez hızlanır, üretilen oksijen ve kabarcık sayısı artar."}],"ans":"Kabarcıklar üretilen oksijendir; ışık arttıkça fotosentez ve kabarcık sayısı artar."},{"q":"Topraktaki mineral (örneğin azot, magnezyum) eksikliği fotosentezi neden olumsuz etkiler?","steps":[{"t":"Mineraller ne için gerekli?","a":"Klorofil yapımı","d":"Magnezyum gibi mineraller <b>klorofilin</b> yapısına katılır."},{"t":"Eksik olursa?","a":"Az klorofil","d":"Mineral eksikliğinde yeterli klorofil üretilemez, ışık az yakalanır ve fotosentez azalır."}],"ans":"Mineraller klorofil yapımına katılır; eksikliklerinde fotosentez azalır."}]},"lise":{"kolay":[{"q":"Sınırlayıcı faktör nedir?","steps":[{"t":"Tanım","a":"En yetersiz faktör","d":"Bir tepkimenin hızını belirleyen, ortamda <b>en az</b> veya en yetersiz bulunan faktördür."},{"t":"Fotosentezde","a":"Hızı o belirler","d":"Fotosentezde diğer koşullar yeterli olsa bile, sınırlayıcı faktör hızı sınırlar."}],"ans":"Sınırlayıcı faktör, hızı belirleyen, ortamda en yetersiz bulunan faktördür."},{"q":"Doygunluk noktası kavramı fotosentezde neyi ifade eder?","steps":[{"t":"Faktör artarken","a":"Hız önce artar","d":"Bir faktör (örneğin ışık) artarken fotosentez hızı bir süre <b>artar</b>."},{"t":"Doygunlukta","a":"Hız sabitlenir","d":"Faktör daha da artsa bile hızın artmadığı, sabit kaldığı noktaya doygunluk noktası denir."}],"ans":"Doygunluk noktası, faktör artmaya devam etse de fotosentez hızının artmayıp sabitlendiği noktadır."},{"q":"Fotosentez hızını etkileyen çevresel faktörler nelerdir?","steps":[{"t":"Faktörleri sırala","a":"Işık, CO₂, sıcaklık, su, mineral","d":"Başlıca çevresel faktörler <b>ışık şiddeti</b>, ışık dalga boyu, CO₂ derişimi, sıcaklık, su ve minerallerdir."},{"t":"Ortak etki","a":"Hızı değiştirir","d":"Bu faktörlerin her biri belirli sınırlar içinde fotosentez hızını artırır veya azaltır."}],"ans":"Işık şiddeti, ışık dalga boyu, CO₂ derişimi, sıcaklık, su ve mineraller."},{"q":"Klorofil hangi dalga boylarındaki ışığı en çok soğurur?","steps":[{"t":"En verimli renkler","a":"Mavi ve kırmızı","d":"Klorofil özellikle <b>mavi</b> (yaklaşık 430 nm) ve <b>kırmızı</b> (yaklaşık 660 nm) ışığı yüksek oranda soğurur."},{"t":"Yeşil ışık","a":"Az soğurur","d":"Yeşil ışığı büyük oranda yansıttığı için yapraklar yeşil görünür ve yeşilde fotosentez düşüktür."}],"ans":"Klorofil en çok mavi ve kırmızı dalga boylarını soğurur; yeşili yansıtır."},{"q":"Sıcaklığın fotosentez hızı üzerindeki etkisi neden enzimlerle ilişkilidir?","steps":[{"t":"Tepkimeleri kim yürütür?","a":"Enzimler","d":"Fotosentezin özellikle karanlık evre (Calvin) tepkimelerini <b>enzimler</b> katalizler."},{"t":"Sıcaklık-enzim","a":"Aktiviteyi belirler","d":"Enzim aktivitesi sıcaklığa bağlıdır; bu yüzden sıcaklık fotosentez hızını doğrudan etkiler."}],"ans":"Fotosentez tepkimeleri enzimlerle yürür ve enzim aktivitesi sıcaklığa bağlı olduğu için sıcaklık hızı etkiler."},{"q":"Optimum sıcaklık fotosentez için ne anlama gelir?","steps":[{"t":"Tanım","a":"En yüksek hız sıcaklığı","d":"Enzimlerin en verimli çalıştığı ve fotosentez hızının <b>en yüksek</b> olduğu sıcaklıktır."},{"t":"Bitkilere göre","a":"Değişir","d":"Çoğu bitkide optimum sıcaklık yaklaşık 25-35 °C aralığındadır, türe göre değişir."}],"ans":"Optimum sıcaklık, fotosentez hızının en yüksek olduğu sıcaklıktır (çoğu bitkide ~25-35 °C)."},{"q":"Karanlıkta bir bitkiyi tuttuğumuzda fotosentez hızı neden sıfıra yaklaşır?","steps":[{"t":"Işık ne sağlar?","a":"Enerji","d":"Fotosentezin ışığa bağımlı evresi <b>ışık enerjisini</b> kullanır."},{"t":"Işık yoksa","a":"Işığa bağımlı evre durur","d":"Işık olmadan ışığa bağımlı tepkimeler işlemez, ATP ve NADPH üretilmez, fotosentez durur."}],"ans":"Işık olmadan ışığa bağımlı evre çalışamadığı için fotosentez hızı sıfıra yaklaşır."},{"q":"Su miktarının fotosentezi etkilemesinde stomaların rolü nedir?","steps":[{"t":"Su azalınca","a":"Stomalar kapanır","d":"Su yetersizliğinde bitki su kaybını önlemek için <b>stomalarını kapatır</b>."},{"t":"Sonuç","a":"CO₂ giremez","d":"Stomalar kapanınca yaprağa CO₂ girişi azalır ve fotosentez hızı düşer."}],"ans":"Su azalınca stomalar kapanır, CO₂ girişi azalır ve fotosentez hızı düşer."},{"q":"Minerallerin (örneğin magnezyum ve azot) fotosentezdeki önemi nedir?","steps":[{"t":"Magnezyum","a":"Klorofil merkezinde","d":"Magnezyum, <b>klorofil</b> molekülünün merkezinde yer alır."},{"t":"Azot","a":"Klorofil ve enzim yapısında","d":"Azot, klorofilin ve fotosentez enzimlerinin yapısına katılır; eksiklikleri fotosentezi düşürür."}],"ans":"Magnezyum ve azot klorofil ile enzimlerin yapısına katılır; eksikliklerinde fotosentez azalır."},{"q":"Düşük ışık şiddetinde fotosentez hızı grafiğinde neden doğrusal bir artış görülür?","steps":[{"t":"Düşük ışıkta","a":"Işık sınırlayıcı","d":"Düşük ışıkta <b>ışık</b> sınırlayıcı faktördür."},{"t":"Artırınca","a":"Hız orantılı artar","d":"Bu bölgede ışık arttıkça hız neredeyse doğru orantılı (doğrusal) artar."}],"ans":"Düşük ışıkta ışık sınırlayıcı olduğu için şiddet arttıkça hız doğrusal artar."},{"q":"İki aynı bitkiden biri %0,04 CO₂, diğeri %0,1 CO₂ ortamında, aynı ışık ve sıcaklıkta tutuluyor. Hangisi daha hızlı fotosentez yapar?","steps":[{"t":"Fark hangi faktörde?","a":"CO₂ derişimi","d":"Tek değişken <b>CO₂ derişimidir</b>."},{"t":"Sonuç","a":"%0,1 olan","d":"CO₂ derişimi yüksek olan (%0,1) ortam, sınırlayıcı faktör giderildiği için daha hızlı fotosentez yapar."}],"ans":"%0,1 CO₂ ortamındaki bitki daha hızlı fotosentez yapar."},{"q":"Yeşil ışıkta fotosentez hızının düşük olmasının sebebi nedir?","steps":[{"t":"Klorofil yeşili ne yapar?","a":"Yansıtır","d":"Klorofil yeşil dalga boyunu büyük ölçüde <b>yansıtır</b>, çok az soğurur."},{"t":"Sonuç","a":"Az enerji","d":"Soğurulan ışık az olduğu için yeşil ışıkta fotosentez hızı düşük kalır."}],"ans":"Klorofil yeşil ışığı yansıtıp az soğurduğu için yeşil ışıkta fotosentez hızı düşüktür."},{"q":"Bir serada üretimi artırmak için CO₂ derişimini yükseltmek neden işe yarar?","steps":[{"t":"CO₂'nin rolü","a":"Ham madde","d":"CO₂, Calvin döngüsünde besin yapımının <b>ham maddesidir</b>."},{"t":"Derişim artarsa","a":"Hız artar","d":"Diğer faktörler yeterliyse CO₂ artışı, CO₂'nin sınırlayıcı olduğu durumda fotosentezi ve verimi artırır."}],"ans":"CO₂ ham madde olduğundan, derişimi artırmak (sınırlayıcıyken) fotosentez hızını ve verimi artırır."},{"q":"Fotosentez hızı neden hem çok düşük hem çok yüksek sıcaklıkta azalır?","steps":[{"t":"Çok düşükte","a":"Enzim yavaş","d":"Düşük sıcaklıkta enzimler <b>yavaş</b> çalışır, hız azalır."},{"t":"Çok yüksekte","a":"Enzim bozulur","d":"Çok yüksek sıcaklıkta enzimler denatüre olur (yapısı bozulur), bu yüzden hız tekrar düşer."}],"ans":"Düşük sıcaklıkta enzimler yavaşladığı, yüksek sıcaklıkta denatüre olduğu için her iki uçta hız azalır."},{"q":"Bir bitki yeterli ışık ve CO₂ alıyor ama sıcaklık optimumun çok altında. Hızı artırmak için ne yapılmalı?","steps":[{"t":"Sınırlayıcı ne?","a":"Sıcaklık","d":"Işık ve CO₂ yeterli olduğundan sınırlayıcı faktör <b>sıcaklıktır</b>."},{"t":"Çözüm","a":"Sıcaklığı optimuma çıkarmak","d":"Sıcaklığı optimum değere yaklaştırmak enzim aktivitesini artırır ve fotosentez hızlanır."}],"ans":"Sınırlayıcı sıcaklık olduğu için sıcaklığı optimuma yaklaştırmak gerekir."}],"zor":[{"q":"Işık-fotosentez hızı grafiğinde başlangıçta doğrusal artan eğri, sonradan yatay bir plato yapıyor. Bu platonun nedenini açıklayınız.","steps":[{"t":"Başlangıç bölgesi","a":"Işık sınırlayıcı","d":"Eğrinin doğrusal kısmında <b>ışık</b> sınırlayıcı faktördür; arttıkça hız artar."},{"t":"Plato bölgesi","a":"Başka faktör sınırlar","d":"Platoda ışık artık sınırlayıcı değildir; CO₂ derişimi veya sıcaklık gibi başka bir faktör sınırlayıcı olur."},{"t":"Sonuç","a":"Hız sabitlenir","d":"Sınırlayıcı faktör değiştiği için ışık arttırılsa da hız artmaz, sabit kalır (doygunluk)."}],"ans":"Platoda ışık sınırlayıcı olmaktan çıkar; CO₂ veya sıcaklık sınırlayıcı olduğu için hız sabitlenir."},{"q":"Aynı ışık eğrisi düşük CO₂'de daha alçak bir platoda, yüksek CO₂'de daha yüksek bir platoda sabitleniyor. Bu durum sınırlayıcı faktör kavramıyla nasıl açıklanır?","steps":[{"t":"Plato yüksekliği neye bağlı?","a":"Sınırlayıcı faktöre","d":"Plato yüksekliği, ışık dışında sınırlayıcı olan faktörün (<b>CO₂</b>) değerine bağlıdır."},{"t":"Düşük CO₂'de","a":"Erken ve alçak plato","d":"Düşük CO₂ erken sınırlayıcı olur, hız daha alçak bir değerde sabitlenir."},{"t":"Yüksek CO₂'de","a":"Daha yüksek plato","d":"CO₂ artırılınca sınırlama gevşer, hız daha yüksek bir platoda sabitlenir."}],"ans":"Plato yüksekliği CO₂ derişimiyle belirlenir; CO₂ arttıkça yeni sınırlayıcıya kadar hız daha yüksek bir platoda sabitlenir."},{"q":"Sıcaklık-fotosentez hızı grafiği neden çan (tepe) şeklindedir? Eğrinin yükselen, tepe ve düşen kısımlarını açıklayınız.","steps":[{"t":"Yükselen kısım","a":"Enzim hızlanır","d":"Sıcaklık arttıkça <b>enzim aktivitesi</b> ve molekül çarpışmaları artar, hız yükselir."},{"t":"Tepe","a":"Optimum sıcaklık","d":"Enzimlerin en verimli çalıştığı optimum sıcaklıkta hız maksimuma ulaşır."},{"t":"Düşen kısım","a":"Denatürasyon","d":"Optimumun üstünde enzimler denatüre olmaya başlar, aktif bölgeleri bozulur ve hız hızla düşer."}],"ans":"Eğri çan şeklindedir; hız optimuma kadar artar, optimumda en yüksektir, sonra enzim denatürasyonuyla hızla düşer."},{"q":"Bol ışık ve yüksek sıcaklığa rağmen CO₂ derişimi çok düşükse fotosentez hızı düşük kalır. Bunu Calvin döngüsü ile ilişkilendirerek açıklayınız.","steps":[{"t":"CO₂ nerede kullanılır?","a":"Calvin döngüsü","d":"CO₂, <b>Calvin döngüsünde</b> RuBP ile birleşerek karbon tutulumunda kullanılır."},{"t":"CO₂ azsa","a":"Karbon tutulumu yavaş","d":"Az CO₂ ile karbon tutulumu yavaşlar, üretilen glikoz azalır."},{"t":"Sonuç","a":"CO₂ sınırlayıcı","d":"Işık ve sıcaklık yeterli olsa da CO₂ sınırlayıcı faktör olduğu için fotosentez hızı düşük kalır."}],"ans":"Az CO₂ Calvin döngüsünde karbon tutulumunu yavaşlatır; CO₂ sınırlayıcı olduğundan diğer koşullar uygun olsa da hız düşük kalır."},{"q":"Bir araştırmacı ışık şiddetini iki katına çıkardığında fotosentez hızının değişmediğini gözlemliyor. Bu sonucu hangi olası nedenlerle açıklarsınız?","steps":[{"t":"Olası durum 1","a":"Doygunluk aşılmış","d":"Bitki zaten ışık <b>doygunluk noktasının</b> üzerindedir; daha fazla ışık hızı artırmaz."},{"t":"Olası durum 2","a":"Başka faktör sınırlayıcı","d":"CO₂ veya sıcaklık sınırlayıcı olduğundan ışık artışı etkisizdir."},{"t":"Sonuç","a":"Işık sınırlayıcı değil","d":"Bu koşullarda ışık sınırlayıcı faktör olmadığı için şiddetini artırmak hızı değiştirmez."}],"ans":"Bitki ışık doygunluğunu aşmıştır veya CO₂/sıcaklık sınırlayıcıdır; bu yüzden ışığı artırmak hızı değiştirmez."},{"q":"Eylem (aksiyon) spektrumu ve soğurma (absorpsiyon) spektrumunun mavi ve kırmızı bölgelerde tepe yapması neyi gösterir?","steps":[{"t":"Soğurma spektrumu","a":"Soğurulan dalga boyları","d":"Klorofil özellikle <b>mavi ve kırmızı</b> dalga boylarını yoğun soğurur."},{"t":"Eylem spektrumu","a":"Fotosentez hızı","d":"Fotosentez hızı da mavi ve kırmızı bölgelerde en yüksektir."},{"t":"İlişki","a":"Örtüşme","d":"İki spektrumun örtüşmesi, en çok soğurulan dalga boylarının fotosentezi en çok artıran dalga boyları olduğunu gösterir."}],"ans":"İki spektrumun mavi ve kırmızıda örtüşmesi, en çok soğurulan dalga boylarının fotosentezi en çok yürüten dalga boyları olduğunu gösterir."},{"q":"Sıcak ve kurak bir günde öğle saatlerinde fotosentez hızının düşmesinin (öğle depresyonu) nedenini açıklayınız.","steps":[{"t":"Öğle koşulları","a":"Yüksek sıcaklık, su kaybı","d":"Öğlen sıcaklık ve terleme (transpirasyon) yüksektir, bitki <b>su kaybeder</b>."},{"t":"Bitkinin tepkisi","a":"Stoma kapanır","d":"Su kaybını azaltmak için stomalar kapanır."},{"t":"Sonuç","a":"CO₂ azalır, hız düşer","d":"Stomalar kapanınca yaprağa CO₂ girişi azalır ve fotosentez hızı düşer."}],"ans":"Öğlen su kaybını önlemek için stomalar kapanır, CO₂ girişi azalır ve fotosentez hızı geçici olarak düşer."},{"q":"Magnezyum eksikliği yaşayan bir bitkide yaprakların sararması (kloroz) ve fotosentez azalması arasındaki bağlantıyı açıklayınız.","steps":[{"t":"Magnezyumun rolü","a":"Klorofil merkezi","d":"Magnezyum, <b>klorofil</b> molekülünün merkez atomudur."},{"t":"Eksiklikte","a":"Klorofil az","d":"Magnezyum eksikliğinde yeterli klorofil sentezlenemez, yapraklar sararır (kloroz)."},{"t":"Sonuç","a":"Işık az soğurulur","d":"Klorofil azaldığı için ışık enerjisi az soğurulur ve fotosentez hızı düşer."}],"ans":"Magnezyum klorofilin merkezindedir; eksikliğinde klorofil azalır, yapraklar sararır ve fotosentez düşer."},{"q":"Su yalnızca ham madde olarak mı fotosentezi etkiler, yoksa dolaylı etkileri de var mıdır? Açıklayınız.","steps":[{"t":"Doğrudan etki","a":"Ham madde","d":"Su, ışığa bağımlı evrede parçalanarak (fotoliz) elektron, proton ve <b>oksijen</b> kaynağı olur."},{"t":"Dolaylı etki","a":"Stoma ve turgor","d":"Su, hücre turgorunu ve stoma açıklığını düzenler; su azalınca stomalar kapanır."},{"t":"Sonuç","a":"İki yönlü etki","d":"Bu yüzden su hem doğrudan ham madde hem de stoma yoluyla CO₂ girişini etkileyerek fotosentezi belirler."}],"ans":"Su hem ışığa bağımlı evrede ham maddedir hem de stoma açıklığını etkileyerek CO₂ girişini düzenler; bu yüzden iki yönlü etkilidir."},{"q":"Düşük sıcaklıkta yapılan bir deneyde ışık şiddetini artırmak fotosentez hızını neden sınırlı oranda artırır?","steps":[{"t":"Düşük sıcaklıkta","a":"Enzim yavaş","d":"Düşük sıcaklıkta Calvin döngüsü <b>enzimleri</b> yavaş çalışır."},{"t":"Işık artışı","a":"ATP/NADPH artar","d":"Işık artışı ışığa bağımlı evrede ATP ve NADPH üretimini artırır."},{"t":"Sonuç","a":"Sıcaklık sınırlar","d":"Enzimler yavaş olduğundan üretilen ATP/NADPH tam kullanılamaz; sıcaklık sınırlayıcı olduğu için hız sınırlı artar."}],"ans":"Düşük sıcaklıkta enzimler yavaş olduğundan, ışık artsa bile sıcaklık sınırlayıcı kalır ve hız sınırlı artar."},{"q":"Bir grafikte fotosentez hızı CO₂ derişimiyle önce dik artıyor, sonra yatay sabitleniyor. Yatay bölgede CO₂ artırmanın işe yaramamasını açıklayınız.","steps":[{"t":"Dik artış","a":"CO₂ sınırlayıcı","d":"Başta <b>CO₂</b> sınırlayıcıdır; arttıkça karbon tutulumu ve hız hızla artar."},{"t":"Yatay bölge","a":"Doygunluk","d":"Belli bir derişimde CO₂ artık sınırlayıcı olmaktan çıkar (doygunluk noktası)."},{"t":"İşe yaramaz çünkü","a":"Işık/sıcaklık sınırlar","d":"Bu bölgede ışık veya sıcaklık sınırlayıcı olduğundan CO₂ artırmak hızı değiştirmez."}],"ans":"Yatay bölgede CO₂ doygunluğa ulaşmıştır; ışık veya sıcaklık sınırlayıcı olduğundan CO₂ artırmak hızı artırmaz."},{"q":"C3 bir bitkide yüksek sıcaklık ve yüksek ışıkta fotosolunumun artması fotosentez verimini neden düşürür?","steps":[{"t":"Yüksek sıcaklıkta","a":"O₂ tutulumu artar","d":"Yüksek sıcaklıkta RuBisCO enzimi CO₂ yerine <b>O₂</b> bağlama eğilimini artırır."},{"t":"Fotosolunum","a":"Karbon kaybı","d":"Bu durumda fotosolunum artar; tutulan karbonun bir kısmı CO₂ olarak geri salınır."},{"t":"Sonuç","a":"Net verim düşer","d":"Net karbon tutulumu azaldığı için fotosentez verimi düşer."}],"ans":"Yüksek sıcaklık ve ışıkta RuBisCO'nun O₂'yi bağlamasıyla fotosolunum artar, karbon kaybı olur ve net fotosentez verimi düşer."},{"q":"Bir akvaryum bitkisiyle ışık kaynağı arasındaki uzaklığı yarıya indirdiğimizde çıkan oksijen kabarcığı sayısı neden belirgin biçimde artar?","steps":[{"t":"Uzaklık-ışık ilişkisi","a":"Ters kare","d":"Işık şiddeti uzaklığın <b>karesiyle ters orantılıdır</b>; uzaklık yarıya inince şiddet yaklaşık dört katına çıkar."},{"t":"Işık-hız","a":"Hız artar","d":"Işık sınırlayıcıyken şiddet artışı fotosentez hızını artırır."},{"t":"Sonuç","a":"Kabarcık artar","d":"Hız arttığı için birim zamanda üretilen oksijen ve kabarcık sayısı artar."}],"ans":"Uzaklık yarıya inince ışık şiddeti yaklaşık dört kat artar; ışık sınırlayıcıyken hız ve oksijen kabarcığı sayısı belirgin artar."},{"q":"Telafi (kompanzasyon) noktası nedir ve bitkinin net madde kazancıyla ilişkisi nedir?","steps":[{"t":"Tanım","a":"Eşitlik ışığı","d":"Fotosentez hızının <b>solunum</b> hızına eşit olduğu ışık şiddeti telafi noktasıdır."},{"t":"Bu noktada","a":"Net kazanç sıfır","d":"Üretilen ve tüketilen organik madde eşit olduğundan net madde kazancı sıfırdır."},{"t":"Üzerinde","a":"Net kazanç pozitif","d":"Bu noktanın üzerindeki ışıkta fotosentez solunumu aşar ve bitki net organik madde kazanır."}],"ans":"Telafi noktası, fotosentez hızının solunuma eşit olduğu ışık şiddetidir; bu noktada net madde kazancı sıfır, üzerinde pozitiftir."},{"q":"İki faktörün (ışık ve CO₂) birlikte artırılmasının, yalnız birini artırmaya göre fotosentezi daha çok hızlandırabilmesini sınırlayıcı faktör ilkesiyle açıklayınız.","steps":[{"t":"Tek faktör artışı","a":"Diğeri sınırlar","d":"Yalnız ışık artırılırsa, bir süre sonra <b>CO₂</b> sınırlayıcı olur ve hız sabitlenir."},{"t":"İki faktör birlikte","a":"Sınırlama gevşer","d":"Işık ve CO₂ birlikte artırılınca her ikisi de sınırlayıcı olmaktan çıkar."},{"t":"Sonuç","a":"Daha yüksek hız","d":"Sınırlayıcı faktör ilkesine göre tek tek artıştan daha yüksek bir fotosentez hızına ulaşılır (sıcaklık optimumdayken)."}],"ans":"Tek faktör artışında diğeri sınırlayıcı olur; ışık ve CO₂ birlikte artırılınca her iki sınırlama da gevşer ve daha yüksek hıza ulaşılır."}]}},"fotosistemI":{"ilkokul":{"kolay":[{"q":"Bitkilerin yapraklarındaki yeşil parçalar güneş ışığını yakalar. Bu küçük ışık tuzaklarına ne yardımcı olur?","steps":[{"t":"Yaprakta ne var?","a":"Yeşil renk maddesi","d":"Yaprakların yeşil olmasının sebebi içindeki <b>klorofil</b> adlı boyadır."},{"t":"Ne işe yarar?","a":"Işığı yakalar","d":"Klorofil tıpkı bir ağ gibi güneş ışığını yakalar."}],"ans":"Yeşil klorofil güneş ışığını yakalamaya yardım eder."},{"q":"Bitki, güneş ışığını yakalamak için özel ışık merkezleri kullanır. Bu merkezler nerede çalışır?","steps":[{"t":"Nerede?","a":"Yaprakta","d":"Bitkinin ışık merkezleri yaprakların içinde bulunur."},{"t":"Ne yaparlar?","a":"Işık toplar","d":"Bu merkezler güneşten gelen ışığı toplayıp besin yapmaya yardım eder."}],"ans":"Işık merkezleri yaprağın içinde çalışır."},{"q":"Bir bitki karanlık bir odaya konulursa ışık merkezleri çalışabilir mi?","steps":[{"t":"Işık var mı?","a":"Yok","d":"Karanlıkta güneş ışığı yoktur."},{"t":"Sonuç ne olur?","a":"Çalışmaz","d":"Işık olmadığı için bitkinin ışık merkezleri besin yapamaz."}],"ans":"Karanlıkta ışık olmadığı için merkezler çalışamaz."},{"q":"Bitkiler güneş ışığını alıp neye dönüştürür?","steps":[{"t":"Ne alır?","a":"Güneş ışığı","d":"Bitki yapraklarıyla güneş ışığını alır."},{"t":"Neye çevirir?","a":"Besine","d":"Bitki bu ışığı kullanarak kendine besin (şeker) yapar."}],"ans":"Bitkiler güneş ışığını besine dönüştürür."},{"q":"İki arkadaş gibi birlikte çalışan ışık merkezleri vardır. Birlikte çalışmak bitkiye ne sağlar?","steps":[{"t":"Kaç merkez?","a":"İki","d":"Yaprakta birbirine yardım eden iki ışık merkezi vardır."},{"t":"Faydası ne?","a":"Daha çok besin","d":"Birlikte çalışınca bitki daha kolay besin yapar."}],"ans":"İki merkez birlikte çalışınca bitki daha kolay besin yapar."}],"zor":[{"q":"Bir bitkinin ikinci ışık merkezi güneşten ışık alınca içindeki küçük enerji parçaları daha güçlü hale gelir. Buna ne ad verebiliriz?","steps":[{"t":"Ne alıyor?","a":"Işık","d":"İkinci ışık merkezi güneşten gelen ışığı yakalar."},{"t":"Ne oluyor?","a":"Güçleniyor","d":"Işık alınca içindeki minik enerji taneleri canlanıp güçlenir."}],"ans":"Işık alan enerji taneleri güçlenir, buna canlanma diyebiliriz."},{"q":"Bitkide ışık merkezleri bir sıra halinde elektrik gibi enerji aktarır. Bu aktarma neye benzer?","steps":[{"t":"Nasıl ilerler?","a":"Sırayla","d":"Enerji bir merkezden diğerine sırayla geçer."},{"t":"Neye benzer?","a":"El ele zincire","d":"Tıpkı çocukların el ele tutuşup bir şeyi sırayla iletmesi gibidir."}],"ans":"Enerji, el ele tutuşan bir zincir gibi sırayla aktarılır."},{"q":"Bitki besin yaparken hem güneş ışığına hem de suya ihtiyaç duyar. Su olmazsa ne olur?","steps":[{"t":"Su ne işe yarar?","a":"Yardımcı olur","d":"Bitki besin yaparken suyu da kullanır."},{"t":"Su yoksa?","a":"Yapamaz","d":"Su olmazsa bitki sağlıklı besin yapamaz ve solar."}],"ans":"Su olmazsa bitki düzgün besin yapamaz."},{"q":"Bitkinin yakaladığı güneş enerjisi sonunda hangi işe yarar?","steps":[{"t":"Enerji nereye gider?","a":"Besin yapımına","d":"Yakalanan enerji bitkinin besin yapmasında kullanılır."},{"t":"Besin ne sağlar?","a":"Büyüme","d":"Bu besin sayesinde bitki büyür ve yaşar."}],"ans":"Yakalanan güneş enerjisi besin yapımında, bitki büyür."},{"q":"İki ışık merkezinden biri suya, diğeri besin yapımına yakın çalışır. Bu iş bölümü neden iyidir?","steps":[{"t":"Görevler aynı mı?","a":"Farklı","d":"Her merkezin ayrı bir görevi vardır."},{"t":"Neden iyi?","a":"İş kolaylaşır","d":"Herkes kendi işini yapınca bitki daha kolay ve hızlı besin yapar."}],"ans":"İş bölümü sayesinde bitki besini daha kolay yapar."}]},"ortaokul":{"kolay":[{"q":"Fotosentezde ışığı yakalayan iki sistemden biri Fotosistem I'dir. Fotosistem I hangi organelde bulunur?","steps":[{"t":"Fotosentez nerede?","a":"Kloroplast","d":"Fotosentez bitki hücresindeki <b>kloroplast</b> adlı organelde olur."},{"t":"Sistem nerede?","a":"Tilakoit zarda","d":"Fotosistem I, kloroplastın içindeki tilakoit zara yerleşmiştir."}],"ans":"Fotosistem I kloroplastın tilakoit zarında bulunur."},{"q":"Fotosistem I'in tepkime merkezindeki klorofil molekülüne özel bir ad verilir. Bu ad nedir?","steps":[{"t":"Hangi sistem?","a":"Fotosistem I","d":"Fotosistem I'in merkezinde özel bir klorofil vardır."},{"t":"Adı ne?","a":"P700","d":"Bu klorofile <b>P700</b> denir."}],"ans":"Fotosistem I'in tepkime merkezindeki klorofile P700 denir."},{"q":"Fotosistem I ışık enerjisini ne için kullanır?","steps":[{"t":"Ne yakalar?","a":"Işık","d":"Fotosistem I güneş ışığını yakalar."},{"t":"Ne için?","a":"Elektron uyarmak","d":"Yakaladığı ışıkla elektronları uyarıp enerjilendirir."}],"ans":"Fotosistem I ışığı, elektronları uyarmak için kullanır."},{"q":"Fotosentezde iki fotosistem birlikte çalışır. Fotosistem I'in yanında çalışan diğer sistem hangisidir?","steps":[{"t":"Kaç sistem var?","a":"İki","d":"Fotosentezin ışık tepkimelerinde iki fotosistem görev alır."},{"t":"Diğeri?","a":"Fotosistem II","d":"Fotosistem I ile birlikte <b>Fotosistem II</b> de çalışır."}],"ans":"Fotosistem I ile birlikte Fotosistem II çalışır."},{"q":"Fotosistem I'in görevi bitki için neden önemlidir?","steps":[{"t":"Ne üretir?","a":"Enerji taşıyıcı","d":"Fotosistem I, besin yapımı için gerekli enerji taşıyıcı üretmeye yardım eder."},{"t":"Sonuç?","a":"Şeker yapımı","d":"Bu taşıyıcılar sayesinde bitki şeker (besin) üretebilir."}],"ans":"Fotosistem I, besin yapımı için gerekli taşıyıcıları sağlar."}],"zor":[{"q":"Fotosistem I'in P700 klorofili ışık enerjisini aldığında ne olur?","steps":[{"t":"Ne alır?","a":"Işık enerjisi","d":"P700 klorofili gelen ışık enerjisini soğurur."},{"t":"Sonuç ne?","a":"Elektron uyarılır","d":"Soğurulan enerjiyle P700'deki elektron yüksek enerji düzeyine çıkar (uyarılır)."}],"ans":"P700 ışığı alınca elektronu uyarılarak enerjilenir."},{"q":"Fotosistem I'den çıkan enerjili elektron sonunda hangi molekülün üretiminde kullanılır?","steps":[{"t":"Elektron nereye?","a":"Taşıma zinciri","d":"Uyarılan elektron bir taşıyıcı zincirden geçer."},{"t":"Ürün ne?","a":"NADPH","d":"Sonunda bu elektronlar <b>NADPH</b> molekülünün oluşmasını sağlar."}],"ans":"Fotosistem I'in elektronları NADPH üretiminde kullanılır."},{"q":"Fotosistem II'den ayrılan elektron, Fotosistem I'e nasıl ulaşır?","steps":[{"t":"Aradaki yol?","a":"Taşıma zinciri","d":"İki fotosistem arasında bir elektron taşıma zinciri vardır."},{"t":"Sonuç?","a":"PSI'e gelir","d":"Elektron bu zincirden geçerek Fotosistem I'e ulaşır ve eksilen elektronu tamamlar."}],"ans":"Elektron, taşıma zinciri üzerinden Fotosistem I'e ulaşır."},{"q":"Fotosistem I bazen elektronu NADPH yapmak yerine tekrar kendi zincirine gönderir. Bu duruma ne ad verilir?","steps":[{"t":"Elektron nereye gider?","a":"Geri döner","d":"Elektron NADPH'ye gitmek yerine başladığı yere geri döner."},{"t":"Adı?","a":"Döngüsel akış","d":"Bu olaya <b>döngüsel elektron akışı</b> denir."}],"ans":"Buna döngüsel elektron akışı denir."},{"q":"Fotosistem I ve Fotosistem II'nin birlikte çalışması bitki için neden gereklidir?","steps":[{"t":"PSII ne sağlar?","a":"Elektron kaynağı","d":"Fotosistem II suyu parçalayarak elektron sağlar."},{"t":"PSI ne yapar?","a":"NADPH üretir","d":"Fotosistem I bu elektronları kullanarak NADPH üretir; ikisi birlikte ışık tepkimelerini tamamlar."}],"ans":"İkisi birlikte çalışarak elektron sağlar ve NADPH üretir."}]},"lise":{"kolay":[{"q":"Fotosistem I'in tepkime merkezindeki klorofile P700 adı verilir. Bu isimdeki 700 sayısı neyi belirtir?","steps":[{"t":"P700 nedir?","a":"Tepkime merkezi klorofili","d":"P700, Fotosistem I'in tepkime merkezindeki özelleşmiş klorofil a çiftidir."},{"t":"700 ne anlatır?","a":"Dalga boyu","d":"700 sayısı, bu klorofilin en güçlü soğurum yaptığı ışığın dalga boyunu (700 nm) gösterir."}],"ans":"700, P700'ün en iyi soğurduğu ışığın dalga boyunu (700 nm) belirtir."},{"q":"Fotosistem I tilakoit zarda yer alır. PSI'in genel görevi nedir?","steps":[{"t":"Ne soğurur?","a":"Işık enerjisi","d":"PSI'deki anten pigmentleri ışığı soğurup enerjiyi P700'e aktarır."},{"t":"Ne üretir?","a":"NADPH'ye katkı","d":"PSI, uyarılmış elektronları NADP⁺'ye aktararak NADPH üretimini sağlar."}],"ans":"PSI ışığı soğurur ve elektronlarıyla NADPH üretimine katkı sağlar."},{"q":"Fotosistem I'in P700 klorofili ışık soğurduğunda elektronuna ne olur?","steps":[{"t":"Enerji girişi","a":"Soğurma","d":"P700, soğurulan ışık enerjisini elektronuna aktarır."},{"t":"Elektronun durumu","a":"Uyarılma","d":"Elektron yüksek enerjili (uyarılmış) hale gelir ve birincil alıcıya verilir."}],"ans":"P700'ün elektronu uyarılarak yüksek enerji düzeyine çıkar."},{"q":"PSI'den çıkan yüksek enerjili elektronu ilk alan zincir proteinlerinden biri ferredoksindir. Ferredoksinin görevi nedir?","steps":[{"t":"Ferredoksin nedir?","a":"Elektron taşıyıcı","d":"Ferredoksin, PSI'den gelen elektronu alan demir içeren bir proteindir."},{"t":"Nereye aktarır?","a":"NADP⁺ redüktaza","d":"Ferredoksin elektronu NADP⁺ redüktaz enzimine aktarır."}],"ans":"Ferredoksin, PSI'in elektronunu alıp NADP⁺ redüktaza taşır."},{"q":"NADP⁺ redüktaz enzimi fotosentezin ışık tepkimelerinde hangi tepkimeyi gerçekleştirir?","steps":[{"t":"Substrat ne?","a":"NADP⁺","d":"Enzim, elektron alıcısı olarak NADP⁺ molekülünü kullanır."},{"t":"Ürün ne?","a":"NADPH","d":"NADP⁺'yi elektron ve H⁺ ile indirgeyerek NADPH oluşturur."}],"ans":"NADP⁺ redüktaz, NADP⁺'yi indirgeyerek NADPH üretir."},{"q":"Fotosistem I, elektron taşıma zincirinde Fotosistem II'ye göre nerede yer alır?","steps":[{"t":"Sıralama","a":"PSII önce","d":"Doğrusal akışta önce PSII, sonra elektron taşıma zinciri gelir."},{"t":"PSI'in yeri","a":"Sonra","d":"PSI, zincirin sonunda yer alır ve NADP⁺'ye elektron verir."}],"ans":"PSI, doğrusal elektron akışında PSII'den sonra, zincirin sonunda yer alır."},{"q":"Doğrusal (lineer) elektron akışında Fotosistem I'in elektron açığı nasıl kapatılır?","steps":[{"t":"Açık nasıl oluşur?","a":"Elektron verilir","d":"P700 uyarılan elektronunu ferredoksine verince elektronca eksilir."},{"t":"Kaynak ne?","a":"PSII","d":"Bu açık, PSII'den taşıma zinciri yoluyla gelen elektronla kapatılır."}],"ans":"PSI'in elektron açığı, PSII'den gelen elektronla kapatılır."},{"q":"Fotosistem I ile Fotosistem II arasındaki başlıca ürün farkı nedir?","steps":[{"t":"PSII ürünü","a":"O₂ ve H⁺","d":"PSII suyu parçalar (fotoliz), oksijen ve protonlar açığa çıkarır."},{"t":"PSI ürünü","a":"NADPH","d":"PSI ise zincirin sonunda NADPH üretimini sağlar."}],"ans":"PSII oksijen açığa çıkarır, PSI ise NADPH üretimine yol açar."},{"q":"NADPH molekülü fotosentezde üretildikten sonra nerede kullanılır?","steps":[{"t":"Nerede üretilir?","a":"Işık tepkimeleri","d":"NADPH, tilakoit zardaki ışık tepkimelerinde PSI sayesinde üretilir."},{"t":"Nerede kullanılır?","a":"Calvin döngüsü","d":"NADPH, stromadaki Calvin döngüsünde CO₂'nin şekere indirgenmesinde kullanılır."}],"ans":"NADPH, Calvin döngüsünde CO₂'nin şekere indirgenmesinde kullanılır."},{"q":"Ferredoksin proteininin yapısında hangi element kritik öneme sahiptir?","steps":[{"t":"Ferredoksin türü","a":"Demir-kükürt proteini","d":"Ferredoksin, demir-kükürt (Fe-S) kümeleri içeren bir proteindir."},{"t":"Hangi element?","a":"Demir","d":"Demir atomları elektronu alıp verme yeteneğiyle elektron taşımayı sağlar."}],"ans":"Ferredoksinin yapısında demir (Fe) elementi kritik öneme sahiptir."},{"q":"Döngüsel elektron akışında elektron hangi yolu izler?","steps":[{"t":"Başlangıç","a":"PSI","d":"Döngüsel akış yalnızca Fotosistem I ile başlar."},{"t":"Akışın sonu","a":"PSI'e döner","d":"Elektron ferredoksinden sitokrom kompleksine, oradan tekrar PSI'e döner."}],"ans":"Döngüsel akışta elektron PSI'den çıkıp tekrar PSI'e geri döner."},{"q":"Döngüsel elektron akışı hücreye hangi ürünü kazandırır?","steps":[{"t":"NADPH üretir mi?","a":"Hayır","d":"Döngüsel akışta elektron NADP⁺'ye gitmez, NADPH üretilmez."},{"t":"Ne üretilir?","a":"ATP","d":"Proton gradiyenti oluşturarak yalnızca ATP üretimine katkı sağlar."}],"ans":"Döngüsel elektron akışı yalnızca ATP üretimini sağlar."},{"q":"PSI'in anten kompleksinin temel işlevi nedir?","steps":[{"t":"Anten nedir?","a":"Pigment topluluğu","d":"Anten kompleksi çok sayıda klorofil ve karotenoid pigmentten oluşur."},{"t":"Görevi","a":"Enerji toplama","d":"Soğurduğu ışık enerjisini tepkime merkezi P700'e aktarır."}],"ans":"Anten kompleksi ışık enerjisini toplayıp P700'e aktarır."},{"q":"Fotosentezin ışık tepkimelerinde su molekülünü parçalayan fotosistem hangisidir?","steps":[{"t":"PSI mi?","a":"Hayır","d":"PSI suyu parçalamaz; o elektronu zincirin sonunda alır."},{"t":"Hangisi?","a":"PSII","d":"Suyu parçalayıp (fotoliz) elektron, H⁺ ve O₂ üreten PSII'dir."}],"ans":"Suyu parçalayan fotosistem PSII'dir, PSI değildir."},{"q":"P700 ismindeki P harfi neyi temsil eder?","steps":[{"t":"P ne demek?","a":"Pigment","d":"P harfi İngilizce 'pigment' kelimesinin baş harfidir."},{"t":"Birlikte anlamı","a":"700 nm pigment","d":"P700, 700 nm dalga boyunda soğurma yapan tepkime merkezi pigmenti demektir."}],"ans":"P harfi 'pigment' anlamına gelir; P700, 700 nm'de soğuran pigmenttir."}],"zor":[{"q":"Doğrusal elektron akışında elektron suyun parçalanmasından NADPH'ye kadar ilerler. Fotosistem I'in bu yoldaki rolünü açıklayın.","steps":[{"t":"PSI'e giriş","a":"İndirgenmiş plastosiyanin","d":"PSII'den gelen elektron, sitokrom b₆f ve plastosiyanin üzerinden P700'e ulaşıp onun açığını kapatır."},{"t":"İkinci uyarılma","a":"P700 elektron verir","d":"P700 ışık soğurarak elektronunu yeniden uyarır ve ferredoksine aktarır."},{"t":"Son ürün","a":"NADPH","d":"Ferredoksin elektronu NADP⁺ redüktaza verir, NADP⁺ + H⁺ ile NADPH oluşur."}],"ans":"PSI, elektronu ikinci kez uyararak ferredoksin yoluyla NADP⁺'ye aktarır ve NADPH oluşumunu sağlar."},{"q":"Fotosistem I'de elektronun neden ikinci kez uyarılmaya ihtiyaç duyduğunu enerji açısından açıklayın.","steps":[{"t":"İlk enerji kaybı","a":"Zincirde düşer","d":"PSII'den gelen elektron, sitokrom b₆f zincirinde enerji kaybeder ve düşük enerjili plastosiyanine ulaşır."},{"t":"İkinci uyarılma","a":"P700 ışık soğurur","d":"NADP⁺'yi indirgeyebilecek enerji için P700, ışık enerjisiyle elektronu yeniden yüksek enerji düzeyine çıkarır."},{"t":"Sonuç","a":"Yeterli potansiyel","d":"Böylece elektronun indirgenme potansiyeli NADP⁺'yi indirgeyecek kadar negatif (güçlü) olur."}],"ans":"Zincirde enerji kaybeden elektron, NADP⁺'yi indirgeyecek güce ulaşmak için P700'de ikinci kez uyarılır."},{"q":"Ferredoksin-NADP⁺ redüktaz (FNR) enziminin katalizlediği tepkimeyi madde ve elektron dengesiyle açıklayın.","steps":[{"t":"Girenler","a":"2 indirgenmiş ferredoksin","d":"FNR, ferredoksinden gelen iki elektronu toplar (her ferredoksin bir elektron taşır)."},{"t":"Elektron + proton","a":"NADP⁺ + H⁺","d":"İki elektron ve bir H⁺, NADP⁺ molekülüne aktarılır."},{"t":"Ürün","a":"NADPH","d":"Tepkime NADP⁺ + 2e⁻ + H⁺ → NADPH şeklinde tamamlanır."}],"ans":"FNR, ferredoksinden aldığı 2 elektronu bir H⁺ ile NADP⁺'ye aktararak NADPH oluşturur."},{"q":"Döngüsel ve doğrusal elektron akışlarını ürün ve işlev açısından karşılaştırın.","steps":[{"t":"Doğrusal akış","a":"ATP + NADPH + O₂","d":"PSII ve PSI birlikte çalışır; su parçalanır, ATP ve NADPH üretilir, O₂ açığa çıkar."},{"t":"Döngüsel akış","a":"Sadece ATP","d":"Yalnızca PSI çalışır; elektron geri döner, NADPH ve O₂ üretilmez, sadece ATP oluşur."},{"t":"İşlev farkı","a":"ATP/NADPH dengesi","d":"Döngüsel akış, Calvin döngüsünün ihtiyaç duyduğu ek ATP'yi karşılamak için devreye girer."}],"ans":"Doğrusal akış ATP, NADPH ve O₂ üretirken; döngüsel akış yalnızca PSI ile ek ATP üretir."},{"q":"Bir hücrede NADPH bol, ATP az olduğunda bitki neden döngüsel elektron akışını artırır?","steps":[{"t":"Sorun","a":"ATP/NADPH oranı bozuk","d":"Calvin döngüsü ATP ve NADPH'yi belirli oranda kullanır; ATP yetersizse döngü yavaşlar."},{"t":"Çözüm","a":"Döngüsel akış","d":"Döngüsel akış yalnızca PSI'i kullanarak NADPH üretmeden ek ATP sağlar."},{"t":"Sonuç","a":"Denge sağlanır","d":"Böylece ATP açığı kapanır ve ATP/NADPH oranı dengelenir."}],"ans":"Döngüsel akış NADPH üretmeden ek ATP sağlayarak ATP/NADPH dengesini düzeltir."},{"q":"Fotosistem I'in P700'ünden ferredoksine elektron geçiş sırasını ara taşıyıcılarla açıklayın.","steps":[{"t":"Uyarılma","a":"P700*","d":"P700 ışık soğurunca uyarılmış P700* haline gelir ve elektronunu verir."},{"t":"Birincil alıcılar","a":"A₀, A₁","d":"Elektron önce klorofil A₀'a, ardından filokinon A₁'e aktarılır."},{"t":"Fe-S ve ferredoksin","a":"Fₓ→ferredoksin","d":"Elektron demir-kükürt merkezlerinden (Fₓ, Fₐ, F_b) geçip ferredoksine ulaşır."}],"ans":"P700*'tan elektron A₀, A₁, Fe-S merkezleri üzerinden ferredoksine aktarılır."},{"q":"Plastosiyaninin Fotosistem I için önemini ve görevini açıklayın.","steps":[{"t":"Plastosiyanin nedir?","a":"Bakır içeren protein","d":"Plastosiyanin, tilakoit lümeninde hareket eden bakır (Cu) içeren küçük bir proteindir."},{"t":"Görevi","a":"Elektron taşır","d":"Sitokrom b₆f kompleksinden aldığı elektronu P700'e taşır."},{"t":"Önemi","a":"PSI açığını kapatır","d":"Elektronunu vermiş olan P700⁺'yi indirgeyerek PSI'in tekrar çalışmasını sağlar."}],"ans":"Plastosiyanin, sitokrom b₆f'ten aldığı elektronu P700'e taşıyıp PSI'in açığını kapatır."},{"q":"Fotosistem I'in soğurma zirvesi 700 nm iken Fotosistem II'ninki 680 nm'dir. Bu farkın işbirliğindeki anlamını açıklayın.","steps":[{"t":"Enerji ilişkisi","a":"Kısa dalga daha enerjili","d":"680 nm ışık, 700 nm'den daha yüksek enerjilidir; PSII daha enerjili foton kullanır."},{"t":"Z şeması","a":"Enerji basamakları","d":"İki fotosistem 'Z şeması'nda art arda çalışarak elektronu iki kez yukarı taşır."},{"t":"İşbirliği","a":"NADP⁺ indirgenir","d":"İki ayrı uyarılma sayesinde elektron, suyun düşük enerjisinden NADP⁺'yi indirgeyecek seviyeye çıkar."}],"ans":"İki farklı dalga boyu, Z şemasında art arda uyarılmayla elektronu suyun seviyesinden NADP⁺'yi indirgeyecek enerjiye taşır."},{"q":"Fotosistem I işlevini yitirirse fotosentezin ışık tepkimelerinde ne tür aksamalar olur?","steps":[{"t":"NADPH üretimi","a":"Durur","d":"PSI olmadan elektron NADP⁺'ye ulaşamaz, NADPH üretilemez."},{"t":"Calvin döngüsü","a":"Aksar","d":"NADPH eksikliğinde Calvin döngüsü CO₂'yi indirgeyemez, şeker üretilemez."},{"t":"Elektron zinciri","a":"Tıkanır","d":"PSII'den gelen elektronlar son alıcıyı bulamaz, zincir tıkanır ve fotosentez durur."}],"ans":"PSI çalışmazsa NADPH üretilemez, Calvin döngüsü durur ve şeker üretimi gerçekleşmez."},{"q":"Doğrusal elektron akışında her bir NADPH üretimi için kaç foton ve hangi fotosistemlerin gerektiğini açıklayın.","steps":[{"t":"Elektron sayısı","a":"2 elektron","d":"Bir NADPH oluşması için NADP⁺'ye 2 elektron aktarılması gerekir."},{"t":"Foton ihtiyacı","a":"4 foton","d":"Her elektron PSII ve PSI'de birer kez uyarıldığından elektron başına 2 foton, toplam 4 foton gerekir."},{"t":"Fotosistemler","a":"PSII + PSI","d":"Bu fotonlar iki fotosistem tarafından soğurulur; ikisi de zorunludur."}],"ans":"Bir NADPH için 2 elektron, dolayısıyla PSII ve PSI'de toplam 4 foton soğurulması gerekir."},{"q":"Fotosistem I'in tepkime merkezi P700, neden 'tuzak (trap)' olarak nitelendirilir?","steps":[{"t":"Anten görevi","a":"Enerji aktarır","d":"Anten pigmentleri soğurdukları enerjiyi rezonansla P700'e doğru aktarır."},{"t":"P700'ün özelliği","a":"En düşük enerji düzeyi","d":"P700, kompleksteki en düşük uyarılma enerjisine sahip pigmenttir, enerji ona doğru akar."},{"t":"Tuzak işlevi","a":"Yük ayrımı","d":"Enerji P700'de 'tuzaklanıp' fotokimyasal yük ayrımına (elektron verme) dönüştürülür."}],"ans":"P700 en düşük enerji düzeyine sahip olup enerjiyi yakalar ve yük ayrımına dönüştürdüğü için tuzak olarak adlandırılır."},{"q":"Ferredoksin, NADPH üretiminin yanında başka hangi hücresel süreçlerde elektron sağlayabilir? İşlevini açıklayın.","steps":[{"t":"Çok yönlü taşıyıcı","a":"Dağıtım noktası","d":"İndirgenmiş ferredoksin, PSI'den aldığı elektronu birden çok yola dağıtabilir."},{"t":"Diğer kullanımlar","a":"Azot/kükürt indirgenmesi","d":"Nitrit ve sülfat indirgenmesi gibi tepkimelere de elektron sağlar."},{"t":"Döngüsel akış","a":"Sitokroma elektron","d":"Döngüsel akışta elektronu sitokrom b₆f'e vererek ATP üretimine katkıda bulunur."}],"ans":"Ferredoksin, NADPH dışında azot/kükürt indirgenmesi ve döngüsel akış gibi süreçlere de elektron sağlar."},{"q":"Fotosistem I'in döngüsel akışında sitokrom b₆f kompleksinin rolünü ATP üretimi açısından açıklayın.","steps":[{"t":"Elektronun gelişi","a":"Ferredoksinden","d":"Döngüsel akışta indirgenmiş ferredoksin elektronu tekrar sitokrom b₆f'e verir."},{"t":"Proton pompalama","a":"Lümene H⁺","d":"Sitokrom b₆f, elektron geçişiyle stromadan lümene proton pompalar."},{"t":"ATP sentezi","a":"ATP sentaz","d":"Oluşan proton gradiyenti ATP sentaz enzimini çalıştırarak ATP üretir."}],"ans":"Sitokrom b₆f döngüsel akışta proton pompalayarak gradiyent oluşturur ve ATP sentazla ATP üretimini sağlar."},{"q":"Bir bitki yalnızca PSI'i uyaran uzun dalga boylu ışıkla (700 nm üzeri) aydınlatılırsa fotosentez verimi neden düşer? Bu olaya ne ad verilir?","steps":[{"t":"Tek sistem uyarımı","a":"Sadece PSI çalışır","d":"700 nm üstü ışık yalnızca PSI'i uyarır, PSII yeterince uyarılamaz."},{"t":"Elektron eksikliği","a":"PSII besleyemez","d":"PSII çalışmadığından PSI'e yeterli elektron gelmez, doğrusal akış aksar."},{"t":"Olay adı","a":"Kırmızı düşüş","d":"Verimin düşmesine 'kırmızı düşüş (red drop)' denir; iki sistemin birlikte uyarılması gerekir."}],"ans":"Yalnızca PSI uyarıldığında PSII elektron sağlayamadığı için verim düşer; bu olaya kırmızı düşüş denir."},{"q":"Emerson güçlendirme etkisi (enhancement effect) Fotosistem I ve II işbirliğini nasıl kanıtlar? Açıklayın.","steps":[{"t":"Gözlem","a":"İki ışık birlikte daha verimli","d":"680 nm ve 700 nm ışık ayrı ayrı verilince verim düşükken, birlikte verilince toplamdan fazla verim alınır."},{"t":"Yorum","a":"İki ayrı sistem","d":"Bu, iki ayrı fotosistemin (PSII 680 nm, PSI 700 nm) var olduğunu gösterir."},{"t":"İşbirliği","a":"Seri çalışma","d":"İki sistem birlikte uyarıldığında elektron akışı kesintisiz olur ve verim güçlenir."}],"ans":"Emerson etkisi, iki dalga boyunun birlikte verildiğinde verimin artmasıyla PSI ve PSII'nin seri işbirliğini kanıtlar."}]}},"fotosistemII":{"ilkokul":{"kolay":[{"q":"Yapraktaki yeşil renk, güneş ışığını yakalayarak suyu parçalamaya yardım eder. Bu işte hangi enerji kullanılır?","steps":[{"t":"Kaynağı düşün","a":"Güneşten gelir","d":"Bitkiler işlerini yaparken bir güce ihtiyaç duyar. Bu güç gökyüzünden, güneşten gelen ışıktır."},{"t":"Adını söyle","a":"Işık enerjisi","d":"Yaprağın suyu parçalaması için kullandığı güç <b>ışık enerjisidir</b>. Işık olmadan bu olay gerçekleşmez."}],"ans":"Işık (güneş) enerjisi"},{"q":"Yaprakta ışık enerjisiyle su parçalanınca havaya hangi gaz verilir?","steps":[{"t":"Olayı düşün","a":"Su parçalanır","d":"Yaprak güneş ışığını alınca içindeki suyu küçük parçalara ayırır."},{"t":"Çıkan gazı bul","a":"Oksijen","d":"Su parçalanınca havaya <b>oksijen</b> gazı çıkar. Bu gaz bizim soluduğumuz temiz havadır."}],"ans":"Oksijen"},{"q":"Bitkilerin ışık enerjisiyle suyu parçalama olayı bitkinin hangi kısmında olur?","steps":[{"t":"Yeşil yeri düşün","a":"Yeşil yapraklar","d":"Bitkilerin yeşil renkli bölümü güneş ışığını en iyi yakalayan kısımdır."},{"t":"Yeri söyle","a":"Yaprakta","d":"Su parçalama ve oksijen çıkışı çoğunlukla <b>yaprakta</b> gerçekleşir. Yaprak bitkinin güneş alan kısmıdır."}],"ans":"Yaprakta"},{"q":"Yaprağın güneş ışığını yakalamasını sağlayan yeşil renkli maddenin adı nedir?","steps":[{"t":"Rengi düşün","a":"Yeşil renk","d":"Yaprakların yeşil görünmesinin sebebi içlerinde özel bir madde olmasıdır."},{"t":"Adını söyle","a":"Klorofil","d":"Bu yeşil maddeye <b>klorofil</b> denir. Klorofil güneş ışığını yakalar ve suyun parçalanmasına yardım eder."}],"ans":"Klorofil"},{"q":"Suyun parçalanıp oksijen çıkması için bitkiye karanlık mı yoksa ışık mı gerekir?","steps":[{"t":"İhtiyacı düşün","a":"Güneş gerekir","d":"Bitki suyu parçalamak için güneşten gelen güce ihtiyaç duyar."},{"t":"Cevabı ver","a":"Işık gerekir","d":"Suyun parçalanıp <b>oksijen</b> çıkması için <b>ışık</b> gereklidir. Karanlıkta bu olay olmaz."}],"ans":"Işık (aydınlık) gerekir"}],"zor":[{"q":"Bir bitkiyi tamamen karanlık bir dolaba koyarsak, suyu parçalayıp oksijen verebilir mi? Neden?","steps":[{"t":"İhtiyacı hatırla","a":"Işık gerekli","d":"Bitkinin suyu parçalaması için güneş ışığına ihtiyacı vardır. Işık bu işin gücünü sağlar."},{"t":"Karanlığı düşün","a":"Işık yok","d":"Karanlık dolapta hiç ışık yoktur. Bitki yakalayacak ışık bulamaz."},{"t":"Sonuca var","a":"Veremez","d":"Işık olmadığı için bitki suyu parçalayamaz ve <b>oksijen veremez</b>. Bu yüzden bitkilere ışık gereklidir."}],"ans":"Veremez, çünkü ışık yoktur"},{"q":"Su altındaki yeşil bir bitkinin yapraklarından küçük kabarcıklar çıkıyor. Bu kabarcıkların içindeki gaz nedir ve nereden gelir?","steps":[{"t":"Olayı düşün","a":"Su parçalanır","d":"Yeşil bitki güneş ışığını alınca içindeki suyu parçalar."},{"t":"Gazı bul","a":"Oksijen","d":"Su parçalanınca <b>oksijen</b> gazı oluşur. Bu gaz suda kabarcıklar halinde yukarı çıkar."},{"t":"Kaynağı söyle","a":"Sudan gelir","d":"Kabarcıktaki oksijen, parçalanan <b>sudan</b> gelir. Yani su, oksijenin kaynağıdır."}],"ans":"Oksijendir; parçalanan sudan gelir"},{"q":"Yaprakta su parçalanırken hem oksijen hem de çok küçük parçacıklar açığa çıkar. Bitki bu küçük parçacıkları ne için kullanır?","steps":[{"t":"Parçalanmayı düşün","a":"Su bölünür","d":"Işık yardımıyla su küçük parçalara ayrılır."},{"t":"Parçaları gör","a":"Oksijen ve küçük yükler","d":"Bu parçalanmadan <b>oksijen</b> ve çok küçük yüklü parçacıklar çıkar."},{"t":"Kullanımı söyle","a":"Besin yapımında","d":"Bitki bu küçük parçacıkları kendi <b>besinini (şekerini)</b> yapmak için kullanır."}],"ans":"Kendi besinini (şekerini) yapmak için"},{"q":"İki saksı bitkiden biri güneşli pencerede, biri karanlık odada duruyor. Hangisi daha çok oksijen üretir ve neden?","steps":[{"t":"Şartı düşün","a":"Işık gerekli","d":"Oksijen üretmek için suyun parçalanması, bunun için de ışık gerekir."},{"t":"İki bitkiyi karşılaştır","a":"Biri ışıkta","d":"Penceredeki bitki bol ışık alır, karanlıktaki bitki hiç ışık almaz."},{"t":"Sonucu bul","a":"Güneşteki","d":"<b>Güneşli</b> penceredeki bitki daha çok oksijen üretir, çünkü suyu parçalayacak ışığı vardır."}],"ans":"Güneşli penceredeki bitki üretir"},{"q":"Bir öğrenci yaprağın oksijeni nereden aldığını merak ediyor. Bitki bu oksijeni dışarıdan mı alır yoksa kendi mi üretir?","steps":[{"t":"Olayı hatırla","a":"Su parçalanır","d":"Bitki ışıkla suyu parçalar."},{"t":"Oksijenin kaynağı","a":"Sudan oluşur","d":"Parçalanan sudan <b>oksijen</b> oluşur, yani bitki onu kendi içinde yapar."},{"t":"Cevabı ver","a":"Kendi üretir","d":"Bitki oksijeni dışarıdan almaz, suyu parçalayarak <b>kendi üretir</b> ve havaya verir."}],"ans":"Kendi üretir (suyu parçalayarak)"}]},"ortaokul":{"kolay":[{"q":"Fotosentezde suyu parçalayan ve oksijeni açığa çıkaran olayın gerçekleştiği yapı hangi organelin içindedir?","steps":[{"t":"Organeli düşün","a":"Yeşil organel","d":"Fotosentez, bitki hücresindeki yeşil renkli organelde gerçekleşir."},{"t":"Adını söyle","a":"Kloroplast","d":"Suyun parçalanıp oksijenin çıktığı olaylar <b>kloroplast</b> içinde gerçekleşir. Yeşil rengi klorofilden gelir."}],"ans":"Kloroplast"},{"q":"Fotosentezde ışık enerjisiyle suyun parçalanması olayına ne ad verilir?","steps":[{"t":"Olayı düşün","a":"Su bölünür","d":"Işık enerjisi kullanılarak su molekülü daha küçük parçalara ayrılır."},{"t":"Adını söyle","a":"Suyun fotolizi","d":"Işıkla suyun parçalanmasına <b>suyun fotolizi (ışıkla parçalanma)</b> denir. Sonucunda oksijen açığa çıkar."}],"ans":"Suyun fotolizi"},{"q":"Suyun fotolizinde açığa çıkan ve bitkinin havaya verdiği gaz nedir?","steps":[{"t":"Olayı hatırla","a":"Su parçalanır","d":"Işıkla su parçalanınca farklı parçalar oluşur."},{"t":"Gazı bul","a":"Oksijen","d":"Suyun fotolizinde havaya verilen gaz <b>oksijen (O₂)</b> gazıdır. Bu gaz canlıların solunumunda kullanılır."}],"ans":"Oksijen (O₂)"},{"q":"Fotosentezde açığa çıkan oksijen, sudan mı yoksa karbondioksitten mi gelir?","steps":[{"t":"Olayı düşün","a":"Su parçalanır","d":"Fotosentezde su, ışık yardımıyla parçalanır."},{"t":"Kaynağı söyle","a":"Sudan gelir","d":"Açığa çıkan oksijen <b>sudan (H₂O)</b> gelir, karbondioksitten değil. Su, oksijenin kaynağıdır."}],"ans":"Sudan (H₂O) gelir"},{"q":"Suyun fotolizi fotosentezin ışığa bağımlı olan kısmında mı yoksa karanlıkta mı gerçekleşir?","steps":[{"t":"İhtiyacı düşün","a":"Işık gerekir","d":"Suyun parçalanması için ışık enerjisi gereklidir."},{"t":"Evreyi söyle","a":"Işığa bağımlı evre","d":"Suyun fotolizi fotosentezin <b>ışığa bağımlı evresinde</b> gerçekleşir. Bu evre kloroplastın tilakoit kısmında olur."}],"ans":"Işığa bağımlı evrede"}],"zor":[{"q":"Suyun fotolizinde su parçalanırken oksijenin yanında hangi iki parça daha açığa çıkar?","steps":[{"t":"Su molekülünü düşün","a":"H ve O içerir","d":"Su molekülü hidrojen ve oksijen atomlarından oluşur. Parçalanınca bu parçalar ayrılır."},{"t":"Parçaları belirle","a":"Elektron ve proton","d":"Suyun fotolizinde oksijenin yanı sıra <b>elektronlar (e⁻)</b> ve <b>protonlar (H⁺)</b> açığa çıkar."},{"t":"Kullanımı söyle","a":"Bitki kullanır","d":"Bu elektron ve protonlar fotosentezin sonraki adımlarında enerji taşımak için kullanılır."}],"ans":"Elektronlar (e⁻) ve protonlar (H⁺)"},{"q":"Klorofil ışığı yakaladığında içindeki elektrona ne olur ve bu neden önemlidir?","steps":[{"t":"Işığın etkisi","a":"Enerji verir","d":"Klorofil molekülü ışık enerjisini soğurur (emer)."},{"t":"Elektrona ne olur","a":"Uyarılır, kopar","d":"Soğurulan enerjiyle klorofildeki <b>elektron uyarılır</b> ve yüksek enerjiyle yerinden fırlar."},{"t":"Önemini söyle","a":"Enerji taşır","d":"Kopan bu elektron enerji taşır ve bitkinin besin yapması için bu enerji aktarılır. Bu yüzden önemlidir."}],"ans":"Elektron uyarılıp kopar ve enerji taşır"},{"q":"Klorofil elektron kaybedince oluşan boşluğu doldurmak için bitki nereden elektron alır?","steps":[{"t":"Sorunu düşün","a":"Elektron eksildi","d":"Klorofil ışıkla elektron kaybedince eksik kalır, yenisine ihtiyaç duyar."},{"t":"Kaynağı bul","a":"Su parçalanır","d":"Eksik elektron, parçalanan <b>sudan</b> sağlanır. Suyun fotolizi elektron eksiğini kapatır."},{"t":"Sonucu söyle","a":"Su gerekli","d":"Bu yüzden fotosentez sürerken sürekli su gereklidir; su elektron kaynağıdır."}],"ans":"Parçalanan sudan alır"},{"q":"Bir bitkiye sürekli ışık veriliyor ama suyu kesiliyor. Bir süre sonra oksijen üretimi neden durur?","steps":[{"t":"Oksijenin kaynağı","a":"Su parçalanır","d":"Oksijen, suyun parçalanmasıyla oluşur."},{"t":"Su kesilince","a":"Parçalanacak su yok","d":"Su olmazsa parçalanacak madde kalmaz, fotoliz duraklar."},{"t":"Sonucu bul","a":"Oksijen durur","d":"Parçalanacak <b>su olmadığı</b> için oksijen üretimi durur. Işık tek başına yeterli değildir."}],"ans":"Parçalanacak su kalmadığı için durur"},{"q":"Suyun fotolizi sonucu ortamda biriken H⁺ (proton) iyonları bitki için neden faydalıdır?","steps":[{"t":"Protonu düşün","a":"H⁺ birikir","d":"Su parçalanınca tilakoit içinde bol miktarda <b>proton (H⁺)</b> birikir."},{"t":"Birikmenin etkisi","a":"Enerji deposu","d":"Bir tarafta proton birikmesi, su bendinde su birikmesi gibi bir enerji deposu oluşturur."},{"t":"Kullanımı söyle","a":"ATP yapımı","d":"Bu biriken protonlar geri akarken bitki <b>ATP</b> adlı enerji molekülünü üretir. Yani proton birikimi enerji sağlar."}],"ans":"Birikimleri ATP (enerji) üretiminde kullanılır"}]},"lise":{"kolay":[{"q":"Fotosistem II'nin reaksiyon merkezindeki özel klorofil çiftine, en iyi soğurduğu dalga boyu nedeniyle hangi ad verilir?","steps":[{"t":"Soğurma tepesini düşün","a":"680 nm","d":"Fotosistem II reaksiyon merkezindeki klorofil çifti ışığı en güçlü olarak 680 nm dalga boyunda soğurur."},{"t":"Adını ver","a":"P680","d":"Bu nedenle reaksiyon merkezine <b>P680</b> (pigment 680) denir. PSII'nin elektron veren özel klorofilidir."}],"ans":"P680"},{"q":"Fotosistem II'de suyun ışıkla parçalanarak elektron, proton ve oksijene ayrılması olayının adı nedir?","steps":[{"t":"Olayı tanımla","a":"Su bölünür","d":"PSII'de su molekülü ışık enerjisi kullanılarak yapı taşlarına ayrılır."},{"t":"Adını ver","a":"Fotoliz","d":"Bu olaya suyun <b>fotolizi</b> denir. 2H₂O → 4H⁺ + 4e⁻ + O₂ şeklinde gerçekleşir."}],"ans":"Suyun fotolizi"},{"q":"Fotosistem II'de suyu parçalayan ve manganez içeren enzim kompleksinin adı nedir?","steps":[{"t":"Görevi düşün","a":"Suyu parçalar","d":"PSII'nin lümen tarafında suyu parçalayıp elektron sağlayan özel bir protein kompleksi vardır."},{"t":"Adını ver","a":"OEC","d":"Bu yapıya <b>oksijen açığa çıkaran kompleks (OEC)</b> veya su parçalama kompleksi denir. Mn iyonları içerir."}],"ans":"Oksijen açığa çıkaran kompleks (OEC)"},{"q":"P680 ışık enerjisini soğurup uyarıldığında elektronunu hangi ilk elektron alıcısına aktarır?","steps":[{"t":"Uyarılmayı düşün","a":"Elektron kopar","d":"P680 ışık soğurunca P680* olur ve yüksek enerjili elektronunu hızla bir alıcıya verir."},{"t":"İlk alıcıyı söyle","a":"Feofitin","d":"P680'in elektronunu aktardığı ilk alıcı <b>feofitin (Phe)</b> molekülüdür. Buradan elektron taşıma zincirine geçer."}],"ans":"Feofitin (Phe)"},{"q":"PSII'de feofitinden sonra elektronu alan ve membranda hareket edebilen elektron taşıyıcısı nedir?","steps":[{"t":"Akışı izle","a":"Feofitinden sonra","d":"Elektron feofitinden sonra PSII'nin son sabit alıcıları olan QA ve QB üzerinden ilerler."},{"t":"Taşıyıcıyı söyle","a":"Plastokinon","d":"Elektron QB'de indirgenip <b>plastokinona (PQ)</b> aktarılır. PQ membran içinde hareket ederek elektronu sitokrom b6f'ye taşır."}],"ans":"Plastokinon (PQ)"},{"q":"Suyun fotolizinde 2 molekül su parçalandığında kaç molekül oksijen açığa çıkar?","steps":[{"t":"Tepkimeyi yaz","a":"2H₂O → O₂","d":"Fotoliz tepkimesi 2H₂O → 4H⁺ + 4e⁻ + O₂ şeklindedir."},{"t":"Oksijeni say","a":"1 molekül O₂","d":"2 molekül su parçalanınca <b>1 molekül O₂</b> oluşur. Ayrıca 4 elektron ve 4 proton açığa çıkar."}],"ans":"1 molekül oksijen (O₂)"},{"q":"PSII reaksiyon merkezi olan P680 elektron verdikten sonra hangi hâle dönüşür?","steps":[{"t":"Elektron kaybını düşün","a":"Eksik kalır","d":"P680 elektronunu feofitine verince pozitif yüklü hâle geçer."},{"t":"Hâlini söyle","a":"P680⁺","d":"Elektron veren P680, güçlü bir oksitleyici olan <b>P680⁺</b> hâline döner. Bu hâl sudan elektron çekecek kadar güçlüdür."}],"ans":"P680⁺ (yükseltgenmiş hâl)"},{"q":"Fotosentezde açığa çıkan moleküler oksijenin kaynağı su mu yoksa karbondioksit midir? Bu nasıl kanıtlanmıştır?","steps":[{"t":"Kaynağı belirt","a":"Su","d":"Açığa çıkan O₂'nin kaynağı sudur, CO₂ değildir."},{"t":"Kanıtı söyle","a":"İşaretli oksijen","d":"Suyun oksijeni ağır izotop (¹⁸O) ile işaretlendiğinde açığa çıkan O₂'nin de işaretli olması, oksijenin <b>sudan</b> geldiğini kanıtlamıştır."}],"ans":"Sudan gelir (¹⁸O izotop deneyiyle kanıtlandı)"},{"q":"PSII'nin tilakoit membran üzerinde, lümene (iç boşluğa) bakan kısmında bulunan kompleks hangisidir?","steps":[{"t":"Konumu düşün","a":"Lümen tarafı","d":"Su parçalanması tilakoidin iç boşluğunda (lümen) gerçekleşir."},{"t":"Kompleksi söyle","a":"OEC","d":"Lümene bakan kısımda <b>su parçalama kompleksi (OEC)</b> bulunur. Burada suyun protonları lümene salınır."}],"ans":"Su parçalama kompleksi (OEC)"},{"q":"Suyun fotolizi sonucu açığa çıkan protonlar (H⁺) tilakoidin hangi bölmesinde birikir?","steps":[{"t":"Fotoliz yerini düşün","a":"Lümene bakar","d":"Su, OEC tarafından tilakoid lümenine bakan yüzeyde parçalanır."},{"t":"Birikme yerini söyle","a":"Lümen","d":"Açığa çıkan H⁺ iyonları tilakoit <b>lümeninde (iç boşlukta)</b> birikir. Bu, proton derişim farkı oluşturur."}],"ans":"Tilakoit lümeninde (iç boşlukta)"},{"q":"PSII'de elektronu uyaran ışık enerjisini, klorofilden reaksiyon merkezine ileten pigment topluluğuna ne denir?","steps":[{"t":"Görevi düşün","a":"Işığı toplar","d":"Reaksiyon merkezinin çevresinde ışığı soğurup enerjiyi merkeze ileten çok sayıda pigment vardır."},{"t":"Adını ver","a":"Anten kompleksi","d":"Bu pigment topluluğuna <b>anten (ışık toplayıcı) kompleksi</b> denir. Topladığı enerjiyi P680'e aktarır."}],"ans":"Anten (ışık toplayıcı) kompleksi"},{"q":"Fotosistem II'nin elektron sağladığı temel kaynak nedir?","steps":[{"t":"Elektron eksiğini düşün","a":"P680⁺ oluşur","d":"P680 elektron verince P680⁺ olur ve elektron eksiğini kapatması gerekir."},{"t":"Kaynağı söyle","a":"Su","d":"PSII bu elektronları <b>suyun</b> parçalanmasından (fotolizden) sağlar. Su, fotosentezin nihai elektron vericisidir."}],"ans":"Su (suyun fotolizi)"},{"q":"PSII'den çıkan elektronlar plastokinon ve sitokrom b6f'den geçip sonunda hangi fotosisteme ulaşır?","steps":[{"t":"Akışı izle","a":"PSII'den çıkar","d":"Elektronlar PSII → PQ → sitokrom b6f → plastosiyanin sırasını izler."},{"t":"Varışı söyle","a":"PSI","d":"Elektronlar son olarak <b>Fotosistem I (PSI, P700)</b>'e ulaşır. Böylece elektron taşıma zinciri tamamlanır."}],"ans":"Fotosistem I (PSI)"},{"q":"PSII'nin çalışması için ışık şart mıdır? Karanlıkta su parçalanır mı?","steps":[{"t":"Enerji kaynağını düşün","a":"Işık gerekli","d":"P680'in elektronu ancak soğurulan ışık enerjisiyle uyarılıp kopar."},{"t":"Sonucu söyle","a":"Karanlıkta olmaz","d":"Işık olmadan P680 uyarılamaz, P680⁺ oluşmaz; dolayısıyla <b>karanlıkta su parçalanmaz</b>. PSII ışığa bağımlıdır."}],"ans":"Işık şarttır; karanlıkta su parçalanmaz"},{"q":"Suyun fotolizinden açığa çıkan elektronların PSII'deki ilk gidiş yeri neresidir?","steps":[{"t":"Su elektronunu düşün","a":"OEC'den çıkar","d":"OEC suyu parçalayınca elektronlar açığa çıkar."},{"t":"İlk hedefi söyle","a":"P680⁺","d":"Bu elektronlar önce elektron eksiği olan <b>P680⁺</b>'ya verilir ve onu nötr P680 hâline döndürür."}],"ans":"P680⁺ (eksik klorofili doldurur)"}],"zor":[{"q":"P680⁺'nın biyolojideki bilinen en güçlü oksitleyicilerden biri olması neden zorunludur?","steps":[{"t":"Görevi belirle","a":"Sudan e⁻ çeker","d":"P680⁺'nın elektron eksiğini kapatmak için sudan elektron koparması gerekir."},{"t":"Suyun direncini düşün","a":"Su zor verir","d":"Suyun yükseltgenme potansiyeli çok yüksektir; elektronunu kolay vermez (+0,82 V)."},{"t":"Zorunluluğu açıkla","a":"Çok güçlü olmalı","d":"Bu nedenle P680⁺ (~ +1,2 V) son derece güçlü bir <b>oksitleyici</b> olmalıdır; aksi hâlde suyu parçalayamaz ve elektron akışı durur."}],"ans":"Suyu yükseltgeyebilmek için aşırı güçlü oksitleyici olmalıdır"},{"q":"OEC'nin manganez kümesi (Mn₄CaO₅) suyu tek seferde değil de adım adım parçalar. Bu döngü nasıl açıklanır?","steps":[{"t":"Sorunu belirle","a":"4 e⁻ gerekli","d":"Bir O₂ üretmek için iki sudan toplam 4 elektronun ayrı ayrı koparılması gerekir."},{"t":"Döngüyü tanıt","a":"S durumları","d":"OEC her foton/elektron aktarımında S₀→S₁→S₂→S₃→S₄ adlı <b>S durumlarından</b> geçer (Kok döngüsü)."},{"t":"Sonucu açıkla","a":"S₄'te O₂ çıkar","d":"Dört adım birikince S₄ durumunda iki su birden parçalanır ve <b>O₂</b> açığa çıkar; küme S₀'a döner."}],"ans":"S durumları döngüsü (Kok döngüsü) ile 4 elektron birikip S₄'te O₂ çıkar"},{"q":"PSII'den geçen elektron akışı sırasında tilakoit lümeninde proton birikiminin iki ayrı kaynağı nedir?","steps":[{"t":"Birinci kaynağı bul","a":"Su fotolizi","d":"OEC suyu lümene bakan yüzeyde parçalar; açığa çıkan H⁺ doğrudan <b>lümene</b> bırakılır."},{"t":"İkinci kaynağı bul","a":"PQ döngüsü","d":"Plastokinon stromadan aldığı protonları sitokrom b6f kompleksinde lümene pompalar (Q-döngüsü)."},{"t":"Sonucu birleştir","a":"Gradiyent oluşur","d":"İki kaynak birlikte lümende güçlü bir <b>proton gradiyenti</b> (H⁺ derişim farkı) oluşturur; bu ATP sentezini sürer."}],"ans":"Suyun fotolizi ve plastokinon (Q) döngüsündeki proton pompalanması"},{"q":"Plastokinonun (PQ) elektron taşırken aynı zamanda proton da taşıması fotosentez enerjisi açısından neden önemlidir?","steps":[{"t":"PQ'nun çift işlevi","a":"e⁻ ve H⁺ taşır","d":"PQ, QB'de iki elektron alırken stromadan iki proton da alarak PQH₂'ye (plastokinol) dönüşür."},{"t":"Protonun yönünü izle","a":"Lümene bırakır","d":"PQH₂ membranda hareket edip sitokrom b6f'ye gelir; elektronları verirken protonları <b>lümene</b> bırakır."},{"t":"Önemini açıkla","a":"Gradiyent artar","d":"Böylece PQ protonları stromadan lümene taşımış olur; bu <b>kemiozmotik gradiyenti</b> güçlendirip ATP üretimini artırır."}],"ans":"Protonları stromadan lümene taşıyıp ATP üreten proton gradiyentini güçlendirir"},{"q":"DCMU (diuron) adlı bir herbisit PSII'de QB bağlanma bölgesini bloke eder. Bu maddenin oksijen çıkışına etkisi ne olur ve neden?","steps":[{"t":"Engeli belirle","a":"QB bloke","d":"DCMU, plastokinonun bağlandığı QB bölgesini kapatır; elektron PQ'ya geçemez."},{"t":"Akışın kesilmesini düşün","a":"e⁻ zinciri durur","d":"Elektron QA'dan ileri gidemez; P680 yeni elektron veremez ve P680⁺ kalıcı olarak doldurulamaz."},{"t":"Sonucu bul","a":"O₂ durur","d":"Su parçalama için P680⁺ talebi kalmaz; sonuçta suyun fotolizi ve <b>oksijen çıkışı durur</b>. DCMU bu yüzden fotosentezi engeller."}],"ans":"Elektron akışı kesilir, su fotolizi ve oksijen çıkışı durur"},{"q":"PSII'de enerji akışını sırasıyla yazınca, ışık fotonundan oksijene kadar olan elektron yolu nasıldır?","steps":[{"t":"Başlangıcı yaz","a":"Foton → P680*","d":"Anten pigmentlerinin topladığı foton enerjisi P680'i uyarır (P680*)."},{"t":"İlk aktarımları yaz","a":"Feofitin → QA → QB","d":"P680* elektronunu feofitine, oradan sırasıyla QA ve QB'ye aktarır; QB plastokinona verir."},{"t":"Eksiği kapat","a":"Su → P680⁺","d":"Oluşan P680⁺, OEC aracılığıyla suyu parçalayarak elektron alır; sudan ayrıca H⁺ ve <b>O₂</b> açığa çıkar."}],"ans":"Foton → P680* → feofitin → QA → QB → PQ; P680⁺ ise sudan (OEC) elektron alır, O₂ çıkar"},{"q":"P680'in PSII reaksiyon merkezindeki en güçlü oksitleyici olması, klorofilin yapısından çok hangi özelliğiyle ilgilidir?","steps":[{"t":"Klorofili karşılaştır","a":"Aynı pigment","d":"PSI'daki P700 ile PSII'deki P680 benzer klorofil molekülleridir; fark pigmentin kendisinde değildir."},{"t":"Çevreyi düşün","a":"Protein ortamı","d":"P680'i çevreleyen protein ortamı ve komşu rezidüler, elektronik düzeylerini değiştirir."},{"t":"Sonucu açıkla","a":"Redoks ayarı","d":"Bu protein çevresi P680⁺'nın <b>redoks potansiyelini</b> aşırı pozitif yapar; böylece suyu parçalayabilir. Yani konum/çevre belirleyicidir."}],"ans":"Reaksiyon merkezindeki protein çevresinin redoks potansiyelini ayarlamasıyla ilgilidir"},{"q":"Yüksek ışık şiddetinde PSII'nin zarar görmesi (fotoinhibisyon) neden öncelikle D1 proteininde olur?","steps":[{"t":"Riskli bölgeyi bul","a":"P680 ve OEC","d":"En güçlü oksitleyici P680⁺ ve suyu parçalayan OEC, D1 proteini üzerinde konumlanır."},{"t":"Hasar nedenini düşün","a":"Reaktif türler","d":"Aşırı ışıkta yüksek enerjili elektronlar ve P680⁺ reaktif oksijen türleri oluşturur; bunlar proteine zarar verir."},{"t":"Sonucu açıkla","a":"D1 yenilenir","d":"Hasar en çok <b>D1</b> proteinindedir; hücre bu yüzden D1'i sürekli onarıp yeniden sentezleyen bir döngü işletir."}],"ans":"P680⁺ ve OEC'nin oluşturduğu oksidatif hasar D1 proteininde yoğunlaştığı için"},{"q":"Klorofil floresansı ölçümü PSII'nin sağlığını gösterir. Eğer elektron QA'dan ileri akamazsa floresans nasıl değişir ve neden?","steps":[{"t":"Normal durumu düşün","a":"Enerji işe gider","d":"Sağlıklı PSII'de soğurulan enerji elektron taşımaya harcanır; floresans (geri yayılan ışık) düşüktür."},{"t":"Tıkanmayı düşün","a":"QA dolu kalır","d":"Elektron QA'dan ileri akamazsa QA indirgenmiş kalır; reaksiyon merkezi 'kapalı' olur."},{"t":"Sonucu açıkla","a":"Floresans artar","d":"Enerji elektron taşımaya gidemediğinden ışık olarak geri salınır; <b>floresans artar</b>. Yüksek floresans elektron akışının engellendiğini gösterir."}],"ans":"Elektron taşınamadığından enerji ışık olarak salınır ve floresans artar"},{"q":"PSII'nin OEC kümesindeki kalsiyum (Ca²⁺) ve klor (Cl⁻) iyonları çıkarıldığında suyun fotolizine ne olur?","steps":[{"t":"İyonların rolünü düşün","a":"OEC kofaktörü","d":"Ca²⁺ ve Cl⁻, Mn kümesinin doğru geometrisini ve su moleküllerinin konumlanmasını sağlayan kofaktörlerdir."},{"t":"Eksikliği düşün","a":"Küme bozulur","d":"Bu iyonlar olmadan OEC'nin katalitik düzeni bozulur; S durumları döngüsü ilerleyemez."},{"t":"Sonucu bul","a":"Fotoliz durur","d":"Su düzgün konumlanıp parçalanamaz; <b>suyun fotolizi ve O₂ çıkışı durur</b>. Bu iyonlar fotoliz için zorunludur."}],"ans":"OEC işlevini yitirir; su parçalanamaz ve oksijen çıkışı durur"},{"q":"Bir araştırmacı ortama elektron akışını engellemeden sadece ATP sentazı bloke ediyor. Lümendeki proton derişimine ne olur ve elektron akışı uzun vadede nasıl etkilenir?","steps":[{"t":"İlk etkiyi bul","a":"H⁺ akamaz","d":"ATP sentaz bloke olunca lümende biriken protonlar stromaya geri akamaz."},{"t":"Birikmeyi düşün","a":"Gradiyent aşırı artar","d":"Protonlar boşalamadığı için lümende H⁺ birikimi (gradiyent) aşırı yükselir, pH düşer."},{"t":"Geri besleme etkisi","a":"Akış yavaşlar","d":"Çok yüksek proton gradiyenti PQH₂'nin protonlarını lümene bırakmasını termodinamik olarak zorlaştırır; bu da elektron akışını ve sonunda <b>su fotolizini yavaşlatır</b> (fotosentetik kontrol)."}],"ans":"Lümen proton derişimi aşırı artar; gradiyent geri baskısı elektron akışını ve su fotolizini yavaşlatır"},{"q":"PSII ve PSI birlikte çalışırken (Z şeması) PSII'nin rolü elektron enerjisi açısından nasıl tanımlanır?","steps":[{"t":"Başlangıç düzeyini düşün","a":"Düşük enerjili e⁻","d":"PSII suyun düşük enerjili (sıkı bağlı) elektronlarını alır."},{"t":"Işıkla yükseltmeyi belirt","a":"Foton e⁻'yi yükseltir","d":"P680 foton soğurarak elektronu yüksek enerji düzeyine çıkarır; bu elektron zincirde aşağı inerken enerjisinin bir kısmı proton pompalamaya harcanır."},{"t":"Rolü tanımla","a":"İlk yükseltici","d":"Yani PSII, Z şemasında elektronu <b>ilk kez ışıkla yükselten</b> ve suyun fotolizini sağlayan basamaktır; ikinci yükseltme PSI'da olur."}],"ans":"PSII, suyun elektronlarını ışıkla ilk kez yükselten ve fotolizi sağlayan basamaktır"},{"q":"PSII'de plastokinol (PQH₂) hareketli bir taşıyıcı olduğu hâlde feofitin ve P680 sabittir. Bu yapısal farkın işlevsel anlamı nedir?","steps":[{"t":"Sabit kısmı düşün","a":"Hızlı aktarım","d":"P680 ve feofitin reaksiyon merkezine gömülüdür; aralarında ışık hızında, çok hızlı elektron aktarımı olur."},{"t":"Hareketliyi düşün","a":"Mekik görevi","d":"PQH₂ membran içinde serbestçe yüzer; PSII ile uzaktaki sitokrom b6f arasında elektron ve proton <b>mekiği</b> görevi yapar."},{"t":"Anlamı açıkla","a":"Kompleksleri bağlar","d":"Bu farklılık, hızlı yerel kimyayı (sabit) ile uzak kompleksler arası taşımayı (hareketli) ayırır; böylece elektron taşıma zinciri esnek ve verimli işler."}],"ans":"Sabit taşıyıcılar hızlı yerel aktarımı, hareketli PQH₂ ise uzak kompleksler arası taşımayı sağlar"},{"q":"Sadece PSII'yi uyaran (680 nm civarı) ışık verilip PSI uyarılmazsa, bir süre sonra PSII'de elektron akışı neden yavaşlar? (Kırmızı düşüş benzeri durum)","steps":[{"t":"Akışı düşün","a":"e⁻ PSI'a gider","d":"PSII'den çıkan elektronlar zincir boyunca ilerleyip PSI tarafından alınmalıdır."},{"t":"PSI uyarılmazsa","a":"e⁻ birikir","d":"PSI uyarılmazsa elektronları çekemez; PQ havuzu ve zincir tamamen indirgenmiş (dolu) kalır."},{"t":"Sonucu açıkla","a":"PSII tıkanır","d":"Dolu zincir PSII'den yeni elektron alamaz; P680⁺ azalır, su fotolizi yavaşlar. İki fotosistemin <b>dengeli uyarılması</b> gerektiğini gösterir."}],"ans":"Zincir indirgenmiş kalıp elektron çekemez; PSII tıkanır ve su fotolizi yavaşlar"},{"q":"Fotoliz tepkimesi 2H₂O → O₂ + 4H⁺ + 4e⁻ verildiğine göre, 6 molekül O₂ üretmek için kaç molekül su parçalanır ve kaç elektron açığa çıkar?","steps":[{"t":"Su oranını bul","a":"2 su / 1 O₂","d":"Tepkimeye göre 1 O₂ için 2 su parçalanır. 6 O₂ için 6 × 2 = 12 molekül su gerekir."},{"t":"Elektronu hesapla","a":"4 e⁻ / 1 O₂","d":"Her O₂ için 4 elektron açığa çıkar. 6 × 4 = 24 elektron oluşur."},{"t":"Sonucu yaz","a":"12 su, 24 e⁻","d":"Sonuç: <b>12 molekül su</b> parçalanır, <b>24 elektron</b> ve aynı şekilde 24 proton açığa çıkar."}],"ans":"12 molekül su parçalanır; 24 elektron (ve 24 proton) açığa çıkar"}]}},"genelBakis":{"ilkokul":{"kolay":[{"q":"Fotosentez nedir? Kısaca açıkla.","steps":[{"t":"Kelimenin anlamı","a":"ışıkla yemek yapmak","d":"<b>Foto</b> ışık demektir, <b>sentez</b> ise yapmak demektir. Yani ışık yardımıyla bir şey yapmaktır."},{"t":"Bitkide olan iş","a":"besin üretimi","d":"Bitkiler güneş ışığını kullanarak kendi besinini üretir. Buna fotosentez denir."}],"ans":"Fotosentez, bitkilerin güneş ışığını kullanarak kendi besinini ürettiği olaydır."},{"q":"Fotosentezi hangi canlılar yapar?","steps":[{"t":"Yeşil canlıları düşün","a":"yeşil bitkiler","d":"Ağaçlar, çimenler ve yapraklı bitkiler yeşil renklidir ve fotosentez yapar."},{"t":"Sonuç","a":"bitkiler","d":"Genellikle yeşil bitkiler fotosentez yapar, hayvanlar yapamaz."}],"ans":"Fotosentezi yeşil bitkiler yapar."},{"q":"Bitkiler fotosentez yaparken hangi ışığı kullanır?","steps":[{"t":"Doğal ışık kaynağı","a":"Güneş","d":"Gökyüzündeki Güneş, dünyaya ışık gönderen en büyük ışık kaynağıdır."},{"t":"Bitkinin kullandığı ışık","a":"güneş ışığı","d":"Bitkiler besin yapmak için güneş ışığını kullanır."}],"ans":"Bitkiler fotosentez için güneş ışığını kullanır."},{"q":"Bitkinin hangi kısmı fotosentez yapar?","steps":[{"t":"Yeşil kısmı bul","a":"yapraklar","d":"Bitkinin yaprakları yeşildir ve geniş yüzeyiyle ışığı toplar."},{"t":"Sonuç","a":"yaprak","d":"Fotosentez en çok yapraklarda olur çünkü yapraklar yeşildir."}],"ans":"Fotosentez en çok bitkinin yapraklarında yapılır."},{"q":"Fotosentez yapan bir bitki bize hangi yararlı gazı verir?","steps":[{"t":"Nefes aldığımız gaz","a":"oksijen","d":"Biz nefes alırken havadaki oksijen gazına ihtiyaç duyarız."},{"t":"Bitkinin verdiği gaz","a":"oksijen","d":"Bitkiler fotosentez yaparken havaya oksijen verir, biz de onu soluruz."}],"ans":"Bitkiler fotosentez sırasında bize oksijen gazı verir."}],"zor":[{"q":"Bir bitki besin yapmak için topraktan ve havadan neleri alır?","steps":[{"t":"Topraktan alınan","a":"su","d":"Bitki kökleriyle topraktaki suyu emer ve yapraklara taşır."},{"t":"Havadan alınan","a":"karbondioksit","d":"Yapraklar havadaki karbondioksit gazını içeri alır."},{"t":"Birleştir","a":"su ve karbondioksit","d":"Bitki, su ile karbondioksiti güneş ışığıyla birleştirerek besin yapar."}],"ans":"Bitki topraktan su, havadan karbondioksit alarak besin üretir."},{"q":"Bitkiler neden gündüzleri fotosentez yapar, geceleri yapamaz?","steps":[{"t":"Fotosentezin gerekli olanı","a":"ışık","d":"Fotosentez için güneş ışığı gereklidir."},{"t":"Gece durumu","a":"ışık yok","d":"Geceleri Güneş battığı için ortalık karanlık olur ve ışık yoktur."},{"t":"Sonuç","a":"sadece gündüz","d":"Işık olmadığı için bitki gece fotosentez yapamaz, sadece gündüz yapar."}],"ans":"Işık gece olmadığı için bitkiler fotosentezi sadece gündüz, ışıklı zamanda yapar."},{"q":"Bitkilere neden 'üretici' deriz?","steps":[{"t":"Kendi besinini yapma","a":"besinini kendi üretir","d":"Bitkiler dışarıdan hazır besin almaz, kendi besinini kendisi üretir."},{"t":"Üretici adı","a":"üretici","d":"Kendi besinini ürettikleri için bitkilere üretici denir."}],"ans":"Bitkiler kendi besinini kendileri ürettiği için onlara üretici denir."},{"q":"Yeryüzünde fotosentez olmasaydı havadaki oksijen ne olurdu?","steps":[{"t":"Oksijenin kaynağı","a":"bitkiler","d":"Havadaki oksijenin büyük kısmını fotosentez yapan bitkiler üretir."},{"t":"Fotosentez olmazsa","a":"oksijen azalır","d":"Bitkiler oksijen üretmezse havadaki oksijen yavaş yavaş azalır."},{"t":"Sonuç","a":"nefes almak zorlaşır","d":"Oksijen azalınca canlıların nefes alması zorlaşırdı."}],"ans":"Fotosentez olmasaydı oksijen azalır ve canlıların nefes alması zorlaşırdı."},{"q":"Bir saksı bitkisini karanlık bir dolaba koyarsak ne olur?","steps":[{"t":"Eksik olan","a":"ışık yok","d":"Dolapta güneş ışığı olmadığı için bitki ışık alamaz."},{"t":"Fotosentez durumu","a":"besin yapamaz","d":"Işık olmayınca bitki fotosentez yapamaz ve besin üretemez."},{"t":"Sonuç","a":"solar, sararır","d":"Besin yapamayan bitki zamanla sararır ve solar."}],"ans":"Karanlıkta ışık olmadığı için bitki besin yapamaz, sararıp solar."}]},"ortaokul":{"kolay":[{"q":"Fotosentezin gerçekleştiği hücre organeli hangisidir?","steps":[{"t":"Yeşil renk veren yapı","a":"kloroplast","d":"Bitki hücrelerinde yeşil renkli kloroplast adlı organel bulunur."},{"t":"Görevi","a":"fotosentez","d":"Kloroplast, ışığı yakalayıp fotosentezin yapıldığı yerdir."}],"ans":"Fotosentez, bitki hücrelerindeki kloroplast organelinde gerçekleşir."},{"q":"Kloroplastlara yeşil rengini veren madde nedir?","steps":[{"t":"Yeşil pigment","a":"klorofil","d":"Kloroplastların içinde klorofil adlı yeşil bir pigment vardır."},{"t":"Görevi","a":"ışığı yakalar","d":"Klorofil, güneş ışığını yakalayarak fotosentezi başlatır."}],"ans":"Yeşil rengi klorofil pigmenti verir ve klorofil ışığı yakalar."},{"q":"Fotosentezde üretilen besin (organik madde) nedir?","steps":[{"t":"Üretilen besin","a":"glikoz","d":"Fotosentez sonucunda glikoz adı verilen bir şeker üretilir."},{"t":"Glikozun yararı","a":"enerji deposu","d":"Glikoz, bitki için besin ve enerji kaynağı olarak kullanılır."}],"ans":"Fotosentezde glikoz adı verilen şeker (besin) üretilir."},{"q":"Fotosentez sırasında havadan alınan ve havaya verilen gazlar nelerdir?","steps":[{"t":"Alınan gaz","a":"karbondioksit","d":"Bitki havadan karbondioksit (CO₂) gazını alır."},{"t":"Verilen gaz","a":"oksijen","d":"Fotosentez sonucu havaya oksijen (O₂) gazı verilir."}],"ans":"Fotosentezde karbondioksit alınır, oksijen verilir."},{"q":"Fotosentez için gerekli üç temel madde nedir?","steps":[{"t":"Sıvı ve gaz","a":"su ve karbondioksit","d":"Bitki köklerden su, yapraklardan karbondioksit alır."},{"t":"Enerji kaynağı","a":"ışık","d":"Bu maddelerin birleşmesi için güneş ışığı enerjisi gerekir."}],"ans":"Fotosentez için su, karbondioksit ve ışık gereklidir."}],"zor":[{"q":"Fotosentezin genel denklemini kelimelerle yazınız.","steps":[{"t":"Girenler","a":"su, karbondioksit, ışık","d":"Bitki su (H₂O) ve karbondioksit (CO₂) alır, enerjiyi ışıktan sağlar."},{"t":"Ürünler","a":"glikoz ve oksijen","d":"Bu maddeler birleşince glikoz besini ve oksijen gazı oluşur."},{"t":"Denklemi yaz","a":"CO₂ + H₂O → glikoz + O₂","d":"Karbondioksit + su, ışık enerjisiyle glikoz + oksijene dönüşür."}],"ans":"Karbondioksit + su, ışık enerjisiyle → glikoz + oksijen."},{"q":"Fotosentezde güneşin ışık enerjisi neye dönüşür?","steps":[{"t":"Başlangıç enerjisi","a":"ışık enerjisi","d":"Güneşten gelen ışık bir enerji türüdür."},{"t":"Depolandığı yer","a":"glikozda","d":"Bu enerji, üretilen glikoz besininin içinde saklanır."},{"t":"Enerji türü","a":"kimyasal enerji","d":"Işık enerjisi, besinin bağlarında kimyasal enerjiye dönüşür."}],"ans":"Işık enerjisi, glikozda saklanan kimyasal enerjiye dönüşür."},{"q":"Fotosentez besin zincirinin neden temelinde yer alır?","steps":[{"t":"Üreticiler","a":"bitkiler besin üretir","d":"Bitkiler fotosentezle besin üreten üreticilerdir."},{"t":"Tüketicilerin bağlılığı","a":"hayvanlar bitkiyle beslenir","d":"Otçul hayvanlar bitkileri, etçiller de o hayvanları yiyerek beslenir."},{"t":"Sonuç","a":"enerjinin kaynağı","d":"Tüm canlıların enerjisi en başta fotosentezden gelir."}],"ans":"Tüm canlıların besini ve enerjisi en başta fotosentezden geldiği için fotosentez besin zincirinin temelidir."},{"q":"Yaprakların geniş ve yeşil olması fotosenteze nasıl yardımcı olur?","steps":[{"t":"Geniş yüzey","a":"daha çok ışık","d":"Yaprağın geniş olması daha fazla güneş ışığı yakalamasını sağlar."},{"t":"Yeşil renk","a":"klorofil bol","d":"Yeşil renk, ışığı yakalayan bol miktarda klorofil olduğunu gösterir."},{"t":"Sonuç","a":"verimli fotosentez","d":"Bol ışık ve bol klorofil sayesinde fotosentez daha verimli olur."}],"ans":"Geniş yüzey çok ışık toplar, yeşil renk bol klorofil demektir; ikisi fotosentezi artırır."},{"q":"Sucul bitkiler (su yosunları) da fotosentez yapar mı? Neden?","steps":[{"t":"Klorofil var mı","a":"evet, yeşildir","d":"Su yosunları da yeşildir ve klorofil içerir."},{"t":"Işık ulaşır mı","a":"su yüzeyine ulaşır","d":"Güneş ışığı suyun içine bir miktar girer ve bitkilere ulaşır."},{"t":"Sonuç","a":"fotosentez yapar","d":"Klorofil ve ışık olduğu için sucul bitkiler de fotosentez yapar."}],"ans":"Evet; klorofilleri olduğu ve ışık suya ulaştığı için sucul bitkiler de fotosentez yapar."}]},"lise":{"kolay":[{"q":"Fotosentezin tanımını bilimsel olarak yapınız.","steps":[{"t":"Süreç","a":"inorganikten organik","d":"Fotosentez, inorganik maddelerin (CO₂ ve H₂O) organik maddeye dönüştürülmesidir."},{"t":"Enerji kaynağı","a":"ışık","d":"Bu dönüşüm için gerekli enerji güneş ışığından sağlanır."}],"ans":"Fotosentez, ışık enerjisi kullanılarak inorganik maddelerden organik besin (glikoz) üretilmesidir."},{"q":"Fotosentezin dengelenmiş genel denklemini yazınız.","steps":[{"t":"Girenler","a":"6CO₂ + 6H₂O","d":"Altı molekül karbondioksit ve altı molekül su tepkimeye girer."},{"t":"Ürünler","a":"C₆H₁₂O₆ + 6O₂","d":"Işık enerjisiyle bir molekül glikoz ve altı molekül oksijen oluşur."}],"ans":"6CO₂ + 6H₂O → C₆H₁₂O₆ + 6O₂ (ışık enerjisi ve klorofil ile)."},{"q":"Klorofil pigmenti hangi renkteki ışığı en az kullanır?","steps":[{"t":"Soğurulan renkler","a":"mavi ve kırmızı","d":"Klorofil en çok mavi ve kırmızı dalga boylarını soğurur."},{"t":"Yansıtılan renk","a":"yeşil","d":"Yeşil ışığı büyük oranda yansıttığı için bitkiler yeşil görünür."}],"ans":"Klorofil yeşil ışığı en az kullanır (yansıtır), bu yüzden bitkiler yeşil görünür."},{"q":"Fotosentezde açığa çıkan oksijenin kaynağı hangi moleküldür?","steps":[{"t":"Su molekülü","a":"H₂O","d":"Işığa bağımlı tepkimelerde su molekülü parçalanır (fotoliz)."},{"t":"Oksijenin çıkışı","a":"sudan","d":"Suyun parçalanmasıyla açığa çıkan O₂, ortama verilen oksijendir."}],"ans":"Fotosentezde açığa çıkan oksijen, parçalanan su (H₂O) molekülünden gelir."},{"q":"Ototrof ve heterotrof beslenme arasındaki fark nedir?","steps":[{"t":"Ototrof","a":"kendi besinini üretir","d":"Ototroflar inorganik maddeden kendi organik besinini üretir (bitkiler)."},{"t":"Heterotrof","a":"dışarıdan alır","d":"Heterotroflar besinini hazır olarak dışarıdan alır (hayvanlar)."}],"ans":"Ototroflar besinini kendi üretir, heterotroflar dışarıdan hazır alır."},{"q":"Fotosentezin gerçekleştiği iki ana evre nedir?","steps":[{"t":"Birinci evre","a":"ışığa bağımlı","d":"Tilakoitlerde gerçekleşen, ışık enerjisinin yakalandığı evredir."},{"t":"İkinci evre","a":"ışıktan bağımsız","d":"Stromada gerçekleşen, CO₂ tutulumunun (Calvin) olduğu evredir."}],"ans":"Fotosentez ışığa bağımlı ve ışıktan bağımsız (Calvin) evrelerinden oluşur."},{"q":"Kloroplastın hangi kısmında ışığa bağımlı tepkimeler gerçekleşir?","steps":[{"t":"Yapı","a":"tilakoit","d":"Kloroplast içinde yassı keseler olan tilakoitler bulunur."},{"t":"Görev","a":"ışık tepkimeleri","d":"Klorofil tilakoit zarında olduğu için ışık tepkimeleri burada olur."}],"ans":"Işığa bağımlı tepkimeler kloroplastın tilakoit zarlarında gerçekleşir."},{"q":"Kloroplastın hangi kısmında Calvin döngüsü gerçekleşir?","steps":[{"t":"Sıvı kısım","a":"stroma","d":"Tilakoitlerin dışında kalan sıvı dolu bölüme stroma denir."},{"t":"Görev","a":"karbon tutma","d":"CO₂'nin glikoza dönüştürüldüğü Calvin döngüsü stromada olur."}],"ans":"Calvin döngüsü (ışıktan bağımsız tepkimeler) kloroplastın stromasında gerçekleşir."},{"q":"Neden fotosentez 'enerji dönüşümü' olarak adlandırılır?","steps":[{"t":"Girdi enerjisi","a":"ışık enerjisi","d":"Sürece güneşten gelen ışık (radyant) enerjisi girer."},{"t":"Çıktı enerjisi","a":"kimyasal enerji","d":"Bu enerji glikozun bağlarında kimyasal enerji olarak depolanır."}],"ans":"Fotosentez, ışık enerjisini kimyasal enerjiye dönüştürdüğü için bir enerji dönüşümüdür."},{"q":"Fotosentez için gerekli ham maddeler ve enerji kaynağı nelerdir?","steps":[{"t":"Ham maddeler","a":"CO₂ ve H₂O","d":"Karbondioksit havadan, su ise topraktan alınır."},{"t":"Enerji ve katalizör","a":"ışık ve klorofil","d":"Tepkimeyi başlatan enerji ışıktan, soğurucu pigment klorofilden gelir."}],"ans":"Ham maddeler CO₂ ve H₂O; enerji kaynağı ışık, soğurucu pigment ise klorofildir."},{"q":"Üreticilerin bir ekosistemdeki temel rolü nedir?","steps":[{"t":"Besin üretimi","a":"organik madde","d":"Üreticiler fotosentezle inorganikten organik besin üretir."},{"t":"Enerji girişi","a":"güneşten ekosisteme","d":"Güneş enerjisini ekosisteme sokarak besin zincirini başlatır."}],"ans":"Üreticiler, güneş enerjisini organik maddeye çevirerek ekosisteme enerji ve besin girişini sağlar."},{"q":"Klorofil dışında ışığı soğuran yardımcı pigmentlere ne ad verilir?","steps":[{"t":"Renkli pigmentler","a":"karotenoitler","d":"Sarı-turuncu renkli karotenoit pigmentleri de ışık soğurur."},{"t":"Görevi","a":"yardımcı soğurma","d":"Klorofilin soğuramadığı dalga boylarını yakalayıp enerjiyi aktarır."}],"ans":"Karotenoitler gibi yardımcı pigmentler, klorofilin yakalayamadığı ışığı soğurur."},{"q":"Fotosentezde üretilen glikoz bitkide hangi amaçlarla kullanılır?","steps":[{"t":"Enerji","a":"solunumda yakıt","d":"Glikoz, hücresel solunumda parçalanarak enerji (ATP) sağlar."},{"t":"Yapı ve depo","a":"nişasta, selüloz","d":"Fazla glikoz nişasta olarak depolanır veya selüloz yapımında kullanılır."}],"ans":"Glikoz hem solunumda enerji için kullanılır hem de nişasta/selüloz olarak yapı ve depo görevi görür."},{"q":"Stoma (gözenek) yapısının fotosentezdeki işlevi nedir?","steps":[{"t":"Gaz girişi","a":"CO₂ alımı","d":"Stomalar açıldığında havadaki CO₂ yaprağa girer."},{"t":"Gaz çıkışı","a":"O₂ verilişi","d":"Fotosentez ürünü oksijen yine stomalardan dışarı verilir."}],"ans":"Stomalar, fotosentez için CO₂'nin girişini ve O₂'nin çıkışını sağlayan gözeneklerdir."},{"q":"Fotosentez ve hücresel solunum birbirinin neden 'tersi' kabul edilir?","steps":[{"t":"Fotosentez","a":"CO₂+H₂O→glikoz+O₂","d":"Fotosentez inorganikten organik üretir ve enerji depolar."},{"t":"Solunum","a":"glikoz+O₂→CO₂+H₂O","d":"Solunum organiği parçalayıp enerji açığa çıkarır, ürünler terstir."}],"ans":"Fotosentezin girenleri solunumun ürünleri, ürünleri ise solunumun girenleri olduğu için birbirinin tersidir."}],"zor":[{"q":"Fotosentezin genel denkleminde radyoaktif işaretleme deneyleri oksijenin sudan geldiğini nasıl gösterir?","steps":[{"t":"İşaretli su","a":"H₂¹⁸O kullanımı","d":"Suyun oksijeni ağır izotop ¹⁸O ile işaretlenir."},{"t":"Ürün analizi","a":"O₂'de ¹⁸O","d":"Açığa çıkan oksijende ¹⁸O bulunur; CO₂ işaretlendiğinde çıkmaz."},{"t":"Sonuç","a":"oksijen sudan","d":"Bu, fotosentez oksijeninin sudan (fotoliz) geldiğini kanıtlar."}],"ans":"Suyun ¹⁸O ile işaretlendiği deneylerde O₂'nin ¹⁸O taşıması, oksijenin sudan geldiğini kanıtlar."},{"q":"C₃ bitkilerinde fotosentezin net denklemi neden 6CO₂ ile yazılır?","steps":[{"t":"Glikoz karbonu","a":"6 karbon","d":"Üretilen glikoz (C₆H₁₂O₆) altı karbon atomu içerir."},{"t":"Karbon kaynağı","a":"her C bir CO₂'den","d":"Her karbon bir CO₂ molekülünden geldiği için 6 CO₂ gerekir."},{"t":"Denge","a":"6CO₂ gerekli","d":"Kütle korunumu gereği 6 CO₂ tutularak 1 glikoz oluşur."}],"ans":"Bir glikozda 6 karbon olduğu ve her karbon bir CO₂'den geldiği için denklem 6CO₂ ile dengelenir."},{"q":"Fotosentezde ışık enerjisinin önce hangi ara enerji taşıyıcı moleküllere aktarıldığını açıklayınız.","steps":[{"t":"Işık tepkimeleri","a":"ATP ve NADPH","d":"Işığa bağımlı evrede enerji önce ATP ve NADPH'ye aktarılır."},{"t":"Aktarım","a":"Calvin'e taşınır","d":"Bu moleküller stromada Calvin döngüsüne enerji ve elektron taşır."},{"t":"Son depo","a":"glikozda","d":"Sonunda enerji kalıcı olarak glikozun bağlarında depolanır."}],"ans":"Işık enerjisi önce ATP ve NADPH'ye aktarılır; bunlar enerjiyi Calvin döngüsüne taşır, oradan glikoza depolanır."},{"q":"Fotosentezin biyosferdeki karbon döngüsündeki rolünü açıklayınız.","steps":[{"t":"CO₂ tutulumu","a":"atmosferden çeker","d":"Üreticiler atmosferdeki CO₂'yi tutarak organik maddeye bağlar."},{"t":"Karbonun aktarımı","a":"besin zinciri","d":"Bu organik karbon, beslenmeyle tüketicilere aktarılır."},{"t":"Geri dönüş","a":"solunum/ayrışma","d":"Solunum ve ayrışma ile karbon tekrar CO₂ olarak atmosfere döner."}],"ans":"Fotosentez atmosferdeki CO₂'yi organik karbona bağlayarak karbon döngüsünün üreticiden başlayan ilk halkasını oluşturur."},{"q":"Klorofil a ve klorofil b arasındaki temel fark ve işlevsel sonucu nedir?","steps":[{"t":"Soğurma farkı","a":"farklı dalga boyları","d":"Klorofil a ve b biraz farklı dalga boylarındaki ışığı soğurur."},{"t":"Rol farkı","a":"a reaksiyon merkezi","d":"Klorofil a reaksiyon merkezinde, b ise yardımcı pigment olarak çalışır."},{"t":"Sonuç","a":"geniş spektrum","d":"İkisi birlikte ışığın daha geniş spektrumunun kullanılmasını sağlar."}],"ans":"Klorofil a reaksiyon merkezinde, klorofil b yardımcı pigment olarak çalışır; birlikte daha geniş ışık spektrumu kullanılır."},{"q":"Tilakoit zarın katlanmış (granum) yapısının fotosentez verimine katkısı nedir?","steps":[{"t":"Yüzey artışı","a":"geniş zar yüzeyi","d":"Tilakoitlerin granum halinde istiflenmesi zar yüzeyini artırır."},{"t":"Pigment yoğunluğu","a":"çok fotosistem","d":"Geniş yüzeye daha çok klorofil ve fotosistem yerleşir."},{"t":"Sonuç","a":"daha çok ışık","d":"Böylece birim alanda daha fazla ışık soğurulup verim artar."}],"ans":"Granum istiflenmesi zar yüzeyini artırarak daha fazla fotosistem ve klorofil barındırır, bu da ışık soğurma verimini yükseltir."},{"q":"Fotosentezde net birincil üretim (NPP) kavramı ne anlama gelir?","steps":[{"t":"Brüt üretim","a":"GPP","d":"Brüt birincil üretim, fotosentezle üretilen toplam organik maddedir."},{"t":"Solunum kaybı","a":"GPP - solunum","d":"Bitkinin kendi solunumunda harcadığı kısım GPP'den çıkarılır."},{"t":"Net üretim","a":"NPP","d":"Geriye kalan, ekosisteme aktarılabilen organik madde NPP'dir."}],"ans":"Net birincil üretim, fotosentezle üretilen toplam organik maddeden bitkinin solunumda harcadığı kısım çıkarıldığında kalan miktardır."},{"q":"Kemosentez ile fotosentez arasındaki temel fark nedir?","steps":[{"t":"Enerji kaynağı","a":"fotosentez ışık","d":"Fotosentez enerjiyi güneş ışığından sağlar."},{"t":"Kemosentez kaynağı","a":"kimyasal","d":"Kemosentez enerjiyi inorganik maddelerin oksidasyonundan alır."},{"t":"Ortak nokta","a":"organik üretim","d":"İkisi de inorganikten organik besin üreten ototrof süreçtir."}],"ans":"İkisi de ototrof üretimdir; fotosentez ışık enerjisi, kemosentez ise kimyasal enerji kullanır."},{"q":"Bir yaprakta fotosentez hızının ışık şiddetiyle ilişkisi sınırsız mıdır? Açıklayınız.","steps":[{"t":"Başlangıç","a":"hız artar","d":"Düşük ışıkta ışık şiddeti arttıkça fotosentez hızı yükselir."},{"t":"Doyum noktası","a":"plato","d":"Belli bir şiddetten sonra hız artmaz, çünkü başka faktör sınırlar."},{"t":"Sınırlayıcı faktör","a":"CO₂ veya sıcaklık","d":"Bu noktada CO₂ miktarı veya sıcaklık sınırlayıcı faktör olur."}],"ans":"Hayır; ışık arttıkça hız önce artar, doyum noktasından sonra CO₂ veya sıcaklık gibi başka faktörler sınırladığı için sabitlenir."},{"q":"Fotosentezin atmosferin oksijen bakımından zenginleşmesindeki tarihsel rolü nedir?","steps":[{"t":"İlk üreticiler","a":"siyanobakteriler","d":"Erken dönemde siyanobakteriler fotosentezle oksijen üretmeye başladı."},{"t":"Büyük Oksijenlenme","a":"O₂ birikimi","d":"Üretilen oksijen atmosferde birikerek Büyük Oksijenlenme Olayı'na yol açtı."},{"t":"Sonuç","a":"aerobik yaşam","d":"Oksijen artışı, oksijenli solunum yapan canlıların gelişmesini sağladı."}],"ans":"Fotosentez yapan ilk canlılar atmosferi oksijenle zenginleştirerek Büyük Oksijenlenme Olayı'nı ve aerobik yaşamı mümkün kılmıştır."},{"q":"Fotosentez denkleminde su hem giren hem de Calvin sonrası ürün olarak görülebilir mi? Açıklayınız.","steps":[{"t":"Giren su","a":"fotolizde 12H₂O","d":"Ayrıntılı denklemde 12 su molekülü ışık tepkimelerinde parçalanır."},{"t":"Oluşan su","a":"6H₂O ürün","d":"Calvin ve sonrası tepkimelerde 6 su molekülü yeniden oluşur."},{"t":"Net denklem","a":"net 6H₂O","d":"Bu yüzden net denklemde su 6H₂O olarak sadeleştirilir."}],"ans":"Evet; ayrıntılı denklemde 12 su girer, 6 su yeniden oluşur, bu nedenle net denklemde su 6H₂O olarak sadeleşir."},{"q":"Yaprağın iç dokusundaki palizat parankiması neden fotosentezde uzmanlaşmıştır?","steps":[{"t":"Konum","a":"üst yüzeye yakın","d":"Palizat hücreleri yaprağın ışık alan üst yüzeyine yakın dizilir."},{"t":"Yapı","a":"bol kloroplast","d":"Uzun, sık dizili bu hücreler çok sayıda kloroplast içerir."},{"t":"Sonuç","a":"yüksek verim","d":"Işığa yakın ve kloroplast yoğun olması fotosentez verimini artırır."}],"ans":"Palizat parankiması üst yüzeye yakın, sık dizili ve bol kloroplastlı olduğu için fotosentezde uzmanlaşmıştır."},{"q":"Fotosentez sırasında enerji dönüşümünün termodinamik açıdan özelliği nedir?","steps":[{"t":"Enerji yönü","a":"düşükten yükseğe","d":"Düşük enerjili CO₂ ve H₂O, yüksek enerjili glikoza dönüşür."},{"t":"Tepkime türü","a":"endergonik","d":"Enerji depolayan bu süreç endergonik (enerji gerektiren) bir tepkimedir."},{"t":"Enerji kaynağı","a":"ışık","d":"Gerekli serbest enerji girişi güneş ışığından sağlanır."}],"ans":"Fotosentez, ışık enerjisini kullanarak düşük enerjili moleküllerden yüksek enerjili glikoz üreten endergonik (enerji depolayan) bir süreçtir."},{"q":"Fotosentez olmasaydı Dünya'daki yaşam enerji açısından neden sürdürülemezdi?","steps":[{"t":"Enerji girişi","a":"güneşi bağlar","d":"Fotosentez, güneş enerjisini canlıların kullanabileceği kimyasal enerjiye çevirir."},{"t":"Besin zinciri","a":"temelde üretici","d":"Tüm tüketiciler doğrudan veya dolaylı bu organik besine bağımlıdır."},{"t":"Sonuç","a":"enerji akışı durur","d":"Fotosentez olmasa ekosisteme enerji girişi durur, besin zinciri çöker."}],"ans":"Fotosentez ekosisteme tek temel enerji girişini sağladığı için olmasaydı besin zincirine enerji akışı durur ve yaşam sürdürülemezdi."},{"q":"Mezofil dokudaki hava boşluklarının fotosentez açısından önemi nedir?","steps":[{"t":"Boşlukların görevi","a":"gaz difüzyonu","d":"Sünger parankiması arasındaki boşluklar gazların serbestçe yayılmasını sağlar."},{"t":"CO₂ ulaşımı","a":"hücrelere taşır","d":"Stomalardan giren CO₂ bu boşluklar yoluyla fotosentez yapan hücrelere ulaşır."},{"t":"Sonuç","a":"verim artışı","d":"Hücrelere kolay CO₂ ulaşımı fotosentez hızını destekler."}],"ans":"Mezofildeki hava boşlukları CO₂'nin stomalardan fotosentez yapan hücrelere yayılmasını sağlayarak gaz alışverişini ve fotosentez verimini destekler."}]}},"kloroplast":{"ilkokul":{"kolay":[{"q":"Yaprakları yeşil yapan, içinde besin yapılan küçük yapının adı nedir?","steps":[{"t":"Yaprağın rengi","a":"Yeşil","d":"Yaprakların yeşil görünmesinin sebebi içlerinde yeşil renkli minik yapıların bulunmasıdır."},{"t":"Bu yapının adı","a":"Kloroplast","d":"Bitki hücrelerinde bulunan bu yeşil yapıya <b>kloroplast</b> denir ve besin burada üretilir."}],"ans":"Bu yeşil yapının adı kloroplasttır."},{"q":"Bitkilerde fotosentez (besin üretimi) hangi yapının içinde olur?","steps":[{"t":"Fotosentez nedir","a":"Besin yapma","d":"Bitkiler güneş ışığını kullanarak kendi besinini yapar; buna fotosentez denir."},{"t":"Nerede olur","a":"Kloroplastta","d":"Bu olay hücrenin içindeki yeşil <b>kloroplast</b> adlı yapıda gerçekleşir."}],"ans":"Fotosentez kloroplast içinde gerçekleşir."},{"q":"Kloroplastlar genellikle bitkinin hangi kısmında çok bulunur?","steps":[{"t":"Işık alan kısım","a":"Yapraklar","d":"Bitkinin güneş ışığını en çok alan kısmı yapraklarıdır."},{"t":"Kloroplast yeri","a":"Yapraklarda","d":"Bu yüzden yeşil <b>kloroplastlar</b> en çok yapraklarda toplanır."}],"ans":"Kloroplastlar en çok yapraklarda bulunur."},{"q":"Kloroplastın rengi neden yeşildir?","steps":[{"t":"İçindeki madde","a":"Yeşil boya","d":"Kloroplastın içinde yeşil renkli bir madde vardır."},{"t":"Sonuç","a":"Yeşil görünür","d":"Bu yeşil madde sayesinde <b>kloroplast</b> ve yapraklar yeşil görünür."}],"ans":"İçindeki yeşil madde yüzünden kloroplast yeşildir."},{"q":"Kloroplast bir bitki hücresinin neresinde bulunur?","steps":[{"t":"Hücre","a":"Bitki hücresi","d":"Bitkiler çok küçük hücrelerden oluşur."},{"t":"Konum","a":"Hücrenin içinde","d":"<b>Kloroplast</b> bu bitki hücrelerinin içinde yer alan küçük bir yapıdır."}],"ans":"Kloroplast bitki hücresinin içinde bulunur."}],"zor":[{"q":"Bir mantar veya hayvan hücresinde kloroplast bulunur mu, neden?","steps":[{"t":"Besin yapma","a":"Yapamazlar","d":"Hayvanlar ve mantarlar kendi besinini kendisi yapamaz, dışarıdan alır."},{"t":"Kloroplast gerekir mi","a":"Gerekmez","d":"Fotosentez yapmadıkları için bu hücrelerde yeşil <b>kloroplast</b> bulunmaz."}],"ans":"Hayvan ve mantar hücrelerinde kloroplast bulunmaz çünkü fotosentez yapmazlar."},{"q":"Karanlıkta uzun süre kalan bir bitkinin yaprakları neden sararabilir?","steps":[{"t":"Işık yok","a":"Güneş yok","d":"Kloroplastın yeşil maddesini koruyup çalıştırmak için ışık gerekir."},{"t":"Sonuç","a":"Sararma","d":"Işık olmayınca <b>kloroplastlar</b> iyi çalışamaz ve yapraklar sararabilir."}],"ans":"Işık olmayınca kloroplastlar zayıflar ve yapraklar sararır."},{"q":"Bir yaprağı büyüteçle çok büyütsek içinde gördüğümüz yeşil noktacıklar ne olabilir?","steps":[{"t":"Yeşil noktalar","a":"Minik yapılar","d":"Yaprağın içi küçük hücrelerle doludur ve bu hücrelerde yeşil noktacıklar vardır."},{"t":"Adı","a":"Kloroplast","d":"Bu yeşil noktacıkların her biri bir <b>kloroplasttır</b>."}],"ans":"Yapraktaki yeşil noktacıklar kloroplastlardır."},{"q":"Kloroplast bitkiye nasıl yardım eder?","steps":[{"t":"Görevi","a":"Besin üretmek","d":"Kloroplast güneş ışığını kullanarak bitkiye besin (şeker) yapar."},{"t":"Faydası","a":"Bitki beslenir","d":"Bu sayede bitki büyüyebilir; yani <b>kloroplast</b> bitkinin mutfağı gibidir."}],"ans":"Kloroplast besin üreterek bitkinin beslenmesini sağlar."},{"q":"Domatesin kırmızı, havucun turuncu olması bitkide her zaman kloroplast olmadığını mı gösterir?","steps":[{"t":"Renkler","a":"Yeşil değil","d":"Bitkinin her yeri yeşil değildir; meyve ve kökler farklı renklerde olabilir."},{"t":"Kloroplast","a":"Yeşil yerlerde","d":"Yeşil <b>kloroplast</b> daha çok yapraklarda bulunur; kırmızı veya turuncu kısımlarda başka renk maddeleri vardır."}],"ans":"Evet, kloroplastlar daha çok yeşil yapraklarda bulunur."}]},"ortaokul":{"kolay":[{"q":"Kloroplast hangi tür canlıların hücrelerinde bulunur?","steps":[{"t":"Fotosentez yapanlar","a":"Bitki ve bazı canlılar","d":"Kendi besinini üretebilen bitkiler ve bazı algler fotosentez yapar."},{"t":"Kloroplast","a":"Onlarda bulunur","d":"Fotosentez yaptıkları için bu canlıların hücrelerinde <b>kloroplast</b> bulunur."}],"ans":"Kloroplast bitki ve alg gibi fotosentez yapan canlılarda bulunur."},{"q":"Kloroplastın içindeki yeşil renkli pigmentin adı nedir?","steps":[{"t":"Yeşil renk","a":"Pigment","d":"Kloroplastın yeşil görünmesini sağlayan bir renk maddesi vardır."},{"t":"Adı","a":"Klorofil","d":"Bu yeşil pigmente <b>klorofil</b> denir ve ışığı emerek fotosentezi başlatır."}],"ans":"Kloroplastın yeşil pigmenti klorofildir."},{"q":"Kloroplast bir organel midir?","steps":[{"t":"Organel nedir","a":"Hücre yapısı","d":"Hücre içinde belirli görevi olan küçük yapılara organel denir."},{"t":"Kloroplast","a":"Evet organeldir","d":"<b>Kloroplast</b> fotosentez görevini yapan bir organeldir."}],"ans":"Evet, kloroplast fotosentez yapan bir organeldir."},{"q":"Klorofil molekülü fotosentez için neyi yakalar?","steps":[{"t":"Gerekli enerji","a":"Işık","d":"Fotosentez için güneşten gelen ışık enerjisi gereklidir."},{"t":"Klorofilin işi","a":"Işığı emer","d":"<b>Klorofil</b> güneş ışığını yakalayıp bu enerjiyi fotosentezde kullanılır hale getirir."}],"ans":"Klorofil güneş ışığını yakalar."},{"q":"Kloroplastın bitki için önemi nedir?","steps":[{"t":"Üretim","a":"Besin ve oksijen","d":"Kloroplast fotosentezle şeker (besin) üretir ve oksijen açığa çıkarır."},{"t":"Önemi","a":"Yaşam kaynağı","d":"Bu sayede <b>kloroplast</b> hem bitkiyi besler hem de havaya oksijen verir."}],"ans":"Kloroplast besin ve oksijen üreterek bitki ve diğer canlılar için önemlidir."}],"zor":[{"q":"Kloroplastın etrafını saran zar sayısı kaçtır?","steps":[{"t":"Dış sınır","a":"Zar","d":"Kloroplast, içeriğini koruyan zarlarla çevrilidir."},{"t":"Sayı","a":"İki zar","d":"<b>Kloroplast</b> çift zarlıdır; biri dış, biri iç olmak üzere iki zarı vardır."}],"ans":"Kloroplastın etrafını iki (çift) zar sarar."},{"q":"Kloroplastın içindeki yassı keseciklere ne ad verilir?","steps":[{"t":"İç yapı","a":"Yassı kesecik","d":"Kloroplastın içinde üst üste dizili yassı kesecikler bulunur."},{"t":"Adı","a":"Tilakoit","d":"Bu yassı keseciklerin her birine <b>tilakoit</b> denir; klorofil burada bulunur."}],"ans":"Kloroplastın içindeki yassı keseciklere tilakoit denir."},{"q":"Tilakoitlerin üst üste dizilerek oluşturduğu yapının adı nedir?","steps":[{"t":"Tilakoit dizilimi","a":"Üst üste","d":"Tilakoitler bozuk para gibi üst üste dizilir."},{"t":"Adı","a":"Granum","d":"Üst üste dizilmiş tilakoit yığınına <b>granum</b> denir."}],"ans":"Üst üste dizili tilakoitler granumu oluşturur."},{"q":"Kloroplastın içini dolduran sıvıya ne denir?","steps":[{"t":"İç sıvı","a":"Akışkan ortam","d":"Tilakoitlerin etrafını saran, kloroplastı dolduran bir sıvı vardır."},{"t":"Adı","a":"Stroma","d":"Bu sıvı kısma <b>stroma</b> denir; bazı reaksiyonlar burada olur."}],"ans":"Kloroplastın içini dolduran sıvıya stroma denir."},{"q":"Kloroplastın kendine ait DNA'sı var mıdır?","steps":[{"t":"DNA","a":"Kalıtım maddesi","d":"DNA, bir yapının görevleri için bilgi taşıyan moleküldür."},{"t":"Kloroplastta","a":"Evet vardır","d":"<b>Kloroplastın</b> kendine ait DNA'sı vardır; bu yüzden bazı proteinlerini kendisi üretebilir."}],"ans":"Evet, kloroplastın kendine ait DNA'sı vardır."}]},"lise":{"kolay":[{"q":"Kloroplast hangi zar sistemiyle çevrilidir ve bu onu hangi organel grubuna sokar?","steps":[{"t":"Zar yapısı","a":"Çift zar","d":"Kloroplast dış zar ve iç zar olmak üzere çift zarla çevrilidir."},{"t":"Grubu","a":"Çift zarlı organel","d":"Mitokondri gibi <b>kloroplast</b> da çift zarlı organeller grubundadır."}],"ans":"Kloroplast çift zarlı bir organeldir."},{"q":"Kloroplastın iç zarının içinde kalan sıvı dolu bölgeye ne ad verilir?","steps":[{"t":"İç bölge","a":"Sıvı ortam","d":"İç zarın çevrelediği, tilakoitlerin gömülü olduğu sıvı vardır."},{"t":"Adı","a":"Stroma","d":"Bu sıvıya <b>stroma</b> denir; enzim, kloroplast DNA'sı ve ribozom içerir."}],"ans":"İç zarın içindeki sıvıya stroma denir."},{"q":"Klorofil pigmenti kloroplastın hangi yapısının zarında yoğun bulunur?","steps":[{"t":"Pigment yeri","a":"Zar üzerinde","d":"Işığı emen klorofil, belirli bir zar sisteminde yerleşiktir."},{"t":"Yapı","a":"Tilakoit zarı","d":"Klorofil <b>tilakoit</b> zarında bulunur; ışık reaksiyonları burada başlar."}],"ans":"Klorofil tilakoit zarında bulunur."},{"q":"Granum ile stroma arasındaki temel yapısal fark nedir?","steps":[{"t":"Granum","a":"Tilakoit yığını","d":"Granum, üst üste dizili tilakoit zarlarından oluşan zar sistemidir."},{"t":"Stroma","a":"Sıvı ortam","d":"<b>Stroma</b> ise tilakoitleri çevreleyen akışkan, enzim dolu sıvıdır."}],"ans":"Granum tilakoit zar yığını, stroma ise onları çevreleyen sıvıdır."},{"q":"Tilakoidlerin içinde kalan boşluğa ne ad verilir?","steps":[{"t":"Tilakoit yapısı","a":"Kese","d":"Her tilakoit, zarla çevrili yassı bir kesedir."},{"t":"İç boşluk","a":"Tilakoit lümeni","d":"Bu kesenin içindeki boşluğa <b>tilakoit lümeni</b> denir; H⁺ iyonları burada birikir."}],"ans":"Tilakoidin içindeki boşluğa tilakoit lümeni denir."},{"q":"Işığa bağımlı (ışık) reaksiyonları kloroplastın neresinde gerçekleşir?","steps":[{"t":"Işık reaksiyonu","a":"Işık gerekir","d":"Bu reaksiyonlar klorofilin ışığı emmesiyle başlar."},{"t":"Yeri","a":"Tilakoit zarı","d":"Bu nedenle ışık reaksiyonları <b>tilakoit</b> zarında gerçekleşir."}],"ans":"Işık reaksiyonları tilakoit zarında gerçekleşir."},{"q":"Karanlık reaksiyonlar (Calvin döngüsü) kloroplastın neresinde gerçekleşir?","steps":[{"t":"Calvin döngüsü","a":"Enzimatik","d":"Bu evrede CO₂ enzimlerle organik moleküle bağlanır (karbon tutulumu)."},{"t":"Yeri","a":"Stroma","d":"Bu enzimler sıvı ortamda olduğundan karanlık reaksiyonlar <b>stromada</b> gerçekleşir."}],"ans":"Karanlık reaksiyonlar (Calvin döngüsü) stromada gerçekleşir."},{"q":"Kloroplast endosimbiyotik teoriye göre hangi canlıdan köken almıştır?","steps":[{"t":"Endosimbiyoz","a":"Ortak yaşam","d":"Bir hücrenin başka bir prokaryotu içine alıp birlikte yaşamasıyla organel oluştuğu düşünülür."},{"t":"Kloroplast kökeni","a":"Siyanobakteri","d":"<b>Kloroplastın</b> fotosentetik bir siyanobakteriden köken aldığı kabul edilir."}],"ans":"Kloroplast endosimbiyotik teoriye göre siyanobakteriden köken alır."},{"q":"Kloroplastın kendine ait DNA ve ribozom bulundurması neyi gösterir?","steps":[{"t":"Bulunan yapılar","a":"DNA ve ribozom","d":"Kloroplast stromasında halkasal DNA ve prokaryot tipi ribozomlar bulunur."},{"t":"Anlamı","a":"Yarı özerklik","d":"Bu, <b>kloroplastın</b> bazı proteinlerini kendi sentezleyebildiğini ve endosimbiyotik kökenini destekler."}],"ans":"Kloroplastın DNA ve ribozomu, yarı özerk olduğunu ve prokaryot kökenini gösterir."},{"q":"Bir kloroplastta birden çok granum bulunur; bunları birbirine bağlayan zara ne denir?","steps":[{"t":"Granumlar","a":"Çok sayıda","d":"Stromada çok sayıda granum bulunur."},{"t":"Bağlantı","a":"Stroma lameli","d":"Granumları birbirine bağlayan tilakoit uzantılarına <b>stroma lameli</b> (intergranal tilakoit) denir."}],"ans":"Granumları birbirine bağlayan zara stroma lameli denir."},{"q":"Kloroplastın dış zarı ile iç zarı arasındaki dar boşluğa ne denir?","steps":[{"t":"İki zar arası","a":"Boşluk","d":"Çift zarlı yapıda dış ve iç zar arasında ince bir aralık vardır."},{"t":"Adı","a":"Zarlar arası boşluk","d":"Bu dar aralığa <b>zarlar arası boşluk</b> denir."}],"ans":"Dış ve iç zar arasındaki boşluğa zarlar arası boşluk denir."},{"q":"Fotosentezde üretilen glikoz aslında kloroplastta önce hangi madde olarak depolanabilir?","steps":[{"t":"İlk ürün","a":"Şeker","d":"Calvin döngüsünde üretilen şekerler birleşerek depo molekülüne dönüşebilir."},{"t":"Depo","a":"Nişasta","d":"Kloroplastın <b>stromasında</b> geçici olarak nişasta tanecikleri depolanır."}],"ans":"Üretilen şekerler stromada nişasta olarak depolanabilir."},{"q":"Klorofilin yeşil görünmesinin sebebi hangi ışık rengiyle ilgilidir?","steps":[{"t":"Emilen ışık","a":"Mavi ve kırmızı","d":"Klorofil özellikle mavi ve kırmızı dalga boylarındaki ışığı emer."},{"t":"Yansıyan ışık","a":"Yeşil","d":"Yeşil ışığı pek ememeyip yansıttığı için <b>klorofil</b> gözümüze yeşil görünür."}],"ans":"Klorofil yeşil ışığı yansıttığı için yeşil görünür."},{"q":"Kloroplast, mitokondri gibi hangi temel ortak özelliği taşır?","steps":[{"t":"Ortak yapı","a":"Çift zar","d":"Hem kloroplast hem mitokondri çift zarlıdır ve kendi DNA'sını taşır."},{"t":"Ortak işlev","a":"Enerji dönüşümü","d":"İkisi de enerji dönüşümü yapar; <b>kloroplast</b> ışık enerjisini kimyasal enerjiye çevirir."}],"ans":"Kloroplast da mitokondri gibi çift zarlı, kendi DNA'lı bir enerji organelidir."},{"q":"Bir bitki hücresinde tilakoit zarının yüzey alanının geniş olması ne sağlar?","steps":[{"t":"Geniş yüzey","a":"Çok klorofil","d":"Üst üste dizilen tilakoitler toplam zar yüzeyini büyük ölçüde artırır."},{"t":"Faydası","a":"Daha çok ışık","d":"Geniş yüzey daha fazla klorofil ve fotosistem barındırır, böylece daha çok ışık emilir."}],"ans":"Geniş tilakoit yüzeyi daha fazla ışık emilimi ve verimli fotosentez sağlar."}],"zor":[{"q":"Işık reaksiyonlarında suyun parçalanması (fotoliz) kloroplastın tam olarak neresinde gerçekleşir?","steps":[{"t":"Fotoliz","a":"Su yarılması","d":"Suyun H⁺, elektron ve O₂'ye ayrışmasına fotoliz denir ve Fotosistem II'de gerçekleşir."},{"t":"Konum","a":"Tilakoit lümeni tarafı","d":"Fotoliz, <b>tilakoit zarının</b> lümene bakan yüzünde olur; açığa çıkan H⁺ lümende birikir."}],"ans":"Fotoliz, tilakoit zarının lümen tarafında gerçekleşir."},{"q":"Kemiosmoz sırasında ATP sentezini sağlayan H⁺ derişim farkı kloroplastın hangi iki bölgesi arasında oluşur?","steps":[{"t":"H⁺ birikimi","a":"Lümen","d":"Fotoliz ve elektron taşınması H⁺ iyonlarını tilakoit lümeninde biriktirir."},{"t":"Gradyan yönü","a":"Lümen → stroma","d":"H⁺, ATP sentaz üzerinden lümenden <b>stromaya</b> akar; bu akış ATP üretir."}],"ans":"H⁺ gradyanı tilakoit lümeni ile stroma arasında oluşur."},{"q":"ATP sentaz enziminin kloroplasttaki konumu ve ürettiği ATP'nin biriktiği yer neresidir?","steps":[{"t":"Enzim yeri","a":"Tilakoit zarı","d":"ATP sentaz tilakoit zarına gömülüdür; başlık kısmı stromaya bakar."},{"t":"ATP'nin yeri","a":"Stroma","d":"H⁺ stromaya akarken üretilen <b>ATP</b> stromada toplanır ve Calvin döngüsünde kullanılır."}],"ans":"ATP sentaz tilakoit zarındadır; ürettiği ATP stromada birikir."},{"q":"Calvin döngüsünün ürünlerinin (NADPH ve ATP) üretildiği yer ile tüketildiği yer arasındaki yapısal ilişkiyi açıklayın.","steps":[{"t":"Üretim yeri","a":"Tilakoit zarı","d":"ATP ve NADPH ışık reaksiyonlarında tilakoit zarında üretilir ve stromaya salınır."},{"t":"Tüketim yeri","a":"Stroma","d":"<b>Calvin döngüsü</b> stromada gerçekleştiği için bu moleküller hemen orada tüketilir; iki bölme komşudur."}],"ans":"ATP/NADPH tilakoit zarında üretilip komşu stromadaki Calvin döngüsünde tüketilir."},{"q":"Fotosistem I ve Fotosistem II'nin kloroplasttaki yerleşimi neresidir?","steps":[{"t":"Fotosistemler","a":"Protein kompleksi","d":"Fotosistem I ve II, klorofil ve proteinlerden oluşan ışık toplayıcı komplekslerdir."},{"t":"Konum","a":"Tilakoit zarı","d":"Her iki <b>fotosistem</b> de tilakoit zarına gömülüdür; aralarında elektron taşıma zinciri bulunur."}],"ans":"Fotosistem I ve II tilakoit zarına yerleşmiştir."},{"q":"NADPH'nin oluştuğu yüzey tilakoit zarının hangi tarafıdır ve neden?","steps":[{"t":"NADP⁺ indirgenmesi","a":"Stroma tarafı","d":"Fotosistem I'den gelen elektronlar NADP⁺'yi indirgeyerek NADPH oluşturur."},{"t":"Neden","a":"Stromaya bakan yüz","d":"NADP⁺ stromada bulunduğundan indirgenme <b>tilakoit zarının</b> stromaya bakan yüzünde olur; NADPH stromaya salınır."}],"ans":"NADPH, tilakoit zarının stromaya bakan yüzünde oluşur çünkü NADP⁺ stromadadır."},{"q":"Kloroplastın çift zarının kökeni endosimbiyotik teoriyle nasıl açıklanır?","steps":[{"t":"İç zar","a":"Bakteri zarı","d":"İç zarın, yutulan siyanobakterinin kendi hücre zarından geldiği düşünülür."},{"t":"Dış zar","a":"Konak zarı","d":"Dış zarın ise yutan konak hücrenin oluşturduğu fagositoz keseciğinden (zarından) geldiği kabul edilir."}],"ans":"İç zar siyanobakteriden, dış zar konak hücrenin keseciğinden köken alır."},{"q":"Tilakoit lümeninin pH'ı, ışık reaksiyonları sırasında stromaya göre nasıl değişir?","steps":[{"t":"H⁺ birikimi","a":"Lümende artar","d":"Fotoliz ve elektron taşınmasıyla H⁺ lümende yoğunlaşır."},{"t":"pH sonucu","a":"Lümen daha asidik","d":"H⁺ artışı <b>tilakoit lümenini</b> stromaya göre daha asidik (düşük pH) yapar; bu fark ATP üretimini sürdürür."}],"ans":"Tilakoit lümeni stromaya göre daha asidik (düşük pH) hale gelir."},{"q":"Kloroplast DNA'sının halkasal olması ve histonsuz oluşu neyi destekler?","steps":[{"t":"DNA yapısı","a":"Halkasal, çıplak","d":"Kloroplast DNA'sı tıpkı bakterilerdeki gibi halkasal ve histon proteinlerinden yoksundur."},{"t":"Anlamı","a":"Prokaryot köken","d":"Bu özellik <b>kloroplastın</b> prokaryot bir atadan (siyanobakteri) geldiği endosimbiyotik teoriyi destekler."}],"ans":"Halkasal, histonsuz DNA kloroplastın prokaryot (siyanobakteri) kökenini destekler."},{"q":"Granumların oluşması (tilakoit istiflenmesi) fotosentez verimi açısından ne sağlar?","steps":[{"t":"İstiflenme","a":"Yüzey artışı","d":"Tilakoitlerin granum halinde istiflenmesi sınırlı hacimde çok büyük zar yüzeyi yaratır."},{"t":"Verim","a":"Daha çok fotosistem","d":"Geniş yüzey daha fazla <b>fotosistem</b> ve klorofil barındırır, böylece ışık emilimi ve ATP/NADPH üretimi artar."}],"ans":"Granum istiflenmesi zar yüzeyini artırarak ışık emilimi ve fotosentez verimini yükseltir."},{"q":"Kloroplastta C₃ bitkilerinde karbon tutulumunu yapan enzim hangisidir ve nerede çalışır?","steps":[{"t":"Enzim","a":"Rubisko","d":"CO₂'yi RuBP'ye bağlayan enzim rubiskodur (RuBP karboksilaz)."},{"t":"Konum","a":"Stroma","d":"Calvin döngüsü stromada geçtiğinden <b>rubisko</b> kloroplastın stromasında çalışır."}],"ans":"Karbon tutulumunu yapan rubisko enzimi kloroplast stromasında çalışır."},{"q":"Işık reaksiyonları ile Calvin döngüsünün kloroplast içinde mekânsal olarak ayrılması ne avantaj sağlar?","steps":[{"t":"Mekânsal ayrım","a":"Zar ve sıvı","d":"Işık reaksiyonları tilakoit zarında, Calvin döngüsü stromada ayrı yürür."},{"t":"Avantaj","a":"Verimli akış","d":"Bu ayrım, H⁺ gradyanının korunmasını ve ATP/NADPH'nin <b>stromaya</b> verimli aktarımını sağlar; süreçler birbirini engellemez."}],"ans":"Mekânsal ayrım H⁺ gradyanını korur ve iki evrenin verimli, engelsiz işlemesini sağlar."},{"q":"Elektron taşıma zinciri kloroplastın neresinde yer alır ve elektronların son alıcısı nedir?","steps":[{"t":"Zincir konumu","a":"Tilakoit zarı","d":"Fotosistem II ile Fotosistem I arasındaki elektron taşıma zinciri tilakoit zarına gömülüdür."},{"t":"Son alıcı","a":"NADP⁺","d":"Elektronların son alıcısı NADP⁺'dir; indirgenerek stromada <b>NADPH</b> oluşur."}],"ans":"Elektron taşıma zinciri tilakoit zarındadır; elektronların son alıcısı NADP⁺'dir."},{"q":"Kloroplast iç zarının mitokondriden farklı olarak kıvrımlar (krista) oluşturmamasının nedeni nedir?","steps":[{"t":"Mitokondri","a":"Krista","d":"Mitokondride yüzey artışı iç zarın kristalar yapmasıyla sağlanır."},{"t":"Kloroplast","a":"Tilakoit sistemi","d":"<b>Kloroplastta</b> yüzey artışı ayrı bir tilakoit zar sistemiyle sağlandığından iç zarın kıvrılmasına gerek kalmaz."}],"ans":"Kloroplastta yüzey artışını ayrı tilakoit sistemi sağladığı için iç zar kıvrım yapmaz."},{"q":"Stromada bulunan kloroplast ribozomlarının (70S) sitoplazma ribozomlarından (80S) farklı olması ne anlama gelir?","steps":[{"t":"Ribozom tipi","a":"70S","d":"Kloroplast ribozomları bakteri tipi 70S iken sitoplazma ribozomları 80S'tir."},{"t":"Anlamı","a":"Bağımsız sentez + köken","d":"Bu fark, <b>kloroplastın</b> kendi proteinlerini bağımsızca üretebildiğini ve prokaryot kökenini gösterir."}],"ans":"70S ribozomlar kloroplastın bağımsız protein sentezini ve prokaryot kökenini gösterir."}]}},"pigmentler":{"ilkokul":{"kolay":[{"q":"Yaprakların yeşil görünmesini sağlayan madde nedir?","steps":[{"t":"1. adım: Renkli madde","a":"Pigment","d":"Bitkilerin renklerini renk veren maddelere pigment denir."},{"t":"2. adım: Yeşil pigment","a":"Klorofil","d":"Yapraklarda en çok bulunan yeşil pigmentin adı klorofildir."}],"ans":"Yaprakları yeşil yapan madde <b>klorofil</b>dir."},{"q":"Klorofil yaprağın hangi bölümünde bol bulunur?","steps":[{"t":"1. adım: Yaprağın yeşil kısmı","a":"Yaprak ayası","d":"Yaprağın yassı ve geniş yeşil bölümünde bol klorofil vardır."},{"t":"2. adım: Sonuç","a":"Yeşil yaprak dokusu","d":"Bu yüzden yaprağın geniş bölümü yemyeşil görünür."}],"ans":"Klorofil yaprağın <b>yeşil ayasında</b> bol bulunur."},{"q":"Bitkiler güneş ışığını yakalamak için neyi kullanır?","steps":[{"t":"1. adım: Işığı yakalayan madde","a":"Klorofil","d":"Yeşil klorofil güneş ışığını yakalayıp bitkiye yardım eder."},{"t":"2. adım: Ne işe yarar","a":"Besin yapımı","d":"Yakalanan ışıkla bitki kendi besinini üretir."}],"ans":"Bitkiler ışığı yakalamak için <b>klorofil</b> kullanır."},{"q":"Bir yaprağın rengi neden çoğu zaman yeşildir?","steps":[{"t":"1. adım: İçindeki pigment","a":"Bol klorofil","d":"Yaprakta çok miktarda yeşil klorofil bulunur."},{"t":"2. adım: Görünen renk","a":"Yeşil","d":"Klorofil çok olunca yaprak bize yeşil görünür."}],"ans":"Yaprak çok <b>klorofil</b> taşıdığı için yeşil görünür."},{"q":"Havuçların turuncu rengini sağlayan boya maddesi de bir pigment midir?","steps":[{"t":"1. adım: Pigment nedir","a":"Renk maddesi","d":"Canlılara renk veren maddelere pigment denir."},{"t":"2. adım: Havuçtaki renk","a":"Turuncu pigment","d":"Havuçtaki turuncu renk de bir pigmenttir."}],"ans":"Evet, havucun turuncu rengi de bir <b>pigmenttir</b>."}],"zor":[{"q":"Sonbaharda yapraklar neden sararıp kızarır?","steps":[{"t":"1. adım: Yeşil pigmentin azalması","a":"Klorofil azalır","d":"Hava soğuyunca yapraktaki yeşil klorofil yavaş yavaş yok olur."},{"t":"2. adım: Diğer renkler ortaya çıkar","a":"Sarı-turuncu pigment","d":"Klorofil gidince altta gizli duran sarı ve turuncu pigmentler görünür."}],"ans":"Klorofil azalınca sarı-turuncu pigmentler görünür ve yaprak <b>sararır</b>."},{"q":"Yaprakların yeşili dışında başka renkleri de var mıdır?","steps":[{"t":"1. adım: Gizli pigmentler","a":"Var","d":"Yaprakta yeşil dışında sarı ve turuncu pigmentler de gizlidir."},{"t":"2. adım: Neden görünmezler","a":"Yeşil baskındır","d":"Klorofil çok olduğu için diğer renkleri örter."}],"ans":"Evet, yaprakta gizli <b>sarı ve turuncu</b> pigmentler de vardır."},{"q":"Karanlıkta uzun süre kalan bir bitki neden sararır?","steps":[{"t":"1. adım: Işık gerekir","a":"Klorofil için ışık","d":"Bitkinin yeşil klorofili yapması için ışığa ihtiyacı vardır."},{"t":"2. adım: Işık olmazsa","a":"Klorofil yapılamaz","d":"Karanlıkta klorofil üretilemez, bitki soluk ve sarı kalır."}],"ans":"Işık olmayınca klorofil yapılamaz, bitki <b>sararır</b>."},{"q":"Yeşil bir yaprağı suya koyup ısıtırsak su yeşile boyanabilir; bu neyi gösterir?","steps":[{"t":"1. adım: Renk nereden geldi","a":"Yapraktan","d":"Yapraktaki yeşil renk maddesi suya geçmiştir."},{"t":"2. adım: O madde nedir","a":"Klorofil","d":"Suyu yeşile boyayan madde yapraktaki klorofildir."}],"ans":"Bu, yaprakta <b>klorofil</b> adlı yeşil bir madde olduğunu gösterir."},{"q":"Domates olgunlaşırken neden yeşilden kırmızıya döner?","steps":[{"t":"1. adım: Yeşil pigmentin gitmesi","a":"Klorofil azalır","d":"Domates olgunlaşırken içindeki yeşil klorofil kaybolur."},{"t":"2. adım: Kırmızı pigment artar","a":"Kırmızı pigment","d":"Aynı sırada kırmızı renk veren pigment çoğalır."}],"ans":"Klorofil azalıp kırmızı pigment artınca domates <b>kırmızı</b> olur."}]},"ortaokul":{"kolay":[{"q":"Fotosentezde ışığı soğuran temel pigment hangisidir?","steps":[{"t":"1. adım: Pigment görevi","a":"Işığı soğurmak","d":"Pigmentler güneş ışığının enerjisini soğurur."},{"t":"2. adım: Temel pigment","a":"Klorofil","d":"Fotosentezde ışığı soğuran en önemli pigment klorofildir."}],"ans":"Fotosentezde ışığı soğuran temel pigment <b>klorofil</b>dir."},{"q":"Klorofil hangi renkleri soğurur, hangi rengi yansıtır?","steps":[{"t":"1. adım: Soğurulan renkler","a":"Kırmızı ve mavi","d":"Klorofil ışığın kırmızı ve mavi kısmını soğurur."},{"t":"2. adım: Yansıyan renk","a":"Yeşil","d":"Yeşil ışığı soğurmaz, geri yansıtır; bu yüzden yeşil görürüz."}],"ans":"Klorofil <b>kırmızı ve maviyi</b> soğurur, <b>yeşili</b> yansıtır."},{"q":"Klorofilin kaç çeşidi en çok bilinir?","steps":[{"t":"1. adım: Ana çeşitler","a":"İki çeşit","d":"Bitkilerde en çok klorofil a ve klorofil b bulunur."},{"t":"2. adım: Görevleri","a":"Işık soğurma","d":"İkisi de ışığı soğurur ama biraz farklı renklerde çalışır."}],"ans":"En çok bilinen iki çeşit <b>klorofil a ve klorofil b</b>dir."},{"q":"Havuç ve kabağa turuncu-sarı renk veren pigment grubu nedir?","steps":[{"t":"1. adım: Renk grubu","a":"Karotenoidler","d":"Sarı, turuncu renk veren pigmentlere karotenoid denir."},{"t":"2. adım: Örnek","a":"Havuç","d":"Havucun turuncu rengi karotenoidlerden gelir."}],"ans":"Sarı-turuncu renk veren pigment grubu <b>karotenoidlerdir</b>."},{"q":"Pigmentler fotosentez için neden gereklidir?","steps":[{"t":"1. adım: Enerji kaynağı","a":"Güneş ışığı","d":"Fotosentez için güneş enerjisi gerekir."},{"t":"2. adım: Enerjiyi yakalama","a":"Pigmentler soğurur","d":"Pigmentler ışık enerjisini soğurarak fotosenteze aktarır."}],"ans":"Pigmentler ışık enerjisini soğurduğu için fotosenteze <b>gereklidir</b>."}],"zor":[{"q":"Bir yaprak neden hem klorofil hem karotenoid bulundurur?","steps":[{"t":"1. adım: Klorofilin sınırı","a":"Bazı renkleri kaçırır","d":"Klorofil özellikle yeşil bölgedeki ışığı pek soğuramaz."},{"t":"2. adım: Karotenoidin yardımı","a":"Farklı renkleri soğurur","d":"Karotenoidler klorofilin kaçırdığı bazı ışıkları soğurup ona aktarır."}],"ans":"Karotenoidler klorofilin soğuramadığı ışıkları yakalayıp <b>yardımcı olur</b>."},{"q":"Sonbaharda yaprakların sararmasını pigmentlerle açıklayınız.","steps":[{"t":"1. adım: Klorofilin parçalanması","a":"Klorofil yıkılır","d":"Soğuk ve kısalan günlerle birlikte klorofil parçalanıp azalır."},{"t":"2. adım: Karotenoidlerin görünmesi","a":"Sarı renk ortaya çıkar","d":"Daha dayanıklı olan karotenoidler kalır ve yaprak sarı-turuncu görünür."}],"ans":"Klorofil azalınca dayanıklı <b>karotenoidler</b> görünür ve yaprak sararır."},{"q":"Yaprağa beyaz ışık tuttuğumuzda neden yeşil rengi gözümüze ulaşır?","steps":[{"t":"1. adım: Beyaz ışığın içeriği","a":"Tüm renkler","d":"Beyaz ışık kırmızı, yeşil, mavi gibi tüm renkleri içerir."},{"t":"2. adım: Klorofilin seçimi","a":"Yeşili yansıtır","d":"Klorofil kırmızı-maviyi soğurur, yeşili yansıttığı için onu görürüz."}],"ans":"Klorofil yeşili soğurmayıp yansıttığı için göze <b>yeşil</b> ulaşır."},{"q":"Klorofil a ile klorofil b arasındaki temel fark nedir?","steps":[{"t":"1. adım: Görev farkı","a":"a ana, b yardımcı","d":"Klorofil a esas iş gören pigment, klorofil b yardımcı pigmenttir."},{"t":"2. adım: Soğurma farkı","a":"Biraz farklı renk","d":"İkisi ışığın biraz farklı renklerini soğurarak birbirini tamamlar."}],"ans":"Klorofil a esas, <b>klorofil b</b> yardımcı pigmenttir ve farklı renkleri soğururlar."},{"q":"Akvaryumdaki kırmızı bir su yosunu da fotosentez yapabilir mi?","steps":[{"t":"1. adım: Farklı pigment","a":"Kırmızı pigment","d":"Bazı yosunlarda klorofil yanında kırmızı renkli pigmentler de bulunur."},{"t":"2. adım: Sonuç","a":"Evet yapar","d":"Bu pigmentler suyun altına ulaşan ışığı soğurarak fotosentezi sürdürür."}],"ans":"Evet, farklı <b>pigmentleri</b> sayesinde kırmızı yosun da fotosentez yapar."}]},"lise":{"kolay":[{"q":"Fotosentezde rol alan pigmentler hangi organelin hangi yapısında bulunur?","steps":[{"t":"1. adım: Organel","a":"Kloroplast","d":"Fotosentez pigmentleri kloroplast içinde yer alır."},{"t":"2. adım: Konum","a":"Tilakoit zarı","d":"Pigmentler tilakoit zarındaki fotosistemlere bağlıdır."}],"ans":"Pigmentler kloroplastın <b>tilakoit zarında</b> bulunur."},{"q":"Klorofil a hangi renk bölgelerinde en güçlü soğurma yapar?","steps":[{"t":"1. adım: Mavi bölge","a":"≈430 nm","d":"Klorofil a mavi ışığı yaklaşık 430 nm civarında güçlü soğurur."},{"t":"2. adım: Kırmızı bölge","a":"≈660-680 nm","d":"Kırmızı ışığı da yaklaşık 660-680 nm civarında soğurur."}],"ans":"Klorofil a <b>mavi (≈430 nm)</b> ve <b>kırmızı (≈660 nm)</b> bölgelerde güçlü soğurur."},{"q":"Yaprakların yeşil görünmesinin fiziksel nedeni nedir?","steps":[{"t":"1. adım: Soğurulan dalga boyları","a":"Mavi ve kırmızı","d":"Klorofiller ışığın mavi ve kırmızı bölgelerini soğurur."},{"t":"2. adım: Yansıyan dalga boyu","a":"Yeşil","d":"Yeşil (≈500-560 nm) bölgesi az soğurulup yansıtılır, gözümüze ulaşır."}],"ans":"Mavi-kırmızı soğurulup <b>yeşil yansıdığı</b> için yapraklar yeşil görünür."},{"q":"Karotenoidler hangi renk bölgesinde ışık soğurur?","steps":[{"t":"1. adım: Soğurma bölgesi","a":"Mavi-yeşil","d":"Karotenoidler ışığın mavi ve mavi-yeşil bölgesini (≈400-500 nm) soğurur."},{"t":"2. adım: Görünen renk","a":"Sarı-turuncu","d":"Bu bölgeyi soğurup sarı-turuncuyu yansıttıkları için o renkte görünürler."}],"ans":"Karotenoidler <b>mavi-yeşil (≈400-500 nm)</b> bölgeyi soğurur, sarı-turuncuyu yansıtır."},{"q":"Klorofil a ve klorofil b'nin işlevsel ayrımı nedir?","steps":[{"t":"1. adım: Klorofil a","a":"Reaksiyon merkezi","d":"Klorofil a, fotosistemin reaksiyon merkezinde doğrudan elektron verir."},{"t":"2. adım: Klorofil b","a":"Yardımcı (anten)","d":"Klorofil b yardımcı pigmenttir; soğurduğu enerjiyi klorofil a'ya aktarır."}],"ans":"Klorofil a <b>reaksiyon merkezi</b>, klorofil b ise <b>yardımcı</b> pigmenttir."},{"q":"Aksesuar (yardımcı) pigmentlerin temel görevi nedir?","steps":[{"t":"1. adım: Görev","a":"Soğurma aralığını genişletmek","d":"Yardımcı pigmentler klorofil a'nın soğuramadığı dalga boylarını soğurur."},{"t":"2. adım: Enerji aktarımı","a":"Klorofil a'ya iletir","d":"Soğurdukları enerjiyi reaksiyon merkezindeki klorofil a'ya aktarırlar."}],"ans":"Yardımcı pigmentler farklı dalga boylarını soğurup enerjiyi <b>klorofil a'ya</b> aktarır."},{"q":"Anten kompleksi (ışık toplayıcı kompleks) nedir?","steps":[{"t":"1. adım: Yapı","a":"Pigment topluluğu","d":"Çok sayıda pigment molekülünün bir araya geldiği toplayıcı yapıdır."},{"t":"2. adım: İşlev","a":"Enerjiyi toplar","d":"Soğurulan ışık enerjisini reaksiyon merkezine doğru aktarır."}],"ans":"Anten kompleksi, ışığı toplayıp enerjiyi <b>reaksiyon merkezine</b> ileten pigment topluluğudur."},{"q":"Bir pigmentin absorpsiyon spektrumu neyi gösterir?","steps":[{"t":"1. adım: Tanım","a":"Soğurma-dalga boyu grafiği","d":"Pigmentin hangi dalga boyunda ne kadar ışık soğurduğunu gösteren grafiktir."},{"t":"2. adım: Yorum","a":"Pik bölgeler","d":"Grafikteki tepe noktaları pigmentin en çok soğurduğu renkleri belirtir."}],"ans":"Absorpsiyon spektrumu, pigmentin <b>dalga boyuna göre soğurma miktarını</b> gösterir."},{"q":"Klorofil ışığın yeşil bölgesini neden zayıf soğurur?","steps":[{"t":"1. adım: Yapısal seçicilik","a":"Belirli enerji düzeyleri","d":"Klorofil yalnızca belirli enerjili (mavi-kırmızı) fotonları soğurur."},{"t":"2. adım: Sonuç","a":"Yeşili yansıtır","d":"Yeşil bölgenin enerjisi bu düzeylere uymadığı için soğurulmaz, yansır."}],"ans":"Yeşilin enerjisi klorofilin soğurma düzeyine uymadığı için <b>zayıf soğurulur</b>."},{"q":"Ksantofil hangi pigment grubuna girer ve neye katkı sağlar?","steps":[{"t":"1. adım: Grup","a":"Karotenoid","d":"Ksantofiller oksijen içeren karotenoidlerdir, sarı renk verir."},{"t":"2. adım: Katkı","a":"Işık soğurma + koruma","d":"Hem ışık soğurur hem de fazla ışıkta klorofili korumaya yardım eder."}],"ans":"Ksantofil bir <b>karotenoid</b>dir; ışık soğurur ve klorofili korumaya katkı sağlar."},{"q":"Etkinlik (aksiyon) spektrumu ile absorpsiyon spektrumu arasındaki ilişki nedir?","steps":[{"t":"1. adım: Absorpsiyon","a":"Soğurma","d":"Absorpsiyon spektrumu pigmentin soğurduğu dalga boylarını gösterir."},{"t":"2. adım: Aksiyon","a":"Fotosentez hızı","d":"Aksiyon spektrumu hangi dalga boyunda fotosentezin hızlandığını gösterir; ikisi büyük ölçüde örtüşür."}],"ans":"Pigmentin <b>soğurduğu</b> dalga boyları, fotosentezin <b>en hızlı</b> olduğu dalga boylarıyla örtüşür."},{"q":"Sonbaharda yaprakların sararmasının pigment temeli nedir?","steps":[{"t":"1. adım: Klorofil yıkımı","a":"Klorofil parçalanır","d":"Kısalan günler ve soğukla klorofil parçalanıp azalır."},{"t":"2. adım: Karotenoid kalması","a":"Sarı görünür","d":"Daha kararlı karotenoidler kaldığı için yaprak sarı-turuncu görünür."}],"ans":"Klorofil yıkılınca kalan <b>karotenoidler</b> sayesinde yaprak sararır."},{"q":"Neden fotosentez en çok mavi ve kırmızı ışıkta verimlidir?","steps":[{"t":"1. adım: Pigment soğurması","a":"Mavi-kırmızı pik","d":"Klorofiller en güçlü soğurmayı mavi ve kırmızı bölgede yapar."},{"t":"2. adım: Sonuç","a":"Yüksek verim","d":"Bu bölgelerde daha çok enerji soğurulduğu için fotosentez hızı artar."}],"ans":"Klorofil mavi-kırmızıyı güçlü soğurduğu için fotosentez bu renklerde <b>verimlidir</b>."},{"q":"Karadeniz'de derin sularda yaşayan yosunların farklı pigment taşıması ne sağlar?","steps":[{"t":"1. adım: Derinlikte ışık","a":"Mavi-yeşil baskın","d":"Derin sulara çoğunlukla mavi-yeşil ışık ulaşır."},{"t":"2. adım: Pigment uyumu","a":"Bu ışığı soğurur","d":"Bu yosunların ek pigmentleri mavi-yeşil ışığı soğurarak fotosentez yapmasını sağlar."}],"ans":"Ek pigmentler derine ulaşan <b>mavi-yeşil ışığı</b> soğurarak fotosentezi sürdürür."},{"q":"Pigment molekülü ışık soğurduğunda molekülde ne olur?","steps":[{"t":"1. adım: Elektron uyarılması","a":"Uyarılmış hâl","d":"Soğurulan foton enerjisiyle pigmentteki elektron üst enerji düzeyine çıkar."},{"t":"2. adım: Enerji aktarımı","a":"İletilir","d":"Bu enerji komşu pigmente ya da reaksiyon merkezine aktarılır."}],"ans":"Işık soğurulunca elektron <b>uyarılır</b> ve enerji reaksiyon merkezine aktarılır."}],"zor":[{"q":"Anten kompleksindeki pigmentler enerjiyi nasıl reaksiyon merkezine taşır?","steps":[{"t":"1. adım: Yardımcı pigment soğurur","a":"Foton soğurma","d":"Karotenoid ve klorofil b gibi yardımcı pigmentler fotonu soğurup uyarılır."},{"t":"2. adım: Rezonans aktarımı","a":"Pigmentten pigmente","d":"Enerji, rezonansla komşu pigmentlere sıçrayarak ilerler."},{"t":"3. adım: Reaksiyon merkezi","a":"Klorofil a","d":"Enerji sonunda reaksiyon merkezindeki özelleşmiş klorofil a'ya ulaşır."}],"ans":"Yardımcı pigmentler soğurdukları enerjiyi <b>rezonansla</b> aktararak reaksiyon merkezindeki klorofil a'ya taşır."},{"q":"Klorofil a ve klorofil b'nin absorpsiyon spektrumları neden tam üst üste değildir?","steps":[{"t":"1. adım: Yapı farkı","a":"Yan grup farkı","d":"Klorofil b'de bir metil grubu yerine aldehit grubu bulunur."},{"t":"2. adım: Soğurma kayması","a":"Pikler kayar","d":"Bu yapı farkı, soğurma piklerini biraz farklı dalga boylarına kaydırır."},{"t":"3. adım: İşlevsel kazanım","a":"Daha geniş aralık","d":"Böylece ikisi birlikte daha geniş bir ışık aralığını soğurur."}],"ans":"Yapı farkı pikleri kaydırdığı için ikisi birlikte <b>daha geniş</b> dalga boyu aralığını soğurur."},{"q":"Karotenoidlerin yalnızca ışık soğurma dışında fotokoruma görevi nasıl gerçekleşir?","steps":[{"t":"1. adım: Aşırı uyarılma riski","a":"Üçlü klorofil","d":"Çok ışıkta klorofil tehlikeli uyarılmış (üçlü) hâle geçebilir."},{"t":"2. adım: Karotenoid söndürme","a":"Enerjiyi alır","d":"Karotenoid bu fazla enerjiyi alıp ısı olarak dağıtır."},{"t":"3. adım: Sonuç","a":"Hasar önlenir","d":"Böylece zararlı reaktif oksijen oluşumu ve klorofil hasarı önlenir."}],"ans":"Karotenoidler fazla enerjiyi söndürerek <b>reaktif oksijeni</b> ve klorofil hasarını önler."},{"q":"Mor ışık altında tutulan yaprakta fotosentez hızı yeşil ışığa göre neden yüksektir?","steps":[{"t":"1. adım: Pigment soğurması","a":"Mor güçlü soğurulur","d":"Klorofil ve karotenoidler mor-mavi ışığı güçlü soğurur."},{"t":"2. adım: Yeşil zayıf","a":"Az soğurulur","d":"Yeşil ışık büyük ölçüde yansıtılır, az enerji soğurulur."},{"t":"3. adım: Hız farkı","a":"Mor hızlı","d":"Daha çok enerji soğurulduğu için mor ışıkta fotosentez hızı yüksektir."}],"ans":"Mor ışık güçlü soğurulduğundan, yeşile göre fotosentez hızı <b>yüksektir</b>."},{"q":"Aksiyon spektrumunun yeşil bölgede sıfır olmaması neyi kanıtlar?","steps":[{"t":"1. adım: Klorofil zayıf","a":"Yeşili az soğurur","d":"Yalnız klorofil olsa yeşilde fotosentez neredeyse durmalıydı."},{"t":"2. adım: Yardımcı pigmentler","a":"Yeşili kısmen soğurur","d":"Karotenoidler ve diğer pigmentler yeşil bölgenin bir kısmını soğurur."},{"t":"3. adım: Kanıt","a":"Çoklu pigment","d":"Yeşilde hâlâ fotosentez olması, birden çok pigmentin katkısını kanıtlar."}],"ans":"Yeşilde fotosentez sürmesi, <b>yardımcı pigmentlerin</b> katkısını kanıtlar."},{"q":"Engelmann'ın spirogyra deneyi pigmentlerin soğurması hakkında ne gösterir?","steps":[{"t":"1. adım: Düzenek","a":"Prizma + bakteri","d":"Yosun farklı renklere ayrılan ışığa konur, oksijen seven bakteriler eklenir."},{"t":"2. adım: Bakteri dağılımı","a":"Mavi-kırmızıda toplanır","d":"Bakteriler en çok oksijenin çıktığı mavi ve kırmızı ışık bölgesinde toplanır."},{"t":"3. adım: Sonuç","a":"Soğurma piki","d":"Bu, fotosentezin pigmentlerin güçlü soğurduğu renklerde en hızlı olduğunu gösterir."}],"ans":"Bakteriler mavi-kırmızıda toplanarak fotosentezin pigment <b>soğurma piklerinde</b> en hızlı olduğunu gösterir."},{"q":"Klorofil molekülünün ışık soğurmasını sağlayan yapısal özelliği nedir?","steps":[{"t":"1. adım: Porfirin halkası","a":"Konjuge çift bağlar","d":"Klorofilin baş kısmında çok sayıda değişimli çift bağ içeren porfirin halkası vardır."},{"t":"2. adım: Elektron uyarılması","a":"Görünür ışık","d":"Bu konjuge sistemdeki elektronlar görünür ışık enerjisiyle kolayca uyarılır."},{"t":"3. adım: Sonuç","a":"Soğurma","d":"Bu yapı sayesinde klorofil mavi ve kırmızı ışığı verimle soğurur."}],"ans":"Porfirin halkasındaki <b>konjuge çift bağ sistemi</b> klorofilin görünür ışığı soğurmasını sağlar."},{"q":"Bir bitkiye yalnızca yeşil ışık verilirse uzun vadede ne beklenir?","steps":[{"t":"1. adım: Soğurma azlığı","a":"Düşük enerji","d":"Yeşil ışık pigmentlerce az soğurulduğu için az enerji sağlanır."},{"t":"2. adım: Fotosentez düşer","a":"Az besin","d":"Düşük enerji nedeniyle fotosentez ve besin üretimi azalır."},{"t":"3. adım: Sonuç","a":"Zayıf büyüme","d":"Uzun vadede bitki zayıflar, büyümesi yavaşlar."}],"ans":"Yeşil az soğurulduğu için fotosentez düşer ve bitki <b>zayıf büyür</b>."},{"q":"Fikobilinler gibi ek pigmentler kırmızı alglerde hangi avantajı sağlar?","steps":[{"t":"1. adım: Su ve ışık","a":"Derinde mavi-yeşil","d":"Suyun derininde özellikle mavi-yeşil ışık kalır."},{"t":"2. adım: Fikobilin soğurması","a":"Bu bölgeyi soğurur","d":"Fikobilinler klorofilin zayıf olduğu bu bölgeyi güçlü soğurur."},{"t":"3. adım: Avantaj","a":"Derinde fotosentez","d":"Böylece bu algler ışığın azaldığı derinliklerde fotosentez yapabilir."}],"ans":"Fikobilinler derine ulaşan <b>mavi-yeşil ışığı</b> soğurarak derinlikte fotosenteze olanak verir."},{"q":"Soğurma spektrumunda iki klorofilin kırmızı bölge piklerinin yeşildeki çukurla ilişkisi nedir?","steps":[{"t":"1. adım: Kırmızı pikler","a":"Yüksek soğurma","d":"Klorofiller kırmızı bölgede yüksek soğurma piki gösterir."},{"t":"2. adım: Yeşil çukur","a":"Düşük soğurma","d":"Yeşil bölgede soğurma çukura iner, ışık çoğunlukla yansır."},{"t":"3. adım: İlişki","a":"Seçicilik","d":"Bu zıtlık, klorofilin belirli dalga boylarını seçici soğurduğunu gösterir; yeşil yansır, kırmızı tutulur."}],"ans":"Kırmızıdaki pik ve yeşildeki çukur, klorofilin <b>seçici soğurma</b> yaptığını ve yeşili yansıttığını gösterir."},{"q":"Reaksiyon merkezi klorofili ile anten klorofili aynı molekül olsa da işlevleri neden farklıdır?","steps":[{"t":"1. adım: Aynı molekül","a":"Klorofil a","d":"İkisi de klorofil a'dır, kimyasal olarak aynıdır."},{"t":"2. adım: Çevre farkı","a":"Protein ortamı","d":"Reaksiyon merkezindeki klorofil özel proteinlere bağlıdır."},{"t":"3. adım: İşlev","a":"Elektron verme","d":"Bu özel ortam sayesinde yalnızca o klorofil uyarılınca elektron verebilir; antendekiler sadece enerji aktarır."}],"ans":"Bağlı oldukları <b>protein ortamı</b> farklı olduğu için reaksiyon merkezi klorofili elektron verir, antendekiler yalnızca enerji aktarır."},{"q":"İki farklı pigment karışımının soğurma spektrumu tek pigmente göre neden daha geniştir?","steps":[{"t":"1. adım: Tek pigment","a":"Dar pikler","d":"Tek pigment yalnızca kendi dalga boylarını soğurur."},{"t":"2. adım: Karışım","a":"Pikler birleşir","d":"Farklı pigmentlerin pikleri üst üste binince soğurulan bölge genişler."},{"t":"3. adım: Sonuç","a":"Daha çok ışık","d":"Böylece güneş ışığının daha geniş bölümü fotosentezde kullanılabilir."}],"ans":"Farklı pigmentlerin pikleri birleştiği için karışım <b>daha geniş</b> dalga boyu aralığını soğurur."},{"q":"Karotenoid bakımından zengin bir yaprakta ışık şiddeti çok yükseldiğinde ne gözlenir?","steps":[{"t":"1. adım: Aşırı ışık","a":"Hasar riski","d":"Yüksek ışık klorofili aşırı uyararak zarar verebilir."},{"t":"2. adım: Karotenoid devreye girer","a":"Enerji söndürme","d":"Karotenoidler fazla enerjiyi alıp ısıya çevirir."},{"t":"3. adım: Sonuç","a":"Koruma","d":"Bu sayede yaprak yüksek ışıkta daha az hasar görür."}],"ans":"Karotenoidler fazla enerjiyi söndürerek yaprağı yüksek ışık <b>hasarından korur</b>."},{"q":"Klorofilin merkezindeki magnezyum iyonu çıkarılırsa pigmentin işlevi nasıl etkilenir?","steps":[{"t":"1. adım: Yapı bozulur","a":"Mg²⁺ çıkar","d":"Porfirin halkasının merkezindeki Mg²⁺ iyonu çıkarılınca yapı değişir."},{"t":"2. adım: Soğurma değişir","a":"Renk solar","d":"Magnezyumsuz molekül ışığı eskisi gibi soğuramaz, yeşil renk kahverengiye döner."},{"t":"3. adım: İşlev kaybı","a":"Fotosentez aksar","d":"Bu hâliyle enerjiyi etkili aktaramaz, fotosentezdeki görevi bozulur."}],"ans":"Mg²⁺ çıkınca soğurma bozulur, renk solar ve klorofilin fotosentezdeki <b>işlevi kaybolur</b>."},{"q":"Bir laboratuvarda yaprak özütü kromatografi ile ayrılınca neden birden çok renkli bant oluşur?","steps":[{"t":"1. adım: Birden çok pigment","a":"Karışım","d":"Yaprak özütünde klorofil a, klorofil b, karotenoid ve ksantofil birlikte bulunur."},{"t":"2. adım: Farklı hareket","a":"Farklı hız","d":"Her pigment çözücüde farklı hızda ilerlediği için ayrı noktalarda toplanır."},{"t":"3. adım: Sonuç","a":"Renk bantları","d":"Bu nedenle yeşil, sarı ve turuncu farklı bantlar olarak görünür."}],"ans":"Yaprakta birden çok pigment olduğu ve farklı hızda ilerledikleri için <b>ayrı renk bantları</b> oluşur."}]}},"zSemasi":{"ilkokul":{"kolay":[{"q":"Bitki yaprağında ışık enerjisi nasıl taşınır?","steps":[{"t":"Işık gelir","a":"yaprağa","d":"Güneş ışığı yaprağın yeşil kısmına çarpar ve burada işe başlar."},{"t":"Adım adım taşınır","a":"küçük taşıyıcılarla","d":"Enerji bir taşıyıcıdan diğerine sırayla geçer; tıpkı eli ele veren bir zincir gibi."}],"ans":"Işık enerjisi yaprakta küçük taşıyıcılar arasında adım adım taşınır."},{"q":"Yapraktaki enerji yolculuğu nereden başlar?","steps":[{"t":"Başlangıç noktası","a":"sudan","d":"Bitki kökleriyle aldığı su yaprağa gelir."},{"t":"Su parçalanır","a":"ışıkla","d":"Işık suyu parçalar ve buradan minik parçacıklar yola çıkar."}],"ans":"Enerji yolculuğu sudan başlar; ışık suyu parçalar."},{"q":"Işık bitkide kaç kez yardımcı olur?","steps":[{"t":"İlk yardım","a":"birinci ışık","d":"Işık ilk kez minik parçacıkları yukarı iter."},{"t":"İkinci yardım","a":"ikinci ışık","d":"Sonra ışık ikinci kez gelir ve onları tekrar yukarı iter."}],"ans":"Işık bitkide iki kez yardım eder ve parçacıkları iki kez yukarı iter."},{"q":"Yapraktaki enerji zinciri neye benzetilir?","steps":[{"t":"Şekle bakılır","a":"yukarı-aşağı","d":"Parçacık önce yukarı çıkar, sonra aşağı iner, tekrar yukarı çıkar."},{"t":"Harfe benzer","a":"Z harfi","d":"Bu yukarı-aşağı yol kâğıda çizilince Z harfine benzer."}],"ans":"Enerji zinciri Z harfine benzediği için ona Z şeması denir."},{"q":"Bitki ışık enerjisini ne yapmak için kullanır?","steps":[{"t":"Enerji toplanır","a":"ışıktan","d":"Yaprak güneşten enerji toplar."},{"t":"Besin için saklanır","a":"besin yapımı","d":"Bu enerji bitkinin kendi besinini yapmasına yardım eder."}],"ans":"Bitki ışık enerjisini kendi besinini yapmak için kullanır."}],"zor":[{"q":"Sudan çıkan minik parçacık yolculuğun sonunda nereye varır?","steps":[{"t":"Sudan çıkar","a":"başlangıç","d":"Işık suyu parçalayınca minik parçacıklar serbest kalır."},{"t":"Yol boyunca taşınır","a":"taşıyıcılarla","d":"Parçacık taşıyıcı zincirden geçerek ilerler."},{"t":"Sonuca ulaşır","a":"saklama yerine","d":"En sonunda bitkinin enerji kutusu denilen yere ulaşır."}],"ans":"Sudan çıkan parçacık taşıyıcılardan geçip en sonda bitkinin enerji kutusuna varır."},{"q":"Neden iki kez ışığa ihtiyaç var?","steps":[{"t":"İlk itiş yetmez","a":"birinci ışık","d":"İlk ışık parçacığı biraz yukarı iter ama yeterince yükseğe çıkaramaz."},{"t":"İkinci itiş gerekir","a":"ikinci ışık","d":"Parçacık aşağı düştükten sonra ikinci ışık onu tekrar yukarı iter."}],"ans":"Tek itiş yeterli olmadığı için ışık iki kez gerekir."},{"q":"Parçacık neden önce yukarı çıkıp sonra aşağı iner?","steps":[{"t":"Işıkla yukarı","a":"enerji alır","d":"Işık çarpınca parçacık enerji kazanıp yukarı zıplar."},{"t":"Taşınırken aşağı","a":"enerji bırakır","d":"Sonra ilerlerken enerjisinin bir kısmını bırakıp aşağı iner."}],"ans":"Parçacık ışıkla yukarı çıkar, taşınırken enerji bırakıp aşağı iner."},{"q":"Z şemasındaki yolculukta su neden önemlidir?","steps":[{"t":"Parça verir","a":"su parçalanır","d":"Su parçalanınca yolculuğa başlayacak minik parçacıkları verir."},{"t":"Yol sürer","a":"su biterse durur","d":"Su olmazsa yola çıkacak parçacık da olmaz, yolculuk başlamaz."}],"ans":"Su yolculuğu başlatan parçacıkları verdiği için çok önemlidir."},{"q":"Z şemasının başı ve sonu arasında ne fark var?","steps":[{"t":"Başta su","a":"düşük yer","d":"Yolculuk suyla, en alçak yerden başlar."},{"t":"Sonda enerji kutusu","a":"yüksek yer","d":"İki kez yukarı itildiği için en sonda yüksek bir yere ulaşır."}],"ans":"Yolculuk alçaktaki sudan başlar, iki itişle yüksekteki enerji kutusunda biter."}]},"ortaokul":{"kolay":[{"q":"Z şeması neyin yolunu gösterir?","steps":[{"t":"Konu belirlenir","a":"elektron yolu","d":"Z şeması, yaprakta elektron denilen minik parçacıkların izlediği yolu gösterir."},{"t":"Enerji değişimi","a":"yükselip alçalır","d":"Bu yol boyunca elektronun enerjisi yükselir ve alçalır."}],"ans":"Z şeması elektronun enerji yükselip alçalarak izlediği yolu gösterir."},{"q":"Elektronlar Z şemasında nereden gelir?","steps":[{"t":"Kaynak bulunur","a":"sudan","d":"Işık suyu parçalar ve elektronlar sudan elde edilir."},{"t":"Yola çıkar","a":"PSII'ye","d":"Bu elektronlar ışıkla çalışan ilk durağa gider."}],"ans":"Z şemasındaki elektronlar parçalanan sudan gelir."},{"q":"Z şemasında ışık kaç durakta elektronu uyarır?","steps":[{"t":"İlk durak","a":"birinci ışık","d":"Işık ilk fotosistemde elektronu uyarır ve yukarı iter."},{"t":"İkinci durak","a":"ikinci ışık","d":"Sonra ikinci fotosistemde ışık elektronu yeniden uyarır."}],"ans":"Işık Z şemasında iki durakta elektronu uyarır."},{"q":"Z şeması adı nereden gelir?","steps":[{"t":"Çizim incelenir","a":"yukarı-aşağı-yukarı","d":"Elektron enerjisi yukarı çıkar, aşağı iner, tekrar yukarı çıkar."},{"t":"Şekle bakılır","a":"Z harfi","d":"Bu çizim Z harfine benzediği için bu ad verilmiştir."}],"ans":"Çizim Z harfine benzediği için Z şeması adını alır."},{"q":"Z şemasının sonunda hangi madde oluşur?","steps":[{"t":"Hedef belirlenir","a":"NADPH","d":"Elektronlar en sonda NADP⁺ ile birleşir."},{"t":"Sonuç","a":"enerji taşıyıcı","d":"Böylece NADPH adlı enerji taşıyan madde oluşur."}],"ans":"Z şemasının sonunda enerji taşıyıcı NADPH oluşur."}],"zor":[{"q":"Z şemasında elektronun enerjisi neden iki kez yükselir?","steps":[{"t":"İlk uyarılma","a":"PSII","d":"İlk fotosistemde ışık elektronu uyarır ve enerjisi yükselir."},{"t":"Enerji düşer","a":"taşıma sırasında","d":"Elektron taşıyıcılardan geçerken enerjisinin bir kısmını kaybeder."},{"t":"İkinci uyarılma","a":"PSI","d":"İkinci fotosistemde ışık tekrar gelir ve enerji yeniden yükselir."}],"ans":"İki ayrı fotosistemde ışıkla uyarıldığı için enerji iki kez yükselir."},{"q":"Su Z şemasında hangi görevi üstlenir?","steps":[{"t":"Elektron kaynağı","a":"su parçalanır","d":"Su parçalanınca açığa çıkan elektronlar PSII'nin kaybettiklerini yerine koyar."},{"t":"Yan ürün","a":"oksijen","d":"Bu sırada havaya oksijen verilir."}],"ans":"Su, elektron sağlar ve parçalanırken oksijen açığa çıkar."},{"q":"Z şemasında elektron PSII'den sonra nereye gider?","steps":[{"t":"Önce yukarı","a":"uyarılır","d":"PSII'de ışıkla uyarılan elektron yükselir."},{"t":"Taşıyıcı zincir","a":"aşağı iner","d":"Elektron, taşıyıcı zincirden geçerken aşağı doğru iner."},{"t":"İkinci durak","a":"PSI","d":"İndikten sonra ikinci fotosistem olan PSI'ye ulaşır."}],"ans":"PSII'den çıkan elektron taşıyıcılardan inerek PSI'ye gider."},{"q":"Z şemasında en yüksek enerji nerede görülür?","steps":[{"t":"Uyarılma anları","a":"fotosistemlerde","d":"Elektron her ışıkla uyarıldığında enerjisi tepe yapar."},{"t":"En tepe","a":"PSI sonrası","d":"İkinci uyarılmadan sonra elektron en yüksek enerjisine ulaşır."}],"ans":"En yüksek enerji ikinci uyarılma sonrası, NADP⁺'ye gitmeden önce görülür."},{"q":"Z şemasının başı suyla, sonu NADPH ile olması neyi anlatır?","steps":[{"t":"Başlangıç","a":"su, düşük enerji","d":"Elektronlar düşük enerjili sudan gelir."},{"t":"İki itiş","a":"ışıkla yükselir","d":"İki kez ışıkla uyarılarak enerjileri artar."},{"t":"Sonuç","a":"NADPH","d":"Yüksek enerjili elektronlar NADP⁺ ile birleşip NADPH yapar."}],"ans":"Z şeması, düşük enerjili sudan başlayıp yüksek enerjili NADPH ile biten elektron yolunu anlatır."}]},"lise":{"kolay":[{"q":"Z şeması fotosentezde neyi temsil eder?","steps":[{"t":"Tanım","a":"elektron akışı diyagramı","d":"Z şeması, ışığa bağımlı tepkimelerde elektronların izlediği enerji düzeyi yolunu gösteren diyagramdır."},{"t":"Eksenler","a":"enerji düzeyi","d":"Dikey eksen elektronun enerji düzeyini, yatay eksen elektronun ilerlediği yolu temsil eder."}],"ans":"Z şeması, elektronların enerji düzeyi değişimiyle izlediği akış yolunu gösteren diyagramdır."},{"q":"Z şemasında elektron akışı hangi molekülden başlar?","steps":[{"t":"Kaynak","a":"su","d":"Elektronlar suyun fotolizi (parçalanması) ile sağlanır."},{"t":"İlk alıcı","a":"PSII","d":"Bu elektronlar PSII'deki tepkime merkezine aktarılır."}],"ans":"Z şemasında elektron akışı su molekülünden başlar."},{"q":"Z şemasında elektronlar son olarak hangi moleküle aktarılır?","steps":[{"t":"Son durak","a":"NADP⁺","d":"PSI'den çıkan yüksek enerjili elektronlar ferredoksin aracılığıyla NADP⁺'ye taşınır."},{"t":"Ürün","a":"NADPH","d":"NADP⁺ elektron ve H⁺ alarak NADPH'ye indirgenir."}],"ans":"Z şemasında elektronlar son olarak NADP⁺'ye aktarılarak NADPH oluşur."},{"q":"Z şemasında kaç fotosistem yer alır?","steps":[{"t":"Sayım","a":"iki","d":"Z şemasında PSII ve PSI olmak üzere iki fotosistem vardır."},{"t":"Sıra","a":"PSII → PSI","d":"Elektron akışında önce PSII, sonra PSI gelir."}],"ans":"Z şemasında PSII ve PSI olmak üzere iki fotosistem yer alır."},{"q":"Z şemasında ışık elektronu kaç kez uyarır?","steps":[{"t":"İlk uyarılma","a":"PSII'de","d":"Işık önce PSII'nin P680 tepkime merkezindeki elektronu uyarır."},{"t":"İkinci uyarılma","a":"PSI'de","d":"Aynı elektron daha sonra PSI'nin P700 merkezinde yeniden uyarılır."}],"ans":"Z şemasında ışık elektronu iki kez uyarır: bir PSII'de, bir PSI'de."},{"q":"Z şeması neden bu adı alır?","steps":[{"t":"Enerji izi","a":"yükseliş-düşüş-yükseliş","d":"Elektronun enerji düzeyi PSII'de yükselir, taşıyıcılarda düşer, PSI'de yeniden yükselir."},{"t":"Şekil","a":"yan yatmış Z","d":"Enerji-yol grafiği çizildiğinde bu izlek yan yatmış Z harfine benzer."}],"ans":"Elektronun enerji izi yan yatmış Z harfine benzediği için Z şeması denir."},{"q":"Suyun fotolizi Z şemasının neresinde gerçekleşir?","steps":[{"t":"Konum","a":"PSII'de","d":"Su, PSII'ye bağlı oksijen açığa çıkaran kompleks tarafından parçalanır."},{"t":"Amaç","a":"elektron yenileme","d":"Açığa çıkan elektronlar, uyarılarak ayrılan elektronların yerini doldurur."}],"ans":"Suyun fotolizi Z şemasının başında, PSII'de gerçekleşir."},{"q":"Z şemasında oksijen ne zaman açığa çıkar?","steps":[{"t":"Kaynak tepkime","a":"su fotolizi","d":"PSII'de su parçalandığında elektron ve H⁺ ile birlikte O₂ açığa çıkar."},{"t":"Yan ürün","a":"O₂","d":"Oksijen, fotosentezin elektron akışındaki bir yan ürünüdür."}],"ans":"Z şemasında oksijen, başta suyun fotolizi sırasında açığa çıkar."},{"q":"Z şemasında PSII ile PSI arasındaki elektron taşınmasını ne sağlar?","steps":[{"t":"Aktarıcılar","a":"elektron taşıma zinciri","d":"Plastokinon, sitokrom b₆f ve plastosiyanin gibi taşıyıcılar elektronu PSII'den PSI'ye iletir."},{"t":"Yön","a":"enerjisel olarak aşağı","d":"Elektron bu zincirde enerjisini kademeli kaybederek ilerler."}],"ans":"PSII ile PSI arasındaki taşınmayı plastokinon, sitokrom b₆f ve plastosiyanin sağlar."},{"q":"Z şemasının tümü hangi tepkimeleri kapsar?","steps":[{"t":"Tepkime grubu","a":"ışığa bağımlı","d":"Z şeması fotosentezin ışığa bağımlı tepkimelerini gösterir."},{"t":"Yer","a":"tilakoit zar","d":"Bu tepkimeler kloroplastın tilakoit zarında gerçekleşir."}],"ans":"Z şeması, tilakoit zardaki ışığa bağımlı tepkimeleri kapsar."},{"q":"Z şemasında elektronun ilk uyarıldığı tepkime merkezi hangisidir?","steps":[{"t":"Merkez","a":"P680","d":"PSII'nin tepkime merkezindeki klorofil çiftine P680 denir."},{"t":"Olay","a":"uyarılma","d":"Işık emildiğinde P680'deki elektron yüksek enerji düzeyine çıkar."}],"ans":"Z şemasında elektron ilk olarak PSII'nin P680 merkezinde uyarılır."},{"q":"Z şemasında PSI'nin tepkime merkezi nasıl adlandırılır?","steps":[{"t":"Merkez adı","a":"P700","d":"PSI'nin tepkime merkezindeki klorofil çiftine P700 denir."},{"t":"Görev","a":"ikinci uyarılma","d":"Elektron burada ikinci kez ışıkla uyarılır."}],"ans":"Z şemasında PSI'nin tepkime merkezi P700 olarak adlandırılır."},{"q":"Z şemasında elektron PSI'den sonra nereye gider?","steps":[{"t":"Aracı","a":"ferredoksin","d":"PSI'de uyarılan elektron önce ferredoksine aktarılır."},{"t":"Hedef","a":"NADP⁺","d":"Ferredoksin, NADP⁺ redüktaz aracılığıyla elektronu NADP⁺'ye verir."}],"ans":"Z şemasında elektron PSI'den sonra ferredoksin üzerinden NADP⁺'ye gider."},{"q":"Z şemasında dikey eksen neyi gösterir?","steps":[{"t":"Eksen anlamı","a":"enerji düzeyi","d":"Dikey eksen elektronların sahip olduğu enerji düzeyini (redoks potansiyelini) gösterir."},{"t":"Yorum","a":"yüksek-alçak","d":"Yukarısı yüksek, aşağısı düşük enerji düzeyini ifade eder."}],"ans":"Z şemasında dikey eksen elektronların enerji düzeyini gösterir."},{"q":"Z şemasındaki elektron akışına ne ad verilir?","steps":[{"t":"Akış türü","a":"döngüsel olmayan","d":"Elektron sudan NADP⁺'ye doğru tek yönde, geri dönmeden akar."},{"t":"Sonuç","a":"NADPH ve ATP","d":"Bu akışla hem NADPH hem de ATP üretilir."}],"ans":"Z şemasındaki bu akışa döngüsel olmayan (doğrusal) elektron akışı denir."}],"zor":[{"q":"Z şemasında elektronun enerji düzeyi PSII'den NADP⁺'ye kadar nasıl değişir?","steps":[{"t":"İlk yükseliş","a":"PSII'de uyarılma","d":"P680'deki elektron ışıkla uyarılarak düşük enerji düzeyinden yüksek enerjili P680* düzeyine çıkar."},{"t":"İlk düşüş","a":"taşıma zinciri","d":"Elektron plastokinon → sitokrom b₆f → plastosiyanin boyunca enerjisini kademeli kaybederek aşağı iner."},{"t":"İkinci yükseliş ve son","a":"PSI'de uyarılma → NADP⁺","d":"P700'de tekrar uyarılıp en yüksek düzeye çıkar, ardından ferredoksin üzerinden NADP⁺'ye aktarılarak NADPH oluşur."}],"ans":"Enerji düzeyi PSII'de yükselir, taşıma zincirinde düşer, PSI'de yeniden yükselir ve NADP⁺'ye aktarılarak NADPH'de bağlanır."},{"q":"Z şemasının iki kez yükseliş gerektirmesinin termodinamik nedeni nedir?","steps":[{"t":"Enerji açığı","a":"su ile NADP⁺ arası","d":"Suyun redoks potansiyeli yüksek (elektron tutması güçlü), NADP⁺'ye elektron vermek için çok büyük bir enerji farkı aşılmalıdır."},{"t":"Tek fotonun yetersizliği","a":"tek uyarılma yetmez","d":"Tek bir ışık uyarımı bu enerji farkını kapatmaya yetmez."},{"t":"İki basamaklı çözüm","a":"iki fotosistem","d":"PSII ve PSI ardışık iki uyarılmayla gereken enerjiyi sağlar; her biri elektronu bir kademe yukarı iter."}],"ans":"Su ile NADP⁺ arasındaki büyük enerji farkı tek uyarılmayla aşılamadığından, iki fotosistemle iki kez yükseliş gerekir."},{"q":"Z şemasında elektron taşıma zincirindeki enerji düşüşü neye yarar?","steps":[{"t":"Salınan enerji","a":"redoks düşüşü","d":"Elektron PSII ile PSI arasında her taşıyıcıya geçerken enerjisinin bir bölümünü serbest bırakır."},{"t":"Proton pompalama","a":"sitokrom b₆f","d":"Bu enerji, stromadan tilakoit boşluğa H⁺ pompalamak için kullanılır."},{"t":"ATP üretimi","a":"kemiozmoz","d":"Oluşan H⁺ derişim farkı, ATP sentaz aracılığıyla ATP yapımını sürdürür."}],"ans":"Taşıma zincirindeki enerji düşüşü H⁺ pompalamak ve kemiozmozla ATP üretmek için kullanılır."},{"q":"Z şemasında P680⁺ neden çok güçlü bir oksitleyicidir ve bunun sonucu nedir?","steps":[{"t":"Elektron kaybı","a":"P680⁺ oluşur","d":"Uyarılan elektron P680'den ayrılınca geriye elektrona aç, güçlü oksitleyici P680⁺ kalır."},{"t":"Su parçalama","a":"yüksek çekim","d":"P680⁺ o kadar güçlü çeker ki suyun elektronlarını koparacak gücü vardır."},{"t":"Sonuç","a":"fotoliz","d":"Böylece su parçalanır, elektron yenilenir, H⁺ ve O₂ açığa çıkar."}],"ans":"P680⁺ çok güçlü oksitleyici olduğu için suyu parçalayabilir; bu sayede elektron yenilenir ve O₂ ile H⁺ açığa çıkar."},{"q":"Z şemasında döngüsel olmayan akış ile döngüsel akış enerji bakımından nasıl ayrılır?","steps":[{"t":"Döngüsel olmayan yol","a":"su → NADP⁺","d":"Elektron sudan başlayıp NADP⁺'de biter; iki fotosistem de kullanılır, hem NADPH hem ATP üretilir."},{"t":"Döngüsel yol","a":"PSI'ye geri","d":"PSI'den çıkan elektron NADP⁺'ye gitmeyip sitokrom b₆f'e dönerek tekrar PSI'ye girer."},{"t":"Ürün farkı","a":"yalnız ATP","d":"Döngüsel yolda yalnız ATP üretilir, NADPH ve O₂ oluşmaz."}],"ans":"Döngüsel olmayan akış su→NADP⁺ yönünde NADPH+ATP üretir; döngüsel akış elektronu PSI'ye geri döndürerek yalnız ATP üretir."},{"q":"Z şemasında elektronun PSII'den ayrıldıktan sonra geçtiği ilk yüksek enerjili alıcı nedir ve önemi nedir?","steps":[{"t":"İlk alıcı","a":"feofitin","d":"Uyarılan P680* elektronu önce feofitine aktarır."},{"t":"Yük ayrımı","a":"geri dönüşü önler","d":"Bu hızlı aktarım, elektronun P680⁺'ye geri düşmesini engelleyerek yük ayrımını kararlı kılar."},{"t":"Devam","a":"plastokinona","d":"Elektron feofitinden plastokinona geçerek taşıma zincirine girer."}],"ans":"Elektron P680*'ten önce feofitine geçer; bu hızlı aktarım yük ayrımını korur ve elektronu taşıma zincirine yönlendirir."},{"q":"Z şemasında plastosiyaninin görevi ve elektron akışındaki konumu nedir?","steps":[{"t":"Konum","a":"sitokrom b₆f sonrası","d":"Plastosiyanin, sitokrom b₆f kompleksinden elektron alır."},{"t":"Taşıma","a":"tilakoit boşlukta","d":"Tilakoit boşlukta hareket ederek elektronu PSI'ye taşır."},{"t":"Teslim","a":"P700⁺'ye","d":"Elektronunu, ışıkla uyarılıp elektron kaybetmiş P700⁺'ye vererek onu yeniler."}],"ans":"Plastosiyanin sitokrom b₆f'ten aldığı elektronu PSI'deki P700⁺'ye taşıyarak akışın sürekliliğini sağlar."},{"q":"Z şemasında PSI'de uyarılan elektronun NADP⁺'ye kadar izlediği yol nasıldır?","steps":[{"t":"İkinci uyarılma","a":"P700 → P700*","d":"PSI'ye ulaşan elektron ışıkla uyarılarak en yüksek enerji düzeyine (P700*) çıkar."},{"t":"Birincil alıcılar","a":"A₀, A₁, Fe-S","d":"Elektron sırasıyla A₀, A₁ ve demir-kükürt merkezlerinden geçer."},{"t":"Son aktarım","a":"ferredoksin → NADP⁺","d":"Ferredoksin elektronu NADP⁺ redüktaza, oradan NADP⁺'ye vererek NADPH oluşturur."}],"ans":"PSI'de uyarılan elektron A₀, A₁ ve Fe-S merkezlerinden ferredoksine, oradan NADP⁺ redüktaz ile NADP⁺'ye geçerek NADPH yapar."},{"q":"Z şemasında 'yan yatmış Z' şeklini oluşturan üç enerji bölümü nelerdir?","steps":[{"t":"Birinci dik kol","a":"PSII yükselişi","d":"P680'in uyarılmasıyla enerji düzeyi keskin biçimde yukarı çıkar (Z'nin alt çizgisinden yukarı)."},{"t":"Çapraz iniş","a":"taşıma zinciri","d":"Elektron taşıma zincirinde enerji kaybederek aşağı iner (Z'nin çapraz orta çizgisi)."},{"t":"İkinci dik kol","a":"PSI yükselişi","d":"P700'ün uyarılmasıyla enerji yeniden keskin biçimde yükselir (Z'nin üst kolu)."}],"ans":"Z şekli; PSII'deki dik yükseliş, taşıma zincirindeki çapraz iniş ve PSI'deki ikinci dik yükselişten oluşur."},{"q":"Z şemasında suyun elektron kaynağı seçilmesinin avantajı ve maliyeti nedir?","steps":[{"t":"Avantaj","a":"bol kaynak","d":"Su her yerde bulunan, tükenmeyen bir elektron ve H⁺ kaynağıdır."},{"t":"Maliyet","a":"yüksek enerji","d":"Suyun elektronları çok sıkı tutulduğundan koparmak büyük enerji gerektirir, bu yüzden iki fotosistem zorunlu olur."},{"t":"Yan kazanç","a":"O₂","d":"Maliyetin yanında atmosfere yaşam için gerekli O₂ kazandırılır."}],"ans":"Su bol ve sınırsız bir elektron kaynağıdır ancak elektronları sıkı tuttuğu için iki uyarılma gerektirir; karşılığında O₂ açığa çıkar."},{"q":"Z şemasında PSII ve PSI'nin emdiği ışığın dalga boyları arasında nasıl bir ilişki vardır?","steps":[{"t":"PSII tepe noktası","a":"680 nm","d":"PSII'nin P680 merkezi en iyi 680 nm dalga boyundaki ışığı emer."},{"t":"PSI tepe noktası","a":"700 nm","d":"PSI'nin P700 merkezi 700 nm dolaylarındaki ışığı emer."},{"t":"İşbirliği","a":"verim artışı","d":"İki dalga boyu birlikte verildiğinde fotosentez hızı tek başına olduğundan daha çok artar (Emerson artış etkisi)."}],"ans":"PSII 680 nm, PSI 700 nm dolaylarında ışık emer; iki fotosistemin birlikte çalışması fotosentez verimini artırır."},{"q":"Z şemasında NADPH ile ATP üretiminin elektron akışına bağlanışı nasıldır?","steps":[{"t":"ATP kaynağı","a":"taşıma zinciri","d":"Elektron PSII ile PSI arasında inerken salınan enerji H⁺ derişim farkı yaratır ve ATP sentazla ATP üretilir."},{"t":"NADPH kaynağı","a":"PSI sonu","d":"PSI'den çıkan yüksek enerjili elektron NADP⁺'yi indirgeyerek NADPH üretir."},{"t":"Ortak kullanım","a":"Calvin döngüsü","d":"Üretilen ATP ve NADPH, ışıktan bağımsız Calvin döngüsünde CO₂ indirgemede kullanılır."}],"ans":"ATP, taşıma zincirindeki enerji düşüşüyle; NADPH, PSI sonunda elektron alımıyla üretilir; ikisi de Calvin döngüsünü besler."},{"q":"Z şemasında elektronun her uyarılmadan sonra yüksek enerji düzeyinde kalamamasının nedeni nedir?","steps":[{"t":"Uyarılmış hal kararsızdır","a":"kısa ömür","d":"Uyarılan elektron yüksek enerji düzeyinde çok kısa süre kalır, kararsızdır."},{"t":"Hızlı aktarım","a":"birincil alıcı","d":"Elektron hemen bir birincil alıcıya (PSII'de feofitin, PSI'de A₀) aktarılır."},{"t":"Sonuç","a":"enerji korunur","d":"Bu hızlı aktarım sayesinde enerji ısı/ışık olarak kaybolmadan kimyasal işe yönlendirilir."}],"ans":"Uyarılmış hal kararsız olduğundan elektron hemen birincil alıcıya aktarılır; böylece enerji boşa harcanmadan akışa kazandırılır."},{"q":"Z şemasında elektronlar PSII'den ayrılınca P680'in elektronları nasıl ve nereden tamamlanır?","steps":[{"t":"Eksik oluşur","a":"P680⁺","d":"Uyarılan elektron ayrılınca P680 elektronca eksik (P680⁺) kalır ve akış sürmesi için bu eksik dolmalıdır."},{"t":"Su parçalanır","a":"oksijen açığa çıkaran kompleks","d":"PSII'ye bağlı kompleks 2 H₂O'yu parçalayarak 4 elektron, 4 H⁺ ve 1 O₂ açığa çıkarır."},{"t":"Yenileme","a":"elektron geri verilir","d":"Açığa çıkan elektronlar P680⁺'ye verilerek tepkime merkezi yenilenir."}],"ans":"P680'in elektronları, oksijen açığa çıkaran kompleksin suyu parçalamasıyla sağlanan elektronlarla tamamlanır."},{"q":"Z şemasının enerji grafiğine bakarak elektronun en düşük ve en yüksek enerji düzeyinde olduğu anlar nasıl belirlenir?","steps":[{"t":"En düşük an","a":"sudaki elektron","d":"Grafikte en alttaki nokta, henüz uyarılmamış, sudan gelen elektronun PSII'ye girmeden önceki düşük enerji düzeyidir."},{"t":"İki tepe","a":"P680* ve P700*","d":"Her uyarılmadan hemen sonra grafikte iki tepe görülür; ikincisi (P700*) en yüksek noktadır."},{"t":"İniş eğilimi","a":"NADP⁺'ye","d":"P700*'ten sonra elektron NADP⁺'ye doğru hafif iner ve NADPH'de bağlı, kararlı yüksek enerjili hale geçer."}],"ans":"En düşük enerji sudan gelen elektrondadır; en yüksek enerji PSI'deki ikinci uyarılma anında (P700*) görülür, ardından NADP⁺'ye iner."}]}}};
